-- Poems batch 60
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('54303255-32f4-466c-9563-19be91dd4bcf','五言白話詩 十二','缺名','唐','唐诗','tang','','[]','本是達官兒，名作郎君子。',72,'全唐诗/poet.tang.51000.json','["本是達官兒，名作郎君子。", "從小好讀書，更須多識字。", "長大人中官，當衙判曹事。", "高馬衣輕裘，伴涉諸王子。", "官高漸入朝，供奉親天子。", "縱得公王侯，終歸不免死。"]'),
('36a8b2f7-5ff0-4ee1-9a39-76ee43fd7b1b','五言白話詩 十三','缺名','唐','唐诗','tang','','[]','秋長夜甚明，長夜照衆生。',60,'全唐诗/poet.tang.51000.json','["秋長夜甚明，長夜照衆生。", "死者歸長路，生者蹔時行。", "夜眠由鬼界，天曉即營生。", "兩兩相刼奪，分毫努眼淨。", "賢愚不相識。", "壤壤信緣行。"]'),
('bdc2e3ff-be5e-46d9-a369-a7340db5bf3d','五言白話詩 十四','缺名','唐','唐诗','tang','','[]','工匠莫學巧，巧即他人使。',48,'全唐诗/poet.tang.51000.json','["工匠莫學巧，巧即他人使。", "身是自來奴，妻亦官人婢。", "夫壻蹔時無，曳將仍被耻。", "未作道與錢，作了擘眼你。"]'),
('20bf057c-ad78-447d-9634-7b3045da6017','五言白話詩 十五','缺名','唐','唐诗','tang','','[]','奴人賜酒食，恩言出義氣。',98,'全唐诗/poet.tang.51000.json','["奴人賜酒食，恩言出義氣。", "（「奴」，項楚校作「好」。", "「義」，蔣紹愚校作「美」。", "）無賴不與錢，蛆心打脊使。", "貧窮實可憐，饑寒肚露地。", "戶役一槩差，不辧棒下死。", "可出頭坐，誰肯被鞭耻。", "何爲拋宅走，良由不得止。"]'),
('7f4a70cb-8251-46af-9f54-32c60a7f571f','五言白話詩 十六','缺名','唐','唐诗','tang','','[]','狼多羊數少，莫畜惡兒子。',101,'全唐诗/poet.tang.51000.json','["狼多羊數少，莫畜惡兒子。", "年是無限年，你身甚急速。", "有意造罪根，無心念諸佛。", "你從何處來，膿血相和出。", "身如水上泡，暫時還却沒。", "魂魄游空虛，盲人入闇窟。", "生死如江河，波浪𧉸啾唧。", "（「𧉸」，斯五六四一卷作「沸」）。"]'),
('0d072027-53c3-450a-bd10-3c784cc7f8be','五言白話詩 十七','缺名','唐','唐诗','tang','','[]','世間日月明，皎皎照衆生。',72,'全唐诗/poet.tang.51000.json','["世間日月明，皎皎照衆生。", "貴者乘車馬，賤者膊膽行。", "富者前身種，貧者慳貪生。", "貧富有殊別，業報自相迎。", "聞强造功德，喫着自身榮。", "智者天上去，愚者入深坑。"]'),
('4919ffa2-00f3-4e41-bd42-0b07863fd09d','五言白話詩 十八','缺名','唐','唐诗','tang','','[]','身如大店家，命如一宿客。',49,'全唐诗/poet.tang.51000.json','["身如大店家，命如一宿客。", "忽起向前去，本不是吾宅。", "吾宅在丘荒，園林出松柏。", "隣接千年塚，故路來長陌。", "。"]'),
('36fe0011-a84b-4cd6-adcb-e489d11c758c','五言白話詩 十九','缺名','唐','唐诗','tang','','[]','身臥空堂內，獨坐令人怕。',87,'全唐诗/poet.tang.51000.json','["身臥空堂內，獨坐令人怕。", "我今避頭去，拋却空閑舍。", "（項楚謂以上四句應自爲一首。", "）你道生時樂，吾道死時好。", "死即長夜眠，生即緣長道。", "生時愁衣食，死鬼無釜竃。", "願作製撥鬼，入家偷喫飽。"]'),
('4ba746ca-1646-4b73-9020-a00cad257390','五言白話詩 二十','缺名','唐','唐诗','tang','','[]','身如破皮袋，盛膿兼裏骨。',48,'全唐诗/poet.tang.51000.json','["身如破皮袋，盛膿兼裏骨。", "將板作皮裘，埋入深坑窟。", "一入恒沙劫，無由更得出。", "除非寒食節，子孫塚傍泣。"]'),
('9eb6edaf-7132-47e8-a439-398b73079638','五言白話詩 二十一','缺名','唐','唐诗','tang','','[]','世間何物平？不過死一色。',48,'全唐诗/poet.tang.51000.json','["世間何物平？不過死一色。", "老小終須去，信前業道力。", "縱使公王侯，用錢遮不得。", "各身改頭皮，相逢定不識。"]'),
('193212b1-e8d1-43f6-a416-d55a4d3705c6','五言白話詩 二十二','缺名','唐','唐诗','tang','','[]','身如內架堂，（「內」，項楚校作「肉」。',107,'全唐诗/poet.tang.51000.json','["身如內架堂，（「內」，項楚校作「肉」。", "）命似堂中燭。", "風急吹燭滅，即是空堂屋。", "家貧無好衣，（自「家貧無好衣」以下，張錫厚作另一首。", "）造得一襖子。", "中心禳破氈，還將布作裏。", "清貧常使樂，不用濁富貴。", "白日串項行，夜眠還作被。"]'),
('084e1bd0-cfba-422d-9376-c06684b8f355','五言白話詩 二十三','缺名','唐','唐诗','tang','','[]','人生一代間，有錢須喫着。',48,'全唐诗/poet.tang.51000.json','["人生一代間，有錢須喫着。", "四海並交游，風光亦須覓。", "錢財只恨無，有時實不惜。", "聞身强健時，多施還須喫。"]'),
('a435a209-c308-4abe-9885-d8217a1c9d86','五言白話詩 二十四','缺名','唐','唐诗','tang','','[]','生坐四合舍。',36,'全唐诗/poet.tang.51000.json','["生坐四合舍。", "死入土角䚥。", "窅窅黑闇眠，永別明燈燭。", "死鬼憶四時，八節生人哭。"]'),
('fa8c9936-b75a-4c5a-85b4-1b5999b23d19','五言白話詩 二十五','缺名','唐','唐诗','tang','','[]','虛霑一百年，八十最是老。',72,'全唐诗/poet.tang.51000.json','["虛霑一百年，八十最是老。", "逢頭捉將去，無老亦無小。", "須臾得暫時，恰同霜下草。", "橫遭狂風吹，總即連根倒。", "悠悠度今日，今夜誰能保。", "語你愚癡人，急修未來道。"]'),
('cf164281-a721-4853-81ca-c93f0db0ae87','五言白話詩 二十六','缺名','唐','唐诗','tang','','[]','暫出門前觀，川原足故塚。',82,'全唐诗/poet.tang.51000.json','["暫出門前觀，川原足故塚。", "富者造山門，貧者如破瓮。", "年年並舍多，歲歲成街巷。", "前死後人塒，鬼補悲聲送。", "縱得百年活，還入土孔籠。", "（以上《燉煌掇瑣》三一引伯希和卷三二一一）。"]'),
('d0519f6e-4652-43ac-b657-b6bf415167bf','五言詩','缺名','唐','唐诗','tang','','[]','（原爲長篇連續不斷。',128,'全唐诗/poet.tang.51000.json','["（原爲長篇連續不斷。", "劉復云：「卷殘，抄出者共五十二首。", "」現選錄十首。", "〖張錫厚《王梵志詩校輯》卷五云與伯三四一八卷爲同一系統的敦煌遺書尚有伯三七二四、斯六○三二、蘇二八五二等三卷。", "今即據其所錄校補。", "此組詩作者，張錫厚推測亦應爲王梵志，但尚缺明確的證據。", "〗）。"]'),
('927c896f-51ad-4d6e-a8df-2daf5775562c','五言詩 一','缺名','唐','唐诗','tang','','[]','審看世上人，有賤亦有貴。',238,'全唐诗/poet.tang.51000.json','["審看世上人，有賤亦有貴。", "賤者由慳貪，𢗞財不布施。", "貴賤既有殊，業報前生值。", "（「值」，戴密微、項楚校作「植」。", "項楚謂以上應爲一首。", "）有錢但喫着，（「有錢」，伯三七二四卷作「有財」。", "）實莫留樻□。", "（「樻□」，原缺一字，伯三七二四卷作「田柜」，張錫厚改作「填櫃」。", "）一日厥摩師，（自「一日厥摩師」以下，張錫厚另作另一首。", "）他用不由你。", "妻嫁親後夫，子心隨母意。", "我物我不用，我自無意智。", "未有千年身，（「千年」，伯三七二四卷作「百年」。", "）從作千年事。", "（「從作」，伯三七二四卷作「徒使」。", "）。"]'),
('66e281d1-2a52-4026-8e59-0a9a1377285e','五言詩 二','缺名','唐','唐诗','tang','','[]','吾死不須哭，徒勞枉却聲。',337,'全唐诗/poet.tang.51000.json','["吾死不須哭，徒勞枉却聲。", "祇用四片板，四角八枚丁。", "急手涂埋却，（「涂」，袁賓、項楚校作「深」。", "）臭穢不中亭。", "墓內不須食，麥酒三五瓶。", "（「麥」酒，張錫厚錄作「美酒」，伯三七二四卷作「羹酒」。", "）時時獨飲樂，飲盡更須傾。", "（「飲」，伯三七二四卷作「沉」。", "）只願長頭醉，作伴喚劉伶。", "你道生勝死（自「你道生勝死」以下，張錫厚另作一首。", "），我道死勝生。", "生即苦戰死，死即無人征。", "十六作夫役，二十充府兵。", "磧裏向前走，衣鉀困須擎。", "白日趁食地，每也悉知更。", "（「每也」，伯三七二四卷作「□夜」。", "）鐵鉢淹甘飯，同火共分諍。", "長頭饑欲旺。", "（「旺」，伯三七二四卷作「死」。", "）[肚]似砍窮坑。", "（「肚」字據伯三七二四卷補。", "「砍」，伯三七二四卷作「破」。", "）遺兒我受苦，（「遺」，伯三七二四卷作「遣」。", "）慈母不須生。"]'),
('05a10a14-7f63-4bf8-b1a2-ef6ebec77ce2','五言詩 三','缺名','唐','唐诗','tang','','[]','夫婦生五男，幷有一雙女。',321,'全唐诗/poet.tang.51000.json','["夫婦生五男，幷有一雙女。", "兒大須娶妻，女大須嫁處。", "（「處」，項楚校爲「去」。", "）戶役差耕來，（「差耕」，伯三七二四卷作「差科」。", "）棄拋我夫婦。", "（「拋」，伯三七二四卷作「挽」。", "）妻即無裙祓，（「裙祓」，伯三七二四卷作「褐被」。", "袁賓校「裙被」。", "）夫體無褌袴。", "父母俱八十，兒年五十五。", "當頭憂妻兒，（「憂」，伯三七二四卷作「養」。", "）不勤養父母。", "渾家少糧食，尋常空餓肚。", "男女一處生，（「生」，伯三七二四卷作「坐」。", "「處」，項楚校作「出」。", "）却似餓狼虎。", "粗飯衆厨飡，美味當房傳佉。", "（「佉」，伯三七二四卷作「棄」，張錫厚改作「去」。", "）努眼看尊親，只覓乳食處。", "少年生平又，（「平又」，伯三七二四卷作「夜□」，張錫厚改作「夜樂」，項楚校爲「夜叉」。", "）老頭自受苦。", "。"]'),
('794a6f9a-3e7b-4b2a-93e1-e7258ce04796','五言詩 四','缺名','唐','唐诗','tang','','[]','一歲已百年，（「已」，伯三七二四卷作「與」。',269,'全唐诗/poet.tang.51000.json','["一歲已百年，（「已」，伯三七二四卷作「與」。", "）中間不怕死。", "長命得八十，漸漸無意智。", "悉能造罪根，不解生慚愧。", "廣貪長命財，身當短命死。", "興生向前走，惟求多出利。", "析心即心枉，（「析心」，伯三七二四卷作「折本」。", "）惶惶煩惱起。", "錢逸即獨富，（「逸」，伯三七二四卷作「𨓚」，張錫厚定作「兌」，蔣紹愚校作「遶」，逮「饒」。", "）吾貧長省事。", "奴富欺郎君，婢富遠娘子。", "（「富遠」，伯三七二四卷作「有陵〖淩〗」。", "）鳥饑緣食亡，人能爲財死。", "（「能」，項楚校作「窮」。", "）錢是害人物，智者常遠離。", "（張錫厚錄此詩，下有「□□□□□，心恒更愿取」。", "項楚謂此首當析爲三首。", "）。"]'),
('16a17c41-ed09-4ead-a5b8-441b7298d504','五言詩 五','缺名','唐','唐诗','tang','','[]','富饒田舍兒，論請實好事。',344,'全唐诗/poet.tang.51000.json','["富饒田舍兒，論請實好事。", "度種如生田，（「度」，伯三七二四卷作「廣」。", "）宅舍青煙起。", "槽上飼肥馬，仍更賣奴婢。", "（「賣」，伯三七二四卷作「買」。", "）牛羊共成羣，滿圈養生子。", "（「養牛子」，伯三七二四卷作「豢肥子」。", "項楚謂「牛」當作「㹠」。", "）窖內多埋穀，尋常願米貴。", "里政追役來，（「里政」，伯三七二四卷作「里正」。", "下同。", "）坐着南廳裏。", "廣設好飲食，多須遣醉。", "（「多須」，伯三七二四卷作「多酒」。", "）追車即與車，須馬即與馬。", "（「須馬」，伯三七二四卷作「追馬」。", "「與馬」，伯三七二四卷作「與使」。", "）須錢便與錢，和市亦不避。", "索麵驢駝送，續後更有雉。", "官人應須物，當家皆具備。", "縣官與恩宅，（「恩宅」，伯三七二四卷作「恩澤」。", "）曹司一家事。", "縱有重差科，有錢不怕你。", "貧窮田舍漢，（自「貧窮田舍漢」以下，張錫厚作另一首。"]'),
('094302bd-b660-479d-a8a9-e882f49f2293','五言詩 六','缺名','唐','唐诗','tang','','[]','當官自慵懶，不勤判文案。',233,'全唐诗/poet.tang.51000.json','["當官自慵懶，不勤判文案。", "尋常打酒醉，（「打酒」，伯三七二四卷作「村酒」。", "）每日出逐伴。", "衙日唱稽逋，佐史寸脊爛。", "更兼受取錢，（「受」，伯三七二四卷作「愛」。", "）差科放却半。", "狂棒百姓死，（「狂」，伯三七二四卷作「枉」。", "）荒忙怕麥散。", "賦歛既不均，（「歛」，伯三七二四卷候「役」。", "）曹司即潦亂。", "啾唧被人言，御史秉正斷。", "除名仍解官，告身奪入案。", "宅舍不許坐，（「宅舍」，伯三七二四卷作「官宅」。", "）錢財即分散。", "路人見心酸，傍看罪過漢。", "一則恥妻兒，二則羞同伴。", "無面還本鄉，諸州且游觀。"]'),
('924df6a3-94c0-4476-8328-6763602d8b24','五言詩 七','缺名','唐','唐诗','tang','','[]','天下浮游人，（「浮游」，斯六○三二卷作「浮逃」。',249,'全唐诗/poet.tang.51000.json','["天下浮游人，（「浮游」，斯六○三二卷作「浮逃」。", "）商多買一半。", "（「商多買一半」，斯六○三二卷作「不啻多一半」。", "）南北擲縱橫，誰他蹔歸貫。", "（「誰」，斯六○三二卷作「誑」；「縱橫」作「蹤藏」。", "）游游自覓活，不愁雁戶役。", "無心念二親，有意隨惡伴。", "强處出頭來，不須曹主喚。", "（「曹主」，斯六○三二卷作「主人」。", "）聞苦即深藏，尋常擬於算。", "（「於」項楚校作「相」。", "）欲似鳥作羣，驚即當頭散。", "（「當頭」，斯六○三二卷作「分頭」。", "）心毒無忠孝，不過浮游漢。", "（「浮遊」，斯六○三二卷作「浮浪」。", "）此是五逆賊，打殺何須案。"]'),
('ca88e42d-f523-4612-a39c-85c241466bf8','五言詩 八','缺名','唐','唐诗','tang','','[]','男女有亦好，無時亦最精。',63,'全唐诗/poet.tang.51000.json','["男女有亦好，無時亦最精。", "兒在愁他役，又恐點着征。", "一則無租調，二則絕兵名。", "閉門無呼喚，耳裏挃星星。", "（「挃」，項楚校作「極」。", "）。"]'),
('c6622f2b-6f61-47d1-a91d-edda51076fe3','五言詩 九','缺名','唐','唐诗','tang','','[]','生兒擬替公，兒大須公死。',72,'全唐诗/poet.tang.51000.json','["生兒擬替公，兒大須公死。", "天配作次第，合去不由你。", "父子總長命，地下無人使。", "閻老忽嗔遲，即棒伺命使。", "火急須領兵，走來且取你。", "不及別妻兒，向前任料理。"]'),
('1686b0c6-a9bd-4d36-872f-19710b92c1f2','五言詩 十','缺名','唐','唐诗','tang','','[]','蹔得一代人，風光亦須覓。',211,'全唐诗/poet.tang.51000.json','["蹔得一代人，風光亦須覓。", "（張錫厚以止二句屬另一首。", "）金玉不成寶，{戒廾=天}身實可惜。", "（「{戒廾=天}」，項楚校作「宍」，即「肉」字。", "）白髮隨年生，美貌別今夕。", "貧富光常空，（「光」，郭在貽校作「无」，即「無」。", "）恣意多着喫。", "活時恠不用，塞墓慎何益？", "（「慎」，戴密微校作「真」。", "）（以上《燉煌掇瑣》三○引伯希和卷三四一八。", "詩中別體不明之處，暫未校正（王梵志詩及此無名氏詩所錄今人校訂意見，皆錄自郭在貽《王梵志詩彙校》。", "））。"]'),
('3e4cd5ea-8dcf-404c-ae5e-da64c78cd7eb','雜詩','寒山','唐','唐诗','tang','','[]','無嗔即是戒，心淨即出家。',64,'全唐诗/poet.tang.51000.json','["無嗔即是戒，心淨即出家。", "我性與汝合，一切法無差。", "（《萬首唐人絕句補》十）（《宗鏡鏡》卷二四、《五燈會元》卷二收此詩爲拾得作。", "）。"]'),
('be1ce326-e89b-4130-bf65-341e4c811f2f','','弘忍','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('a9e16488-2962-4292-9191-8a48fc414236','五祖自詠（時復生再來）（此詩爲後人僞托。）','弘忍','唐','唐诗','tang','','[]','垂垂白髮下青山，七歲歸來改舊顏。',63,'全唐诗/poet.tang.51000.json','["垂垂白髮下青山，七歲歸來改舊顏。", "人却少年松却老，是非從此落人間。", "（《弘治黃州府志》五《人物·仙釋》、同上七《藝文·黃梅縣》）。"]'),
('94cf2ada-5891-454a-b53d-e7323994e82b','偈','神秀','唐','唐诗','tang','','[]','（五祖弘忍一日會衆傳法弟子，神秀呈偈出於壁間。',105,'全唐诗/poet.tang.51000.json','["（五祖弘忍一日會衆傳法弟子，神秀呈偈出於壁間。", "）身是菩提樹，心如明鏡臺。", "時時勤拂拭，勿使惹塵埃。", "（《嘉慶廣東通志》三二八《釋老傳》引《指月錄》）（此偈最早見於《六祖法寶壇經》。", "末句，敦煌本作「莫使有塵埃」。", "）。"]'),
('f8bdfbba-0c68-4428-ba52-81429f4ae206','','慧能','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('17f8142f-54c8-463a-8d6e-fd174cfe830a','偈','慧能','唐','唐诗','tang','','[]','（慧能不識字，聞人誦神秀偈，乃偈請人書其側曰：）菩提本無樹，明鏡亦非臺。',139,'全唐诗/poet.tang.51000.json','["（慧能不識字，聞人誦神秀偈，乃偈請人書其側曰：）菩提本無樹，明鏡亦非臺。", "本來無一物，何處惹塵埃？", "（同上。", "）（此偈最早見於法海本《六祖法寶壇經》。", "敦煌本引作二首，文字差異較大，另詳《全唐詩續拾》卷九。", "）（今按：禪宗六祖南北二家之偈，實爲明白如話的哲理詩，最有代表性，故特補錄。", "）。"]'),
('4ee31704-50d5-4739-8ec9-1e6c866092b0','自臯亭至吳門弔二大護法','慧淨','唐','唐诗','tang','','[]','病耳蚊過似走雷，杖行猶怯步難回。',87,'全唐诗/poet.tang.51000.json','["病耳蚊過似走雷，杖行猶怯步難回。", "一舠白水牽愁斷，兩束黃香拭淚開。", "了悟世緣容直往，徘徊夢影或雙來。", "遠公自看蓮花漏，無復宗雷過講臺。", "（《古今圖書集成·神異典》二一一《居士部》）。"]'),
('57c6cb39-0d50-4d60-a417-525e1aa218bf','丹霄驛詩刻','李隆基','唐','唐诗','tang','','[]','驛前南面架危橋，久欲登臨畏路遙。',48,'全唐诗/poet.tang.51000.json','["驛前南面架危橋，久欲登臨畏路遙。", "今日偶然尋得到。", "直從平地上丹霄。", "（《輿地紀勝》一○七《昭州》）。"]'),
('d63a8657-0564-4f07-a7a8-59013ef1d56c','幸蜀回居南內夢中見妃子於蓬山太真院作詩遺之使焚於馬嵬山下','李隆基','唐','唐诗','tang','','[]','風急雲驚雨不成，覺來仙夢甚分明。',32,'全唐诗/poet.tang.51000.json','["風急雲驚雨不成，覺來仙夢甚分明。", "當時苦根銀屏影，遮隔仙姬秪聽聲。"]'),
('4e0a0cfc-5f7e-46ab-bd89-37cbeb2438aa','又作妃子所遺羅襪銘','李隆基','唐','唐诗','tang','','[]','羅襪羅襪，香塵生不絕。',95,'全唐诗/poet.tang.51000.json','["羅襪羅襪，香塵生不絕。", "細細圓圓，地下得瓊鈎；窄窄弓弓，手中弄新月。", "又如脫履露纖圓，恰似同衾見時節。", "方知清夢事非虛，暗引相思幾時歇？", "（以上《詩話總龜》三三《紀夢門》）（此二首疑出後人依託。", "）。"]'),
('a875aa41-dc74-494a-a505-b7e18a330cd1','馬跑神泉','盧象','唐','唐诗','tang','','[]','將軍稱賀魯，遺廟俯靈淵。',240,'全唐诗/poet.tang.51000.json','["將軍稱賀魯，遺廟俯靈淵。", "漦噴蛟龍穴，波跳赤鯉泉。", "路迴芹澗水，村近石林烟。", "野馬含暄氣，農夫出故廛。", "土膏興耒耜，尸祝傍山嶺。", "閱世無銘石，茲遊匪慕天。", "頃來規下宇，必葺慕先賢。", "悅使成能事，掄材出俸錢。", "伉香推幹蠱，班匠擇精專。", "黝堊何其麗，欒櫨本自然。", "松青離石道，雲白介山田。", "適嘆飛翬速，仍憂黃雀穿。", "梨花寒食後，桂藉酒樽前。", "饑麝尋香柏，流鶯助晚絃。", "吳歈催玉斝，趙舞落金鈿。", "上巳無過酒，春衣欲試湔。", "故園思鞏洛，褉飲客汾川。", "寄語西河老，鄉心朝暮懸。", "（《古今圖書集成·職方典》三四一《汾州府部》）。"]'),
('f5140ff9-e856-4bfe-a04f-716d356b7505','送李邕之秦','王昌齡','唐','唐诗','tang','','[]','空（《文鏡秘府論》地《十七勢》，《全唐詩》作《送李十五》。',69,'全唐诗/poet.tang.51000.json','["空（《文鏡秘府論》地《十七勢》，《全唐詩》作《送李十五》。", "《文鏡秘府》首句「怨別」作「別怨」，三句「杳」作「夢」，四句「影」作「映」。", "）。"]'),
('036054ed-07a4-4739-9b3a-7fa4d4f521d7','','元德秀','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('f5efda1d-10b5-4296-bc26-f206ad8fba1a','歸隱','元德秀','唐','唐诗','tang','','[]','緩步巾車出魯山，陸渾佳處處恣安閑。',56,'全唐诗/poet.tang.51000.json','["緩步巾車出魯山，陸渾佳處處恣安閑。", "家無僕妾饑忘爨，自有琴書興不闌。", "（《古今圖書集成·職方典》四八八《汝州部》）。"]'),
('cf63efef-217d-47d0-b2c6-35b5b2072686','春燕','徐璧','唐','唐诗','tang','','[]','空（《文苑英華》三二九《禽獸》詩《全唐詩》七六九失題，又列爲無世次爵里可考）。',39,'全唐诗/poet.tang.51000.json','["空（《文苑英華》三二九《禽獸》詩《全唐詩》七六九失題，又列爲無世次爵里可考）。"]'),
('4039d820-f678-4992-8f8e-a578e75fc2d3','催粧','徐璧','唐','唐诗','tang','','[]','空（《搜玉小集》《唐人選唐詩》，皆初唐人〖《全唐詩》七六九作徐安期。',108,'全唐诗/poet.tang.51000.json','["空（《搜玉小集》《唐人選唐詩》，皆初唐人〖《全唐詩》七六九作徐安期。", "〗〖《唐詩紀事》卷十三署徐安期，《萬首唐人絕句》卷五五亦署徐璧。", "《全唐詩補逸》卷十七據《永樂大典》卷六五二三錄《催妝》詩，作徐壁，今刪彼存此。", "〗）。"]'),
('219312a2-87f8-4deb-8b40-e5c698109198','題季子廟','李華','唐','唐诗','tang','','[]','空（《全唐詩》七七八作李季華詩，第二句「聽」《圖書集成》作「繼」，第四句「冷」作「滿」。',98,'全唐诗/poet.tang.51000.json','["空（《全唐詩》七七八作李季華詩，第二句「聽」《圖書集成》作「繼」，第四句「冷」作「滿」。", "）（出處當爲《輿地紀勝》卷七《鎮江府》。", "《全唐詩》作李季華，係出《萬首唐人絕句》卷一百，疑涉詩題而致誤。", "）。"]'),
('bda159cb-4ed9-4809-9536-6cf2de08092a','題澤州石佛閣','李華','唐','唐诗','tang','','[]','覽勝詩千首，登高酒一壺。',47,'全唐诗/poet.tang.51000.json','["覽勝詩千首，登高酒一壺。", "此情誰管領，分付石浮圖。", "（《古今圖書集成·職方典》三六四《澤州部》）。"]'),
('9ef01583-7bf0-4b8d-8990-f102ab94876e','贈任華','高適','唐','唐诗','tang','','[]','丈夫結交須結貧，貧者結交交始親。',80,'全唐诗/poet.tang.51000.json','["丈夫結交須結貧，貧者結交交始親。", "世人不解結交者，唯重黃金不重人。", "黃金雖多有盡時，結交一成無竭期。", "君不見管仲與鮑叔，至今留名名不移。", "（《唐詩紀事》二二《任華》）。"]'),
('473d242b-d094-4a77-b940-0b7fcd332c11','題雷威琴','徐浩','唐','唐诗','tang','','[]','石山孫枝，樣剪伏羲。',30,'全唐诗/poet.tang.51000.json','["石山孫枝，樣剪伏羲。", "將扶大隱，永契神機。", "（《西溪叢語》上）。"]'),
('a47e661e-4f5a-403c-9e9b-3c4e3e11eed1','送東林廉上人還廬（山）','徐浩','唐','唐诗','tang','','["\u5e90\u5c71"]','空（《古今圖書集成·神異典·僧部》。',118,'全唐诗/poet.tang.51000.json','["空（《古今圖書集成·神異典·僧部》。", "又《山川典·廬山部》作句融詩）殷璠《河嶽共同願望盡快集》卷上收此爲（劉眘虛詩。", "）（《全唐詩》一四○作王昌齡詩，第二句「人」《圖書集成》作「入」，第五句「昔」作「常」，末三字「望清輝」作「無清機」。", "）。"]'),
('4a502a51-a28d-4566-8ea3-47fbb969fd5a','感春（句）','張謂','唐','唐诗','tang','','[]','梧桐三寸葉，楊柳一尋枝。',25,'全唐诗/poet.tang.51000.json','["梧桐三寸葉，楊柳一尋枝。", "（《歲華紀麗》一《春》）。"]'),
('b598667e-5676-4369-a4fb-dcfd5441c5fe','句（書《奉使帖》後）','顏真卿','唐','唐诗','tang','','[]','人心無路見，時事只天知。',29,'全唐诗/poet.tang.51000.json','["人心無路見，時事只天知。", "（黃本驥編訂《顏魯公文集》十二）。"]'),
('a067d553-fa9f-4468-bc16-21939d9c0c85','龍虎山','吳筠','唐','唐诗','tang','','[]','道土身披魚鬣衣，白日忽上青天飛。',72,'全唐诗/poet.tang.51000.json','["道土身披魚鬣衣，白日忽上青天飛。", "龍虎山頭好明月，玉殿珠樓空翠微。", "（《古今圖書集成·山川典》一四七《龍虎山部》。", "又《職方典》八六六《廣信府部》）。"]'),
('39569c37-60e8-4c3c-b85a-240145c47934','竹枝詞','圓觀','唐','唐诗','tang','','[]','（二首○《蜀中名勝記》二三《夔州府·萬縣》引《碑目》云：「大雲寺碑有唐僧圓澤傳。',61,'全唐诗/poet.tang.51000.json','["（二首○《蜀中名勝記》二三《夔州府·萬縣》引《碑目》云：「大雲寺碑有唐僧圓澤傳。", "」又《忠義傳》載李源道人再生事詩云云。", "）。"]'),
('e9ae8023-64e1-460e-b6ec-0cbeee895ffb','竹枝詞 一','圓觀','唐','唐诗','tang','','[]','三生石上舊精魂，賞月吟風不要論。',32,'全唐诗/poet.tang.51000.json','["三生石上舊精魂，賞月吟風不要論。", "慚愧情人遠相訪，此身雖異性長存。"]'),
('340c17d9-fc8f-41e4-8e75-46526cace0ff','竹枝詞 二','圓觀','唐','唐诗','tang','','[]','身前身後事茫茫，欲話因緣恐斷腸。',94,'全唐诗/poet.tang.51000.json','["身前身後事茫茫，欲話因緣恐斷腸。", "吳越溪山尋已遍，卻迴煙棹上瞿塘。", "（《歲時廣紀》三三《中秋》引《甘澤謠》）（見《太平廣記》卷三八七引《甘澤謠》。", "《宋高僧傳》卷二十有《唐洛京慧林寺圓觀傳》）。"]'),
('aec5358e-b4f0-47ee-957b-374b127fe096','爲哥舒翰歌','西鄙人','唐','唐诗','tang','','[]','（天寶中，哥舒翰爲安西節度使，控地數千里，甚著威令。',156,'全唐诗/poet.tang.51000.json','["（天寶中，哥舒翰爲安西節度使，控地數千里，甚著威令。", "故西鄙人歌曰：）北斗七星高，哥舒夜帶刀。", "吐蕃總殺盡，更築[麗]（西）重壕。", "（《全唐詩》後二句作「至今窺牧馬，不敢過臨洮」。", "《南部新書》庚）（據《太平廣記》卷四九五引《乾𦠆子》及《知不足齋叢書》本《南部新書》校改。", "「哥舒」，《太平廣記》作「歌舒翰」，衍一字。", "）。"]'),
('c6c409f7-1df7-4a32-8bd8-cc185c9ab1f8','寒女吟','李白','唐','唐诗','tang','','[]','昔君布衣時，與妾同辛苦。',105,'全唐诗/poet.tang.51000.json','["昔君布衣時，與妾同辛苦。", "一拜五官郎，便索邯鄲女。", "妾欲辭君去，君心便相許。", "妾讀蘼蕪書，悲歌淚如雨。", "憶昔嫁君時，曾無一夜樂。", "不是妾無堪，君家婦難作。", "起來強歌舞，縱好君嫌惡。", "下堂辭君去，去後悔遮莫。", "（《才調集》六）。"]'),
('3579b2dd-56be-4596-99be-d8e6e4c5f803','日出東南隅行','李白','唐','唐诗','tang','','[]','（《文苑英華》一九三載李白此詩，注云：「集無此詩。',104,'全唐诗/poet.tang.51000.json','["（《文苑英華》一九三載李白此詩，注云：「集無此詩。", "」郭茂倩《樂府詩集》以爲殷謀詩。", "）秦樓出佳麗，正值朝日光。", "陌頭能駐馬，花處復添香。", "（《樂府詩集》卷二八署陳殷謀，《先秦漢魏晉南北朝詩·陳詩》卷九據以收入。", "）。"]'),
('68068990-33c1-4298-955e-0328ae78b131','代佳人寄翁參樞先輩','李白','唐','唐诗','tang','','[]','（《文苑英華》二六二注云：「此詩總目及《李集》皆不載，惟《英華》諸本有之。',328,'全唐诗/poet.tang.51000.json','["（《文苑英華》二六二注云：「此詩總目及《李集》皆不載，惟《英華》諸本有之。", "」）等閑經夏復經寒，夢裏驚嗟豈暫安。", "南家風光當世少，西陵江浪過江難。", "周旋小字桃燈讀，重疊遙山隔霧看。", "真是爲君飡不得，書來莫說更加飡。", "（《文苑英華》）（嚴羽《滄浪詩話·考證》謂本詩「乃晚唐之下者」。", "詹鍈《李詩辨僞》云：「按《文苑英華》編次體例，各類之中，一以時代先後爲序。", "此詩置於張祜、李洞、方干與李羣玉、陳陶之間，與太白時代相去懸遠，定是晚唐之作。", "」吳企明云：「先輩爲應試舉子對已及第者的稱呼，或是進士出身的人互相推敬的稱呼，李白從未應試，不應用此稱呼，集中亦無此稱。", "」又推測翁參樞或爲《登科記考》卷二二所載咸通元年盈第的翁彥樞，「參」、「彥」形近易訛，時代亦與李洞、方干相近。", "）。"]'),
('540f82fd-3684-4b8d-aabc-36cbe88aee2a','陽春曲','李白','唐','唐诗','tang','','[]','芣苡生前徑，含桃落小園。',24,'全唐诗/poet.tang.51000.json','["芣苡生前徑，含桃落小園。", "春心自搖蕩，百舌更多言。"]'),
('9e0f5a23-8b71-4dcc-977b-5f1940842520','摩多樓子','李白','唐','唐诗','tang','','[]','從戎向邊北，遠行辭密親。',177,'全唐诗/poet.tang.51000.json','["從戎向邊北，遠行辭密親。", "借問陰山侯，還知塞上人。", "（以上《萬首唐人絕句》。", "又《樂府詩集》作無名氏）（按影宋本《樂府詩集》卷五一收《陽春曲》，卷七八收《摩多樓子》，皆不署作者名，但緊接李白詩後，於例並非李白詩。", "汲古閣刊本目錄於《陽春曲》下署「無名氏」，可證。", "今人校點本於《摩多樓子》下據王琦《李太白集》補「李白」二字，尤誤，王琦已云《樂府詩集》作無名氏。", "）。"]'),
('313d6622-0384-4f62-80bc-b17d2db0e179','釣灘（一作「臺」）','李白','唐','唐诗','tang','','[]','磨盡石嶺墨，潯陽釣赤魚。',176,'全唐诗/poet.tang.51000.json','["磨盡石嶺墨，潯陽釣赤魚。", "靄峯尖似筆，堪畫不堪書。", "（《輿地紀勝》二十《徽州》有此詩，注稱在黟縣南十八里，相傳太白遊新安，嘗釣於此，作詩云云。", "《九域志》、《錦繡萬花谷》、《一統志》皆引「靄峯尖似筆」之句，以爲太白詩。", "康熙《徽州府志》二《山川》引此詩，「石嶺墨」作「石墨嶺」，「筆」作「削」。", "〖王琦《李太白詩集注》卷三十疑此詩或爲南唐另翰林學士李白作。", "〗）。"]'),
('ea81abe4-ff70-42be-a714-0412207f557e','小桃源','李白','唐','唐诗','tang','','[]','黟縣小桃源，烟霞百里間。',175,'全唐诗/poet.tang.51000.json','["黟縣小桃源，烟霞百里間。", "地多靈草木，人尚古衣冠。", "市向晡前散，山經夜後寒。", "（《輿地紀勝》二十《徯州》載此詩六句，注云見《龍城志》。", "《錦繡節花谷》亦載此詩，以爲太白作。", "王琦按：「此詩乃南唐許堅詩，其後小有二韻。", "」今按：已從《輿地紀勝》補其一韻。", "又按：《全唐詩》七五七及八六一兩見許堅，皆未收此詩。", "〖本書卷十五又笖此詩於許堅名下，凡八句。", "今仍兩存之。", "〗）。"]'),
('7e80a600-5389-4222-8bcc-77b455920e70','烏牙寺','李白','唐','唐诗','tang','','[]','夜宿烏牙寺，舉手捫星辰。',235,'全唐诗/poet.tang.51000.json','["夜宿烏牙寺，舉手捫星辰。", "不取高聲語，恐驚天上人。", "（《輿地紀勝》四七《蘄州》引王得臣《塵史》云：「蘄之黃梅有烏牙山，僧舍小詩，曰李太白也，李集中無之。", "」又《侯鯖錄》、《西清詩話》、《苕溪漁隱叢話》、《竹坡詩話》等又作《題峯頂寺》。", "〖詩見《塵史》卷中。", "王琦《李太白詩集注》卷三十收錄有關此詩之資料甚衆，其中引《侯鯖錄》，或云此爲王元之〖即王禹偁〗少登樓詩，《竹坡詩話》則云爲楊大年〖楊億〗幼年時作，《西清詩話》則以爲非極億作。", "王琦亦未能定之。", "諸書引文差異甚大，不具錄。", "〗）。"]'),
('913c1611-695d-40e9-90b1-a5d5cb6e23f1','桃源（二首） 一','李白','唐','唐诗','tang','','[]','昔日狂秦事可嗟，直驅雞犬入桃花。',47,'全唐诗/poet.tang.51000.json','["昔日狂秦事可嗟，直驅雞犬入桃花。", "至今不出煙溪（一作「巒」）口，萬古潺湲二（一作「一」）水斜。", "。"]'),
('b5776c6e-6641-4733-9f4d-4015dc7745a6','桃源（二首） 二','李白','唐','唐诗','tang','','[]','露暗煙濃草色新，一翻流水滿溪春。',62,'全唐诗/poet.tang.51000.json','["露暗煙濃草色新，一翻流水滿溪春。", "可憐漁歌父重來訪，只見桃花不見人。", "（《輿地紀勝》六八《常德府》引《綿州志》云「李白逸篇」）。"]'),
('2134590c-79c3-4a94-b4ce-0cbb26714ad6','普照寺','李白','唐','唐诗','tang','','[]','天台國清寺，天下爲四絕。',208,'全唐诗/poet.tang.51000.json','["天台國清寺，天下爲四絕。", "今到普照遊，到來復何別。", "柟（一作「枿」）木白雲飛，高僧頂殘雪。", "門外（一作「前」）一條溪（一作「水」），幾回流歲月。", "（《咸淳臨安志》八四。", "○蘇東坡曰：「予舊在富陽，見國清院太白詩，絕凡近，即此篇也。", "」《漁隱叢話》：「新安水西寺，寺依山背，下瞰長溪。", "太白題詩斷句云：『檻外一條溪。", "幾回流碎月。", "』今集中無之。", "」王琦按：「《漁隱》所引，即此篇末二句也，蓋未睹全篇，故訛以爲《是否水西寺》斷句也。", "」。）"]'),
('f5bd656f-ec24-4806-ab9a-b3f4cf4dc14e','興唐寺','李白','唐','唐诗','tang','','[]','（在歙縣郡城練水西，唐至德二年建。',197,'全唐诗/poet.tang.51000.json','["（在歙縣郡城練水西，唐至德二年建。", "宋太平舉國中勅改太平舉國寺。", "）天台國清寺，天下稱四絕。", "我來舉唐遊，於中更無別。", "枿木劃斷雲，高峯頂積雪。", "檻外一條溪，幾回流碎月。", "（康熙《徽州府志》十八《寺觀》。", "○今按：此詩與前篇，異地異題，輾轉漢傳，各有可取之處。", "《苕溪漁隱》所引，應即此一篇之末二句。", "王琦未見此篇，不得稱《漁隱》以爲《題水西寺》斷句爲訛。", "〖宋朱弁《曲洧舊聞》卷八謂此詩石刻在歙溪西太平寺。", "〗）。"]'),
('2a401105-2f4f-4467-9b8c-ee4d39cb3a7e','殷十一贈栗岡硯','李白','唐','唐诗','tang','','[]','殷侯三玄士，贈我栗岡硯。',85,'全唐诗/poet.tang.51000.json','["殷侯三玄士，贈我栗岡硯。", "灑染中山毫，光映吳門練。", "天寒水不凍，日用心不倦。", "攜此臨墨池，還如對君面。", "（高似孫《硯箋》四）（見宋初吳淑《事類賦》卷十五，「光映」作「光輝」。", "）。"]'),
('b225361e-84a7-4e32-b4b8-0f73af0c8cef','贈江油尉','李白','唐','唐诗','tang','','[]','嵐光深院裏，傍砌水泠泠。',176,'全唐诗/poet.tang.51000.json','["嵐光深院裏，傍砌水泠泠。", "野燕巢官舍。", "溪雲入[古]廳。", "日斜孤吏過，簾捲亂峯青。", "五色神仙尉，焚香讀道經。", "（楊慎《全蜀藝文志》）（見《蜀中名勝記》卷十，云此詩「爲米芾書，刻在縣衛」。", "「古」字據此書補。", "吳企明謂此詩中「五色神仙尉」一句，用《北夢瑣言》卷十二所載張裼之子聞說壁魚入道經函，因蠹食神仙字身有五色，吞之可成仙的典故，因疑此詩爲晚唐人或宋人所假託。", "）。"]'),
('29a8c83b-ca99-4598-8413-b6963ce4296e','南陵五松山別荀七','李白','唐','唐诗','tang','','[]','六即潁水荀，何慚許郡賓。',78,'全唐诗/poet.tang.51000.json','["六即潁水荀，何慚許郡賓。", "相逢太史奏，應是聚賢人。", "玉隱且在石，蘭枯還見春。", "俄成萬里別，立德貴清真。", "（見影宋蜀刻本《李太白文集》卷十三，「立德」作「立得」。", "）。"]'),
('eb6d00ef-3e92-4b27-a745-80de47fc2fa4','暖酒','李白','唐','唐诗','tang','','[]','熱暖將來賓鐵文，暫時不動聚白雲。',65,'全唐诗/poet.tang.51000.json','["熱暖將來賓鐵文，暫時不動聚白雲。", "撥卻白雲見青天，掇頭裏許便乘仙。", "（見影宋蜀刻本《李太白文集》卷二十三。", "）（以上繆氏本《太白集》）。"]'),
('a4e5436d-55d9-4dbe-af65-6480f7eab7fd','棲賢寺','李白','唐','唐诗','tang','','[]','知見一何高，拭眼避天位。',42,'全唐诗/poet.tang.51000.json','["知見一何高，拭眼避天位。", "同觀洗耳人，千古應無愧。", "（以上《正德南康府志》十《詩類》）。"]'),
('e5f5d3ef-8c37-46c2-9798-275ffcdb939e','題樓山石笋','李白','唐','唐诗','tang','','[]','石笋如卓筆，縣之山之巔。',76,'全唐诗/poet.tang.51000.json','["石笋如卓筆，縣之山之巔。", "誰爲不平者，與之書青天。", "（《遵義府志》四五《藝文詩》）（按此詩太白文集不載，即他拾遺本亦無之。", "孫志有此，不知何本，仍錄俟考。", "）。"]'),
('9d78816d-e627-48dd-9f7d-758042fd0d0f','闕題','李白','唐','唐诗','tang','','[]','朝披夢澤雲，笠釣青茫茫。',154,'全唐诗/poet.tang.51000.json','["朝披夢澤雲，笠釣青茫茫。", "暮跨紫鱗去，海氣侵肌涼。", "（《苕溪漁隱叢話前集》五引東坡。", "又《詩話總龜》七《評論門》引《百斛明珠》。", "云：「予都下見有人携一紙文書，字則顏魯公也，墨跡如未乾，紙亦新健，其首兩句云云。", "此語非太白不能道。", "」〖此即傳爲李白所作之《上清寶鼎詩》中的四句，全詩及考證見《全唐詩續拾遺》卷十四。", "〗）。"]'),
('e1784005-83c8-4ebc-9d28-700374a0eb84','闕題','李白','唐','唐诗','tang','','[]','庭中繁樹乍含芳，紅錦重重翦作囊。',57,'全唐诗/poet.tang.51000.json','["庭中繁樹乍含芳，紅錦重重翦作囊。", "還合炎蒸留爍景，題來渭得好篇章。", "（王琦輯注《太白集》附錄）（詳後「句」末附按。", "）。"]'),
('52fb39aa-c15f-4383-8b26-eff34d8c8142','題寶圌山（圌音纏）（句）','李白','唐','唐诗','tang','','[]','樵夫與耕者，出入畫屏中。',23,'全唐诗/poet.tang.51000.json','["樵夫與耕者，出入畫屏中。", "（《方輿勝覽》五四）。"]'),
('08300ba0-8213-47ec-bf26-a3c0978290bd','句','李白','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('79147662-e6d9-4aef-a4f3-e6716e579770','句 一','李白','唐','唐诗','tang','','[]','野禽啼杜宇，山蝶舞莊周。',45,'全唐诗/poet.tang.51000.json','["野禽啼杜宇，山蝶舞莊周。", "（《苕溪漁隱叢話後集》四引《法藏碎金》）（見《法藏碎金》卷六。", "）。"]'),
('9e3b86d0-3b7a-4797-999a-42319b2cc418','句 二','李白','唐','唐诗','tang','','[]','霜結梅梢玉，陰凝竹幹銀。',12,'全唐诗/poet.tang.51000.json','["霜結梅梢玉，陰凝竹幹銀。"]'),
('18a68ae5-93b7-41ca-8d09-d80141e70ef1','句 三','李白','唐','唐诗','tang','','[]','竹粉千腰白，桃皮半頰紅。',12,'全唐诗/poet.tang.51000.json','["竹粉千腰白，桃皮半頰紅。"]'),
('e4838cf8-69ed-4e01-a869-d312988554d1','句 四','李白','唐','唐诗','tang','','[]','心爲殺人劍，淚是報恩珠。',12,'全唐诗/poet.tang.51000.json','["心爲殺人劍，淚是報恩珠。"]'),
('a8708a06-ceb1-4526-a90d-892046415f28','句 五','李白','唐','唐诗','tang','','[]','佳人微醉玉顏酡，笑伾粧樓澹小蛾。',16,'全唐诗/poet.tang.51000.json','["佳人微醉玉顏酡，笑伾粧樓澹小蛾。"]'),
('8b2e8f59-9a2e-43f3-bf22-a68c22dd7f59','句 六','李白','唐','唐诗','tang','','[]','借問單樓與同穴，可能銀漢勝重泉。',121,'全唐诗/poet.tang.51000.json','["借問單樓與同穴，可能銀漢勝重泉。", "（以上王琦輯注《太白集》附錄）（以上諸句及「庭中繁樹乍含芳」一首，王琦云見於《海錄碎事》、《錦繡萬花谷》二書，「未詳爲誰氏之作，其句法皆與太白不相似，亦皆以爲太白詩矣。", "」又推測或爲南唐時另一翰林學士李白撰。", "）。"]'),
('e6ff19b1-1052-42ab-a2d1-3e74126fe184','菩薩蠻','李白','唐','唐诗','tang','','[]','舉頭忽見衡陽雁，千聲萬字情何限。',110,'全唐诗/poet.tang.51000.json','["舉頭忽見衡陽雁，千聲萬字情何限。", "叵耐薄情夫，一行書也無。", "泣歸香閣恨，和淚淹紅粉。", "待雁却回時，也無書寄伊。", "（《尊前集》）（《全宋詞》第四冊第二五一月頁云《歷代詩餘》卷九載此爲陳以莊詞，楊金本《草堂詩餘》卷下作陳達叟詞。", "）。"]'),
('12966c79-9a9f-4b61-840d-5d6600fb8059','畫像題詩','杜甫','唐','唐诗','tang','','[]','迎旦東風騎蹇驢，旋呵凍手暖髯鬚。',186,'全唐诗/poet.tang.51000.json','["迎旦東風騎蹇驢，旋呵凍手暖髯鬚。", "洛陽無限丹青手，還有功夫畫我無？", "（《苕溪漁隱叢話後集》八云：「世有碑本子美畫像，上有詩云云。", "子美決不肯自作，兼集中亦無之，必好事者爲之也。", "」又《詩人玉屑》十一《考證》云：「『迎旦東風騎蹇驢』，決非唐人氣象，只似白樂天言語。", "今者世俗圖畫，以爲少陵詩，漁隱亦辨其非矣。", "黃伯思編入《杜集》，非也。", "」〖《詩人玉屑》所引，見《滄浪詩話·考證》。", "〗）。"]'),
('20bf5b64-fdd1-4359-808b-9473f4b74e71','句','杜甫','唐','唐诗','tang','','[]','君看牆頭桃樹花，盡是行人眼中血。',153,'全唐诗/poet.tang.51000.json','["君看牆頭桃樹花，盡是行人眼中血。", "（《螢雪叢說》下卷）（宋曾季貍《艇齋詩話》引唐人詩云：「時人有酒送張八，惟我無酒送張八。", "君有陌上梅花紅，盡是離人眼中血。", "」末二句與此僅數字不同。", "《唐詩紀事》卷三一收李約《贈韋況》有「明月照張八」之句，疑此詩亦李約作。", "《四庫提要》謂《螢雪叢書》錯誤甚多，作杜詩恐不足爲據。", "）。"]'),
('5e13840b-6c3b-4960-8e86-d911c6cd327b','','劉秩','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('ca001389-8d5a-480d-8eda-1c1cdbf9d6ae','過蕪湖','劉秩','唐','唐诗','tang','','[]','百里蕪湖縣，封侯自漢朝。',66,'全唐诗/poet.tang.51000.json','["百里蕪湖縣，封侯自漢朝。", "荻林秋帶雨，沙浦晚生潮。", "近海魚鹽富，瀕淮粟麥饒。", "相逢白頭叟，擊壤頌唐堯。", "（《嘉慶蕪湖縣志》二三《藝文志》）。"]'),
('658657fd-144b-4290-bc25-d3a1a6cc8f2d','題龍日寺西龕石壁','嚴武','唐','唐诗','tang','','[]','聖澤久潤物，皇明常獨幽。',260,'全唐诗/poet.tang.51000.json','["聖澤久潤物，皇明常獨幽。", "恩從祥風翱，德與和氣遊。", "報國建香剎，開蠻臨僻州。", "天長面綠水，地迥起朱樓。", "尋異遍衆壑，坐禪逢一丘。", "永懷根本妙，誓以身心修。", "奇色艷草滿，珍名嘉樹稠。", "遠江崩濤喧，復澗微雨休。", "嘹唳猿響谷，參差峯入流。", "碧煙曳篁徑，白日懸沙洲。", "泛海謝安石，吟詩王子猷。", "揚雄愛清靜，山簡多優游。", "性分固有適，蓍龜何足求？", "神閒孤臺月，目送千里舟。", "攜手逸羣品，浩歌邈悠悠。", "山情慕禽尚，詩格驚曹劉。", "旌能舉滯時，選異拔奇儔。", "鼎食當自致，巖棲難久留。", "嗟余參符守，漢主遠分憂。", "往往行春到，聞鐘散客愁。", "（《蜀中名勝記》二五《保寧府·巴州》）。"]'),
('adfbb8bf-7211-4847-8b0a-08771971eefb','寧國院（在新城縣）','牛仙客','唐','唐诗','tang','','[]','步步穿蘿入徑幽，柏高松老幾人游。',118,'全唐诗/poet.tang.51000.json','["步步穿蘿入徑幽，柏高松老幾人游。", "花開花落非僧事，自有清流對碧流。", "（《嘉慶浙江通志》二二七《寺觀》）（南宋潛說友《咸淳臨安志》卷八五收此詩，幷云此院唐時名碧流，吳越時因避諱更名碧沼，宋大中祥符元年始改名寧國。", "據此，詩題似應作《碧流院》）。"]'),
('33ba4c40-e83b-4dc5-8109-d5416cca19db','句','靈澈','唐','唐诗','tang','','[]','經來白馬寺，僧到赤烏年。',71,'全唐诗/poet.tang.51000.json','["經來白馬寺，僧到赤烏年。", "（《詩話總龜後集》四四《釋氏門》引《雪波齋日記》）（見《劉賓客文集》卷十九《澈上人文集紀》，詩題爲《芙蓉園新寺》。", "）。"]'),
('ccd9df7d-009c-4506-98a5-b345a6540d97','贈兄崇凱','范元凱','唐','唐诗','tang','','[]','空（〖1〗《全唐詩》二九五作何兆詩，題爲《贈兄》。',158,'全唐诗/poet.tang.51000.json','["空（〖1〗《全唐詩》二九五作何兆詩，題爲《贈兄》。", "首句「兄」《全蜀藝文志》作「君」○《全蜀藝文志》二○）（「崇凱，內江人，奏《花萼樓賦》爲第一。", "其弟元凱，亦自負其才，故贈兄」云云。", "○今按：本詩前有李白《送友人內江范崇凱》五律一首，查各本《李白集》題下均無內江范崇凱五字，王琦亦未加注，不知楊慎有何依據。", "特記於此。", "）。"]'),
('a9b3e154-2b8c-4bc6-8485-2b3afd05d149','題阮客舊居（《全唐詩》二六二作李陽冰，第三句「到」《詩話總龜》作「得」）','李𬜪','唐','唐诗','tang','','[]','空（趙明誠《金石錄》云：《題阮客舊居詩》，小篆書，《集古錄》以爲陽冰作。',150,'全唐诗/poet.tang.51000.json','["空（趙明誠《金石錄》云：《題阮客舊居詩》，小篆書，《集古錄》以爲陽冰作。", "驗其姓名，乃縉雲今李{茊/山}，非陽冰也。", "其字畫亦不工。", "蓋陽冰肅宗上元中嘗令縉運，其篆字石刻，尚多有存者，故歐陽公亦誤以此詩爲陽冰作爾。", "○《詩話總龜》二九《正訛門》〖趙明誠語見《金石錄》卷三十，「李{茊/山}」作「李𬜪」。", "〗）。"]'),
('792d644a-969f-498b-8cc3-2c913cc048bc','鐵山（一名鳳凰山）','獨孤及','唐','唐诗','tang','','[]','雁陣起秋雲，雞聲滿林屋。',45,'全唐诗/poet.tang.51000.json','["雁陣起秋雲，雞聲滿林屋。", "客思不可禁，鐵峯駐雕轂。", "（《蜀中名勝記》三○《潼川府·安岳縣》）。"]'),
('7ac137a8-d1a0-41de-b992-04735dd41885','經蘭亭故池聯句','嚴維','唐','唐诗','tang','','[]','（原注：鮑防、嚴維、劉全白、宋迪，共三十五人，具姓名。',370,'全唐诗/poet.tang.51000.json','["（原注：鮑防、嚴維、劉全白、宋迪，共三十五人，具姓名。", "大歷中唱和五十七人，元本不注姓名於聯句下。", "）曝水邀歡處，遺芳尚宛然。", "名從右軍出，山在古人前。", "蕪沒成塵跡，規模得大賢。", "湖心舟已並，村步騎仍連。", "賞是文辭會，歡同癸丑年。", "茂林無舊徑，修竹起新煙。", "宛是崇山下，仍依古道邊。", "院開新地勝，門占舊畬田。", "荒阪披蘭築，枯池帶墨穿。", "敍成應唱道，杯作每推先。", "空見雲生岫，時聞鶴唳天。", "滑苔封石磴，密篠礙飛泉。", "事感人寰變，歸慚府服牽。", "寓時仍覩葉，歎逝更臨川。", "野興攀藤坐，幽情枕石眠。", "玩奇聊倚策，尋異稍移船。", "草露猶霑服，松風尚入弦。", "山遊稱絕調，今古有多篇。", "（桑世昌《蘭亭考》十二）（此詩爲衆人聯句之作。", "最早應見於《大曆年浙東聯唱集》，此書今不傳。", "北宋孔延之《會稽掇英總集》卷十四收入時，每兩句後空兩格，題注：「元本不注名姓於聯句下。", "」「元本即指《大曆年浙東聯唱集》。"]'),
('41d36c62-2c18-45e2-9d7e-42083622a84a','泛太湖','薛據','唐','唐诗','tang','','["\u592a\u6e56"]','萬頃波涵一碧秋，飄飄隨處任輕舟。',87,'全唐诗/poet.tang.51000.json','["萬頃波涵一碧秋，飄飄隨處任輕舟。", "踏歌聽立忘機鷺，擊楫驚飛熟夢鷗。", "烟水淡圖山點翠，雲霞麗景日拋毬。", "帆收不盡湖天景，何必蒹葭古渡頭。", "（《古今圖書集成·山川典》二八二《太湖部》）。"]'),
('deabcfa8-b5aa-40a8-8b24-708d5793f742','題竹','玄覽','唐','唐诗','tang','','[]','（玄覽，大曆末住荆州陟岵寺，道高有風韻，人不可得而親。',217,'全唐诗/poet.tang.51000.json','["（玄覽，大曆末住荆州陟岵寺，道高有風韻，人不可得而親。", "張璪嘗畫古松於齋壁，符載讚之，衛象詩之，亦一時三絕，覽悉加堊焉。", "問其故，曰：「無事疥吾壁也。", "」僧那即其甥，爲寺之患，發瓦探鷇，壞牆薰鼠，覽未嘗責。", "有弟子義詮，布衣一食，覽亦不稱。", "或怪之，乃題詩於竹曰：）大海從魚躍，長空任鳥飛。", "欲知吾道廓，不與物情違。", "（《酉陽雜俎前集》十二《語資》。", "又《詩話總龜》三十《道僧門》引《古今詩話》。", "又《萬首唐人絕句》補本十，詩中前二句與後二句倒置。", "。）"]'),
('bb51edd6-2fb2-4973-8d74-8125cdfb1109','貞元六年春三月庚子百寮宴於曲江亭上賦詩以賜之','李适','唐','唐诗','tang','','[]','歲閏節華晚，衆芳繁暮春。',125,'全唐诗/poet.tang.51000.json','["歲閏節華晚，衆芳繁暮春。", "霽日天地晴，元巳風景新。", "禊飲傳舊俗，古今歡此辰。", "至樂在同和，絲竹奚所陳。", "薰琴是賞心，姑射可凝神。", "何必尚躭緬，浮觴曲水濱？", "（《太平御覽》五九二《文部·御製》引《唐書》。", "）（今按：兩《唐書》本紀均不載，《全唐詩》另有一首不同。", "）。"]'),
('3fa72d96-9a31-4634-b05a-721700be9740','三月三日寒食從劉八丈使君登遷仁樓眺望','李穆','唐','唐诗','tang','','[]','從公無小大，在伴樂人賢。',106,'全唐诗/poet.tang.51000.json','["從公無小大，在伴樂人賢。", "楚國逢荒歲，隨人若有年。", "空波交水埒，重岫夾畬田。", "桑柘溫風軟，雲霞返照鮮。", "因高寺剎迥，臨遠郡樓偏。", "花柳清明節，親賓上巳筵。", "故鄉徒有路，春雁獨歸邊。", "幸望山陰客，爲文內史前。", "（《劉長卿集》五）。"]'),
('b34d73c8-d4df-4289-8f22-9dac80455351','留辭','李穆','唐','唐诗','tang','','[]','（今按：劉長卿另有《送李穆歸淮南詩》，《全唐詩》一五一誤以此詩爲長卿詩○同前八。',42,'全唐诗/poet.tang.51000.json','["（今按：劉長卿另有《送李穆歸淮南詩》，《全唐詩》一五一誤以此詩爲長卿詩○同前八。", "）。"]'),
('8a13722f-8284-43ee-a787-1517d637d7f0','送韋判官赴閩中','皇甫冉','唐','唐诗','tang','','[]','空（《全唐詩》二一○作皇甫詩。',46,'全唐诗/poet.tang.51000.json','["空（《全唐詩》二一○作皇甫詩。", "第四句「傷」《文苑英華》作「驚」《文苑英華》二七二《送行》）。"]'),
('a3239d1f-b2d7-4c4c-ba6d-b7cf1912c983','寄（一作「贈」）章司直','皇甫冉','唐','唐诗','tang','','[]','空（原注：「《百家詩選》作郎士元詩。',48,'全唐诗/poet.tang.51000.json','["空（原注：「《百家詩選》作郎士元詩。", "」《全唐詩》二四八作郎士元《贈韋司直》同上二五四《寄贈》）。"]'),
('ad1252aa-58d8-482e-9429-b97d85df647c','三月三日後亭泛舟','皇甫冉','唐','唐诗','tang','','[]','越中山水高且深，興來無處不登臨。',45,'全唐诗/poet.tang.51000.json','["越中山水高且深，興來無處不登臨。", "永和九年刺海郡，暮春三月醉山陰。", "（桑世昌《蘭亭考》十二）。"]'),
('a9be8b56-8f0b-477c-9f5e-99d517da5ce4','太姥山','薛令之','唐','唐诗','tang','','[]','揚舲窮海島，選勝訪神仙。',73,'全唐诗/poet.tang.51000.json','["揚舲窮海島，選勝訪神仙。", "鬼斧巧開鑿，仙蹤常往還。", "東甌冥漠外，南越渺茫間。", "爲問容成子，刀圭乞駐顏。", "（《古今圖書集成·職方典》一一○八《福寧州部》）。"]'),
('832f5525-5dfe-486a-b781-ac067583d98e','送元使君','錢起','唐','唐诗','tang','','[]','郢門將咫尺，龍節莫夷猶。',51,'全唐诗/poet.tang.51000.json','["郢門將咫尺，龍節莫夷猶。", "送客與雲散，行人看月愁。", "遙聞江漢水，日與政聲流。", "（《輿地紀勝》八四《郢州》）。"]'),
('51ae71a4-d49a-4bda-beea-c20b1b689f6a','歷山','魏炎','唐','唐诗','tang','','[]','（齊州城東有孤石，平地聳出，俗謂之歷山。',98,'全唐诗/poet.tang.51000.json','["（齊州城東有孤石，平地聳出，俗謂之歷山。", "以北有泉，號舜井。", "東隔小街，又有石井，汲之不絕，云是舜東家之井。", "乾元中有魏炎者，於此題詩曰：）齊州城東舜子郡，邑人雖移井不改。", "時聞洶洶動綠波，猶謂華井中在。"]'),
('ce48467d-1b82-4aec-91e5-d8213627f1e4','又曰','魏炎','唐','唐诗','tang','','[]','西家今爲定戒寺，東家今爲練戒寺。',32,'全唐诗/poet.tang.51000.json','["西家今爲定戒寺，東家今爲練戒寺。", "一邊井中投一瓶，兩井相搖響泙濞。"]'),
('2796398b-d3d8-44b8-a942-9e7f31e93f30','又曰','魏炎','唐','唐诗','tang','','[]','濟南郡裏多沮洳，娥皇女英汲井處。',47,'全唐诗/poet.tang.51000.json','["濟南郡裏多沮洳，娥皇女英汲井處。", "竊向池中潛甽來，澆茆畦上平流去。", "（《封氏聞見記》八《歷山》）。"]'),
('b3f93372-0398-48b5-9d4a-e729495291c0','','戎昱','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('c0acb14e-6223-4453-b9a1-a863b56e320a','詩','戎昱','唐','唐诗','tang','','[]','寒食涔陽諸小兒，齊歌齊舞帶花枝。',92,'全唐诗/poet.tang.51000.json','["寒食涔陽諸小兒，齊歌齊舞帶花枝。", "郡從兵亂年荒後，人似開元天寶時。", "（《輿地紀勝》引此四句後，注「云云」二字，復引「行春」二句。", "知原詩爲七律，引時刪去第三聯，今僅六句。", "此處分列，未允。", "）。"]'),
('e3700468-1cbc-49fb-8305-0b61996e392a','句 一','戎昱','唐','唐诗','tang','','[]','行春更欲遊何處，東郭門前竹馬期。',16,'全唐诗/poet.tang.51000.json','["行春更欲遊何處，東郭門前竹馬期。"]'),
('b43c1faf-8a76-4da9-a0ee-1289c8d30cda','句 二','戎昱','唐','唐诗','tang','','[]','不須挂嶺居天末，但見涔陽在眼前。',90,'全唐诗/poet.tang.51000.json','["不須挂嶺居天末，但見涔陽在眼前。", "〖1〗（以上《輿地紀勝》七十《灃州》）（〖1〗《輿地紀勝》卷一○三《靜江府》引「不知桂嶺居天末」句，題作《寄薛評事》，注云：「見《曹州圖經》。", "」）。"]'),
('4e5c9f1f-d009-4a10-ae40-cd7e2805fca5','藥（一見《宋之問集》）','陳潤','唐','唐诗','tang','','[]','有嘉（宋作「卉」）秘神仙，君臣有禮焉。',105,'全唐诗/poet.tang.51000.json','["有嘉（宋作「卉」）秘神仙，君臣有禮焉。", "忻當苦口喻，不畏入腸偏。", "扁鵲功成日，神農定器然（宋作「品年」）。", "丹成如可待，鷄犬自聞天。", "（《文苑英華》三二七《花木》。", "此詩在宋之問《春泉洗藥》後，缺姓名，據目錄作陳潤。", "）。"]'),
('e4afee65-f035-4956-87a1-47994ccd5021','酬張二十員外（《全唐詩》二四二張繼《江上送客遊廬山》詩後）','竇叔向','唐','唐诗','tang','','["\u5e90\u5c71"]','空（此詩原缺出處，應出《文苑英華》卷二四三，題作《酬張二十員外前成長子博士叔向》，署「張繼」，《全唐詩》據以收於張繼名下，岑仲勉《唐人行第錄》考證此應爲竇叔向詩',141,'全唐诗/poet.tang.51000.json','["空（此詩原缺出處，應出《文苑英華》卷二四三，題作《酬張二十員外前成長子博士叔向》，署「張繼」，《全唐詩》據以收於張繼名下，岑仲勉《唐人行第錄》考證此應爲竇叔向詩，張二十即張繼。", "此詩題應作《酬張二十員外》，「前國子博士叔向」爲附收入張作時之署名。", "後人不明唐集附收之例，因誤作張詩。", "）。"]'),
('b51e6574-b34a-4ce6-b469-2cb9f5ab360f','題普門上人房（《文苑英華》二三五《寺院》〖1〗）','皇甫曾','唐','唐诗','tang','','[]','空（〖1〗《全唐詩》卷二四九作皇甫冉，卷一四八又作劉長卿詩，另日末流藏唐鈔本《唐詩卷》則作郎士元詩。',52,'全唐诗/poet.tang.51000.json','["空（〖1〗《全唐詩》卷二四九作皇甫冉，卷一四八又作劉長卿詩，另日末流藏唐鈔本《唐詩卷》則作郎士元詩。", "）。"]'),
('2dd27c72-d591-45f6-9d65-c74df8c71d2d','送韓司直（《全唐詩》二四八作郎士元詩，第三句「春草」，《文苑英華》作「芳草」○同上二七二《送行》〖1〗）','皇甫曾','唐','唐诗','tang','','[]','空（〖1〗《全唐詩》卷一四八又作劉長卿詩。',38,'全唐诗/poet.tang.51000.json','["空（〖1〗《全唐詩》卷一四八又作劉長卿詩。", "《極玄集》卷下又作皇甫冉詩。", "〗）。"]'),
('cde5b36a-0894-4d3c-9f4b-f9178d4ccef1','句','陸贄','唐','唐诗','tang','','[]','（贄爲渭南尉有詩云云。',187,'全唐诗/poet.tang.51000.json','["（贄爲渭南尉有詩云云。", "蓋縣內多流泉。", "）姜泉流渺渺，夾砌樹陰陰。", "（宋敏求《長安志》十七《渭南縣》。", "）（今按：《全唐詩》引《唐語林》，謂任江淮尉題廰詩句。", "第一句不同，第二句「夾」誤「來」。", "〖此引《長安志》當爲《經訓堂叢書》本，《四庫全書》本前句作「遶堦流虢㶁」，《唐語林》卷四作「遶階流助𣵪」，「助𣵪」當作「渺渺」。", "《記纂淵海》卷二四題作《題姜泉》，前句作「遶街流渺渺」。", "〗）。"]'),
('e43e3f24-d8e4-4f73-b656-528d2ce3677e','語錄詩','無住','唐','唐诗','tang','','[]','慧眼近空心，非關髑髏孔。',67,'全唐诗/poet.tang.51000.json','["慧眼近空心，非關髑髏孔。", "對面說不識，饒你母姓董。", "（敦煌寫本《歷代法實記》所附（《歷代法寶記》云此爲無住引王梵志詩。", "此作無住，似誤。", "）。"]'),
('f78e62ce-db93-4c29-83b5-25a5fec4f559','詠走馬燈詩','無際','唐','唐诗','tang','','[]','團團遊了又來遊，無箇明人指路頭。',64,'全唐诗/poet.tang.51000.json','["團團遊了又來遊，無箇明人指路頭。", "除卻心中三昧火，鎗刀馬一齊休。", "（《悅心集》一）（曹汛謂走馬燈始見於宋，唐時未有，詩疑出依託。", "）。"]'),
('a982470e-d834-4abc-966c-502d713d75a3','榮祿（句）','張九宗','唐','唐诗','tang','','[]','牛羊衛草窺環珮，鳥雀離花聽管絃。',33,'全唐诗/poet.tang.51000.json','["牛羊衛草窺環珮，鳥雀離花聽管絃。", "（《輿地紀勝》一五五《遂寧府》）。"]'),
('920cb46a-d278-43ec-bc70-7fd7a5452ed1','白雲向空盡（原注：《類詩》作焦郁。《全唐詩》五○五作焦郁詩〖1〗）','周存','唐','唐诗','tang','','[]','白雲生（一作「昇」）遠岫，搖曳入晴空。',223,'全唐诗/poet.tang.51000.json','["白雲生（一作「昇」）遠岫，搖曳入晴空。", "乘化隨舒卷，無心任始終。", "欲銷仍白（一作「帶」）日，將斷或（一作「更」）因風。", "勢薄飛難定，天高色易窮。", "影收元氣表，光滅太虛中。", "況（一作「儻」）若從龍去（一作「出」），還施潤（一作「濟」）物功。", "（《文苑英華》一八二《省試》）（明刻本《文苑英華》注引《類詩》，指宋人所編之《唐宋類詩》，其於省試諸詩的歸屬，與《文苑英華》有異。", "就今所可考知之各例看，多以《文苑英華》所署者爲長。", "而《全唐詩》多從《類詩》，似未允。", "）。"]'),
('4f991aaa-fdc0-4ea2-90f7-471d1dffd3a2','竹〖1〗','張南史','唐','唐诗','tang','','[]','竹價長東南，別種殊草木。',166,'全唐诗/poet.tang.51000.json','["竹價長東南，別種殊草木。", "成林處處雲，抽筍年年玉。", "天風起成韻，池水涵更綠。", "閒臨庾信園，數竿心自足。", "（《古今圖書集成·草木典》一九二《竹部》）（〖1〗《文苑英華》卷三二五、《全唐詩》卷二九六收張南史《竹》詩，爲一字至七字詩。", "此作五言詩，而詩句與一字至七字詩大致相同，可斷定爲後人據原詩改寫而成。", "《佩文斎詠物詩選》卷三三五所收亦同此。", "）。"]'),
('e01abff6-50a0-4a83-8cdd-0b80a6e629fb','晚次渭上','冷朝陽','唐','唐诗','tang','','[]','晚來清渭上，一似楚江邊。',57,'全唐诗/poet.tang.51000.json','["晚來清渭上，一似楚江邊。", "魚網依沙岸，人家旁水田。", "不逢京口信，空認渡頭船。", "逆旅無消息，歸心誰爲傳？", "（《又玄集》上）。"]'),
('2bbf5206-a54a-4be4-8d6e-ef9a069dccb9','過繡林（句）','于鵠','唐','唐诗','tang','','[]','繡林直照劉郎浦，鋪磧女臯。',29,'全唐诗/poet.tang.51000.json','["繡林直照劉郎浦，鋪磧女臯。", "（《輿地紀勝》六五《江陵府》）。"]'),
('bff1456b-997f-4f2a-9d5d-7e74c5550846','登瀛洲閣〖1〗','李愿','唐','唐诗','tang','','[]','翠閣傍瀛洲，洲中勝事幽。',110,'全唐诗/poet.tang.51000.json','["翠閣傍瀛洲，洲中勝事幽。", "沙明眠雪鷺，波漲宿霜鷗。", "濺雨荷盤膩，縈風柳帶柔。", "公餘自多暇，尊酒奉仙遊。", "（曹汛謂康熙《蓬萊縣志》卷二、乾隆《登州府志》卷；用均云《登蓬萊閣》爲宋李愿撰。", "並疑其人約歐陽修同時。", "姑仍存之，俟考詳。", "）。"]'),
('c3c729b8-9922-4aec-a28c-d053b5f7b8aa','望仙門','李愿','唐','唐诗','tang','','[]','樓影空門裏，門開望衆仙。',72,'全唐诗/poet.tang.51000.json','["樓影空門裏，門開望衆仙。", "綠鬟雲漠漠，翠黛月涓涓。", "煙駕知何處，星槎記昔年。", "夕陽孤鳥畔，渺渺海浮天。", "（《古今圖集當成·職方典》二八○《登州府部》）。"]'),
('11ed7622-9b8b-47da-b29f-1279aa58320c','梅花吟','李愬','唐','唐诗','tang','','[]','平淮策騎過東來，適遇梅花灼爍開。',52,'全唐诗/poet.tang.51000.json','["平淮策騎過東來，適遇梅花灼爍開。", "相耐歲寒存苦節，故於冷境發枯荄。", "（《弘治黃州府志》七《藝文·黃梅縣》）。"]'),
('01d2ff56-9c8e-4c2a-bb47-a5fa460604a6','漳州（句）','徐放','唐','唐诗','tang','','[]','南宮才調久淹留，符節初臨海上州。',32,'全唐诗/poet.tang.51000.json','["南宮才調久淹留，符節初臨海上州。", "（《輿地紀勝》一三一《漳州》）。"]'),
('af27d77b-4437-4002-ba58-e50b5584fcbf','留別劉員外','朱放','唐','唐诗','tang','','[]','寥落窮秋九月天，風吹白雪起江邊。',55,'全唐诗/poet.tang.51000.json','["寥落窮秋九月天，風吹白雪起江邊。", "豈意與君於此別，相看挃淚水潺湲。", "（《四部叢刊》影印明正德本《劉隨州詩集》八）。"]'),
('aa6f9439-7c07-4c42-84d8-28caf5fd2dab','膏澤多豐年','張聿','唐','唐诗','tang','','[]','空（原缺姓名，據目錄補。',54,'全唐诗/poet.tang.51000.json','["空（原缺姓名，據目錄補。", "《全唐詩》四六六作薛存誠，第四句「庾」《文苑英華》作「慶」，又七八七列入無名氏。", "）。"]'),
('d018613d-82c5-40c1-b4e3-31492bc7f52c','望禁苑祥光','張聿','唐','唐诗','tang','','[]','空（原缺姓名，據目錄補。',63,'全唐诗/poet.tang.51000.json','["空（原缺姓名，據目錄補。", "《全唐詩》七八七列入無名氏，第七句「鼎氣」《文苑英華》作「暴氣」○以上《文苑英華》一八○《省試》。", "）。"]'),
('d090eea9-5041-41eb-84d8-14f4c7c8f9b9','題皎然影堂','范傳正','唐','唐诗','tang','','[]','（皎然名晝，以貞元元年終山寺。',245,'全唐诗/poet.tang.51000.json','["（皎然名晝，以貞元元年終山寺。", "有集十卷，于頔序集。", "貞元八年正月，勅寫其文集入於秘閣，天下榮之。", "又著《儒釋交遊傳》及《內典類聚》共四十卷，《號呶子》十卷，時貴流布。", "元和四年，太守范傳正、會稽釋靈澈同過舊院，就影堂傷悼彌久，遺題曰：）道安已返無何鄉，慧遠來過舊草堂。", "余亦當時及門者，共吟佳句一焚香。", "（《古今圖書集成·神異典》一六九《僧部列傳》引《高僧傳》）（見《宋高僧傳》卷二十九《唐湖州杼山皎然傳》。", "「以貞元元年終山寺」，《宋高僧傳》作「以貞元年終山寺」。", "據趙昌平考證，皎然約卒於貞元末。", "）。"]'),
('2e35e787-92aa-453d-81ee-357d775f5fd0','秋疾初愈月夜詠左思招隱詩因而成詠','權德輿','唐','唐诗','tang','','[]','閑吟理輕步，不厭凉夜詠。',72,'全唐诗/poet.tang.51000.json','["閑吟理輕步，不厭凉夜詠。", "斷續風際聲，清羸月中影。", "螢光拂花露，泉脈連桐井。", "心暢百慮銷，境條萬籟靜。", "前賢有遺韻，顧我三日省。", "朗懷方自怡，星河漸耿耿。"]'),
('d756e2b0-4fb8-436f-ba12-1778b6e16f1b','臥病初愈崔侍御相訪','權德輿','唐','唐诗','tang','','[]','移疾門常掩，今朝枉繡衣。',48,'全唐诗/poet.tang.51000.json','["移疾門常掩，今朝枉繡衣。", "笑言之乍愜，拜伏力猶微。", "晚歲貞筠少，貧家上客稀。", "如何忽見訪，里巷有清輝。"]'),
('013f7e88-6d59-48e5-9931-3ac310b902da','夏雨率成呈邑中諸','權德輿','唐','唐诗','tang','','[]','片雲飛暮雨，瀟灑小亭閑。',48,'全唐诗/poet.tang.51000.json','["片雲飛暮雨，瀟灑小亭閑。", "細響疎蕪裏，目涼坐臥間。", "已深池際水，更綠枕前山。", "未敢勞車馬，柴扉且閉關。"]'),
('22d953c0-6b63-4a6d-bbf8-eaddef7408f3','自咎','權德輿','唐','唐诗','tang','','[]','自咎咎何窮，飄然蓽戶中。',74,'全唐诗/poet.tang.51000.json','["自咎咎何窮，飄然蓽戶中。", "清時名未立，稔歲室猶空。", "幽獨慚芳桂，飛鳴羨早鴻。", "出門何所見，歏息向秋風。", "（以上《四部叢刊》影印大興氏刊本《權載之文集》一）。"]'),
('2e4063b2-a9e4-4dcb-bcaf-aca4f55a17dd','題隱者所居','權德輿','唐','唐诗','tang','','[]','一逕茅茨下，千峯麋鹿羣。',54,'全唐诗/poet.tang.51000.json','["一逕茅茨下，千峯麋鹿羣。", "鴻妻同懶逸，漁父每知聞。", "旦暮鳥擇木，天陰山出雲。", "此心終不動，鼓腹向堯君。", "（同前七）。"]'),
('fb2ea9bc-83ef-4cc3-982e-d7fbc770c5fd','天竺寺','權德輿','唐','唐诗','tang','','[]','香剎西天寺，昔遊夢中。',77,'全唐诗/poet.tang.51000.json','["香剎西天寺，昔遊夢中。", "煙蘿迷俗駕，猿狖應山童。", "蕭颯松靜，欹危石棧通。", "雲霞棲半壁，丹紺照晴空。", "世累悲何已，心期惜未同。", "相看整歸騎，花雨夕洪濛濛。", "（同前七）。"]'),
('d5bb0cb2-5835-4643-a969-68013ea49382','貞元七年蒙恩除太常博士自江東來朝時與郡君同行西岳廟停東祝謁元和八年拜東都留守途次祠下追計前事已二十三年于茲矣時郡君以疾恙續發因代書却寄','權德輿','唐','唐诗','tang','','[]','憶昔辛未歲，詔書下江酒濡。',323,'全唐诗/poet.tang.51000.json','["憶昔辛未歲，詔書下江酒濡。", "盡室赴禮官，脂車雜輜軿。", "行役過梁苑，淹留經圃田。", "（郡君表姊壻元俯爲宣武從事，權理宋州，郡君從壻李融，時爲鄭州，各淹留累日。", "）秦關信百二，征駕逾三千。", "仙掌眺蓮峯，靈祠謁八天。", "騶馭儼已駐，女巫爭來前。", "動容既紛若，展敬方肅然。", "（時爲女竺所導，過於恭敬，不能具舉。", "）蹇步入國門，華簪拱祥烟。", "諫曹迨居守，倐已十六遷。", "及茲東乘轅，二十餘三年。", "盛明受恩澤，清近皆聯翩。", "忽當禮寺重，俄忝相印懸。", "陳力才不任，乞骸詞頗堅。", "解龜罷八鼎，賜劍猶要麼泉。", "鄙夫何所能，實賴中饋賢。", "談笑皆體遠，箴規諒才全。", "拜恩理晨裝，詔使來駢闐。", "風生鞍馬疾，日出旌旗鮮。", "信宿歷道途，曩遊記周旋。", "暫別亦不易，沉痾今未痊。", "醫文驗桐君，道術依竺乾。", "庶憑神明佑，得使疾恙蠲。"]'),
('2f922380-6012-4394-985b-801e256f6d2c','漳州','張登','唐','唐诗','tang','','[]','漳州悲遠道，龕留大業僧。',49,'全唐诗/poet.tang.51000.json','["漳州悲遠道，龕留大業僧。", "七年馳便路，三躡石梯層。", "（《永樂大典》九七六四「歲」字韻引《恩平志》。", "）。"]'),
('7c02370b-c491-4056-94a9-c9fbd1376565','秋夜館中醉後作','張登','唐','唐诗','tang','','[]','一葉驚風風已涼，華燈照夜夜何長。',85,'全唐诗/poet.tang.51000.json','["一葉驚風風已涼，華燈照夜夜何長。", "閬山截雲不過雁，漲海浸日誰爲梁。", "北向多虞劍戛戛，南中獨望天茫茫。", "客亭遲還還復醉，醉裏狂歌歌更狂。", "（同上一一三一三「館」字韻引《張燈集》）。"]'),
('686852eb-5daf-407c-a2bf-eb81fef09cfd','賞牡丹（句）','李正封','唐','唐诗','tang','','[]','（唐文皇好詩，大和中賞牡丹，上謂程脩己曰：「今京邑人傳牡丹詩，誰爲首出？',119,'全唐诗/poet.tang.51000.json','["（唐文皇好詩，大和中賞牡丹，上謂程脩己曰：「今京邑人傳牡丹詩，誰爲首出？", "」對曰：「中書舍人李正封詩天番云云。", "」時楊妃侍，上曰：「妝臺前宜飲以一紫金盞酒，則正封之詩見矣。", "」）天香夜染衣，國色朝酣酒。", "（《唐詩紀事》四十）（見《松窗雜錄》。", "）。"]'),
('cf18b84f-88a7-4d04-a7c0-6599cd14eb99','峴山（句）','李正封','唐','唐诗','tang','','[]','峴山移柱石，流水輟恩波。',28,'全唐诗/poet.tang.51000.json','["峴山移柱石，流水輟恩波。", "（《輿地紀勝》八二《襄陽府》）。"]'),
('57c48d4a-5264-438e-8198-861fdcd806e4','九鯉湖','許稷','唐','唐诗','tang','','[]','道是燒丹地，依然雲水居。',71,'全唐诗/poet.tang.51000.json','["道是燒丹地，依然雲水居。", "山空人去後，夢醒客去初。", "溪雨飛沙霽，巖門隱霧虛。", "高歌對明月，松影落扶疎。", "（《古今圖書集成·山川典》三○二《九鯉湖部》。"]'),
('5bef5eb7-dfc3-4dc9-aa2e-eed2af51fae5','','韓愈','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('c0456205-941d-489e-8092-b51a6dc9ed21','題杜工部墳','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','何人鑿開混沌殼，二氣由來有清濁。',383,'全唐诗/poet.tang.51000.json','["何人鑿開混沌殼，二氣由來有清濁。", "孕其清者爲聖賢，鍾其濁者成愚樸。", "英豪雖沒名猶嘉，不肖虛死蓬麻。", "榮華一旦世俗眼，忠孝萬古賢人芽。", "有唐文物盛復全，名書史冊俱才賢。", "中間詩筆誰清新？屈指都無四五人。", "獨有工部稱全美，當日詩人無擬倫。", "筆追清風洗俗耳，心奪造化回陽春。", "天光晴射洞庭秋，寒玉萬頃清光流。", "我常愛慕如饑渴，不見其面生閑愁。", "今春偶客耒陽路，悽慘去尋江上墓。", "召朋特地踏煙霧，路入溪村數百步。", "招手借問騎牛兒，牧兒指我祠堂路。", "入門古屋三四間，草茅緣砌生無數。", "寒竹珊珊搖晚風，野蔓層層纏庭戶。", "升堂再拜心惻然，心欲虔啓不成語。", "一堆空土煙蕪裏，虛使詩人歎悲起。", "怨聲千古寄西風，寒骨一夜沉秋水。", "歸時處處多白酒，生肉如今家家有。", "飲酒食肉今如此，何故常人無飽死？", "子美歸日稱才賢，聶侯見待誠非喜。", "洎乎聖意再搜求，姦臣以此欺天子。", "捉月走入千丈波，忠諫便沉汩羅底。", "固知天意有所存，三賢所歸同一水。"]'),
('9a0558a4-9f00-4e88-8bbd-77fa0143d246','三傷頌','伏牛上人','唐','唐诗','tang','','[]','（斯五五五八卷錄此詩，題作「龍興寺香嚴和尚《嗟世三傷吟》」。',133,'全唐诗/poet.tang.51000.json','["（斯五五五八卷錄此詩，題作「龍興寺香嚴和尚《嗟世三傷吟》」。", "香嚴和尚法名智閑，青州人，住持鄧州香嚴山，梁乾化中卒。", "《宜堂集》卷十九、《宋高僧傳》卷十三有傳。", "該卷存前二首，其一爲「傷嗟啜刀鳥」，其三爲「傷嗟壘巢燕」，異文較多，校如次。", "校文中均以「一作某」代指該卷。", "）。"]'),
('dda65a40-8f31-4969-8866-59bb7b28a4ef','三傷頌 其一','伏牛上人','唐','唐诗','tang','','[]','傷嗟壘巢燕，雖巧無深見。',346,'全唐诗/poet.tang.51000.json','["傷嗟壘巢燕，雖巧無深見。", "修營一箇窠，往復幾千轉。", "雙飛碧水頭，對主動權虹梁畔。", "身緣覓食疲，口爲銜泥爛。", "驅馳九夏初，方產巢中卵。", "（「產巢」，一作「有窠」。", "）停騰怕饑渴，撫養知寒煖。", "憐惜過於人，銜蟲餧皆徧。", "（「餧」，一作「餵」）父爲理毛衣，母來將食饘（一作「眩」）。", "一旦翅翼成，（「一旦」句，一作「一旦翅開便」。", "）分飛不相管。", "世有少智人，懇力憂家眷。", "男女未成長，顏色已（一作「亦」）衰變。", "（「顏色」，一作「容顏」。", "）燕子燕子聽吾語，隨時且過休辛苦。", "縱使窠中千箇兒，秋風纔動終須去。", "（「秋風」句，一作「秋穴纔起皆飛去」。", "）世人世人不要貪，（「貪」，一作「忙」。", "）此言是藥思量取。", "（「思量取」，一作「容思量」。", "）饒你平生男女多，誰能伴歸泉路。", "（「饒你」二句，一作「饒渠平生男女多，三塗惡業自須當」。", "）。"]'),
('df253614-9565-4ade-91cc-b08e5e45c08e','三傷頌 其二','伏牛上人','唐','唐诗','tang','','[]','傷嗟鵽刀鳥，夜夜啼天曉。',281,'全唐诗/poet.tang.51000.json','["傷嗟鵽刀鳥，夜夜啼天曉。", "墜翼柳攀枝，（「柳」，一作「脚」。", "）身隨露葉低，影逐風枝裊。", "一種情相生，爾獨何枯槁。", "（「一種」二句，一作「一種情想生，尔何獨枯栲」。", "）驅驅飲啄稀，役役飛騰少。", "不是官所差，都緣業所造。", "（「都緣」句，一作「有緣業力造」。", "）亦似世間人，貪生不覺老。", "喫著能幾多，强自縈煩惱。", "咄絡無眼人，（「無眼人」，一作「無眠人」。", "）織絡何時了。", "只爲一六迷，遂成十二到。", "（「到」，一作「倒」。", "）{歠欠=鳥}刀{歠欠=鳥}刀林裏叫，（「叫」，一作「啼」。", "）山僧山僧床上笑。", "有人會意解推尋，不假三祇便成道。", "（「有人」二句，一作「有人會意解推尋，不歷僧祗便成道」。", "）。"]'),
('c085bc47-1a2f-43d9-93f5-6c8d6ce5f67a','三傷頌 其三','伏牛上人','唐','唐诗','tang','','[]','傷嗟造蜜蜂，忙忙採花蘂。',225,'全唐诗/poet.tang.51000.json','["傷嗟造蜜蜂，忙忙採花蘂。", "接翼入芳業，分頭傍煙水。", "抱蘂唼香滋，尋花戀春餌。", "驅馳如有縈，盤旋若遭魅。", "蹭蹬遇絲羅，飄零餵螻蟻。", "才能翅翼成，方始窠巢備。", "惡人把火燒，哀鳴樹中死。", "蜜是他人將，美是他人美。", "虛忙百草頭，於身有何利。", "世有少智人，與此恰相似。", "只緣貪愛牽，幾度虛沈墜。", "夏日歲處浮生，十年作童稚。", "一半悲與愁，一半病與悴。", "除折算將來，能得幾多子。", "更將有漏身，自翳無生理。", "永不見如來，都緣開眼睡。", "蜜蜂蜜蜂休役役，空哉終是他人喫。", "世人世人不要貪，留富他人有何益。"]'),
('e2c4bfae-f03c-4af0-8371-d642058a6599','一鉢歌','一鉢和尚','唐','唐诗','tang','','[]','阿剌剌，鬧聒聒，總是悠悠造末撻。',456,'全唐诗/poet.tang.51000.json','["阿剌剌，鬧聒聒，總是悠悠造末撻。", "（「阿」，《大正藏》本《景德傳燈錄》〖以下簡稱「一作」〗卷三十作「遏」。", "「末撻」，一作「抹㒓」）如饑喫監加得渴，枉却一生頭戛戛。", "（「戛戛」，一作「枿枿」。", "）究竟不能知本末，（「本末」，一作「始末」。", "）拋却死屍何處脫。", "閑事到頭須結撮，火落身上當頭撥。", "（「頭」，一作「須」。", "）莫待臨時叫菩薩，大丈夫兒須豁豁。", "（「大丈夫兒」，一作「丈夫語話」。", "）莫學癡人受摩捋，也繫裏，也擺撥，（「也繫裏」二句，一作「趁時結裏學擺撥」。", "）也學柔和也粗糲，亦解剃頭亦披褐，（「亦解」句，一作「也剃頭，也披褐」。", "）也學凡夫作生活。", "直言向君君未達，（「直言」，一作「直語」。", "）更作長歌歌一鉢。", "多中少，少中多，（「多中少」二句，一作「一鉢歌，多中一，一中多」。", "）莫笑野人一鉢歌，緣持此鉢度婆娑。", "（「一鉢歌」，一作「歌一鉢」。", "「緣持此鉢」，一作「曾將一鉢」。", "）青天寥寥月初上，此時境空含萬象。", "（「境空」，一作「影空」。", "）幾處浮生自是非，一源清潔無來往。", "（「清潔」，一作「清淨」。", "）莫謾將心學水泡，百毛流火無事交。"]'),
('03e23082-8019-4cb3-b414-3c8d2a389bfc','靈岩洞','蔣防','唐','唐诗','tang','','[]','一灣溪水出岩泉，前洞沉沉後洞連。',57,'全唐诗/poet.tang.51000.json','["一灣溪水出岩泉，前洞沉沉後洞連。", "可惜秦人不曾到，空留名蹟在桃川。", "（《古今圖書集成·職方典》一二六二《常德府部》）。"]'),
('494b0906-60eb-4540-a689-4b1fa24aaaf8','瀑布泉','劉禹錫','唐','唐诗','tang','','[]','時出西郊霽色開，尋真欲去重徘徊。',80,'全唐诗/poet.tang.51000.json','["時出西郊霽色開，尋真欲去重徘徊。", "風泉净洗高人耳，松柏化爲君子材。", "翠巘絶高尖插漢，碧潭無底攪轟雷。", "上盤下際非凡境，箇裏何曾俗客來。", "（《正德南康府志》十《詩類》）。"]'),
('1f3c1e4a-1ced-416c-9a14-fac27e879354','虎丘西寺','劉禹錫','唐','唐诗','tang','','[]','吳王冠劍作塵埃，葬地翻爲七寶臺。',80,'全唐诗/poet.tang.51000.json','["吳王冠劍作塵埃，葬地翻爲七寶臺。", "石砌百□光似鏡，井輪千轉響成雷。", "昔年棣萼聯枝發，今日蓮宮並蒂開。", "更有女郎墳在此，時時雲雨試僧來。", "（康熙顧《虎丘志》三《寺字》）。"]'),
('c3d9a52b-3056-44a5-a14a-defe59effd40','恩賜耆老布帛（《文苑英華》一八○《省試》）','張復元','唐','唐诗','tang','','[]','空（《全唐詩》三一九作崔樞詩。',75,'全唐诗/poet.tang.51000.json','["空（《全唐詩》三一九作崔樞詩。", "第二句「賑黎元」《文苑英華》作「軫玄元」，第三句「生涯作」作「生成在」，第七句「泰」作「太」，第八句「沾」作「澹」。", "）。"]'),
('0d004fd4-ad1c-4655-b2be-a2a5ee2609ce','過華山（句）（《全唐詩》四八四作楊虞卿句）','楊茂卿','唐','唐诗','tang','','[]','（《雲谿友議》卷中《中山誨》云：「楊危〖應作茂〗卿配校書《過華山》詩曰〖見下〗。',123,'全唐诗/poet.tang.51000.json','["（《雲谿友議》卷中《中山誨》云：「楊危〖應作茂〗卿配校書《過華山》詩曰〖見下〗。", "此句實爲佳對。", "又《唐語林》二《文學》，劉禹錫茂卿云。", "〖見下〗此詩題云《過華山下作》。", "而用蓮蓬之菡萏。", "極的當而暗靜矣。", "」）河勢崑崙遠，山形菡萏秋。", "（《唐詩紀事》三九）。"]'),
('236becaf-9ae6-4afc-8297-280df8d8e870','觀音巖','孟郊','唐','唐诗','tang','','[]','巖洞分明是普陀，和風甘雨向來多。',55,'全唐诗/poet.tang.51000.json','["巖洞分明是普陀，和風甘雨向來多。", "空山寂寞香燈少，蓮坐春雲長薜蘿。", "（《古今圖書集·職方典》七八五《安慶府部》）。"]'),
('eab411d4-398d-4046-ae47-b78e647a69df','虎丘寺','張籍','唐','唐诗','tang','','[]','望月登樓海氣昏，劍池無底浸雲根。',49,'全唐诗/poet.tang.51000.json','["望月登樓海氣昏，劍池無底浸雲根。", "老僧只怕山移去，日暮先教鎖寺門。", "（康熙顧湄《虎丘志》三《寺字》）。"]'),
('705043d3-fbbb-43a1-93ec-e4a96fc5f474','白門前','李賀','唐','唐诗','tang','','[]','白門前，大樓喜，懸虹雲，撻龍尾。',117,'全唐诗/poet.tang.51000.json','["白門前，大樓喜，懸虹雲，撻龍尾。", "劍破匣，舞蛟龍，蚩尤死，鼓龍蓬。", "天墮地，無驚飛，海千里。", "（《四部業刊》影印所以刊本《李賀歌詩編》）（此詩爲《全唐詩》卷三九三李賀《上之回》一詩之別本，前八句僅數字不同，末四句，《上之回》爲七言二句。", "）。"]'),
('66e2edea-796a-42d3-b54a-63a90a0bcd79','落葉','劉乂','唐','唐诗','tang','','[]','返蟻難尋穴，歸禽易見窠。',154,'全唐诗/poet.tang.51000.json','["返蟻難尋穴，歸禽易見窠。", "滿廊僧不厭，一片俗嫌多。", "（《詩話總亀後集》三八《詼諧門》（此詩出《苕溪漁歌隱業話前集》卷五五《宋朝雜記下》，作者作劉義。", "《詩人玉屑》卷三引《冷斎夜話》、《詩林廣記》卷二引《古今詩話》均以爲鄭谷詩，未詳孰是。", "「劉乂」，輯者意當指劉叉、乂、義相淆者較多，但此詩是否劉叉作，恐尚難確定。", "）。"]'),
('b8817723-0ce0-4458-a949-8559a7ec0a4c','黃鶴樓','賈島','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','高檻危簷勢若飛，孤雲野水共依依。',193,'全唐诗/poet.tang.51000.json','["高檻危簷勢若飛，孤雲野水共依依。", "青山萬古長如舊，黃鶴何年去不歸。", "岸映西山（一作「州」）城半山，烟生南浦樹將微。", "定知羽客無因見，空使含情對落暉。", "（《古今圖書集成·職方典》一一二五《武昌府部》（民國《湖北通志》卷一○一《金石》九錄《鄂州雜詩碑》，分五層，錄謝朓及唐人詩三十九首，其中即賈島此詩及本書後錄之盧郢詩。", "碑署「熙寧二年六月□日額立」，不著書人姓名，清代尚存於黃鶴樓後斗姥閣西壁。", "）。"]'),
('76034a1b-1950-4595-bfb1-a98a1952f883','留題南趙古廟','賈島','唐','唐诗','tang','','[]','鱗鵕老樹鐵生斑，神宇荒涼野壑閒。',46,'全唐诗/poet.tang.51000.json','["鱗鵕老樹鐵生斑，神宇荒涼野壑閒。", "地僻無人秋寂寂，一川紅影夕陽間。", "（同上三○五《太原府部》）。"]'),
('60c9833b-733b-4cda-a981-67a556a190c6','虎丘千人坐（又名千人石）','賈島','唐','唐诗','tang','','[]','上陟千人從，低窺百尺松。',41,'全唐诗/poet.tang.51000.json','["上陟千人從，低窺百尺松。", "碧池藏寶劍，寒澗宿潛龍。", "（康熙顧湄《虎邱志》二《泉石》）。"]'),
('743489e7-44a6-4688-8aef-a89d92d36b95','題安業縣','賈島','唐','唐诗','tang','','[]','一山未了一山迎，百里都無半里平。',51,'全唐诗/poet.tang.51000.json','["一山未了一山迎，百里都無半里平。", "宜是老禪遙指處，只堪圖畫不堪行。", "（《關中勝蹟圖志》二五《商州地理》）。"]'),
('531622e6-d628-4286-bf64-a87952c34f3f','貢茶唱和（句）','賈餗','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','（金沙池泉，在常州宜興縣罨畫溪之東，有寺，寺有碑，載當時杭、湖、常三州貢茶唱和，樂天云：「十隻畫船何處宿？',208,'全唐诗/poet.tang.51000.json','["（金沙池泉，在常州宜興縣罨畫溪之東，有寺，寺有碑，載當時杭、湖、常三州貢茶唱和，樂天云：「十隻畫船何處宿？", "洞庭山脚太湖心。", "」常州太守，忘其姓名，和云。", "○今按：白居易二句見《全唐詩》四四七卷《宿湖中》一詩。", "同卷有《赴蘇州至常州答賈舍人》。", "及《自到郡齋僅旬日方專公務未及宴遊偷閒走筆題二十四韻兼寄常州賈舍人湖州崔郎中仍呈吳中諸客》各詩，知常州太守即賈餗。", "）殷勤爲報春風道，不貢新茶只貢心。", "（《詩話總龜》三四《紀夢門》）。"]'),
('e938cb80-61ae-4b92-bc06-c3fea0fd6776','李娃行（句）','元稹','唐','唐诗','tang','','[]','平常不是堆珠玉，難得門前暫徘徊。',66,'全唐诗/poet.tang.51000.json','["平常不是堆珠玉，難得門前暫徘徊。", "（任淵《後山詩註》二《徐氏閑軒》注引）玉顏婷婷階（原誤作「街」）下立。", "（同上《黃梅五首》之三注引）。"]'),
('662e7685-5c70-4190-841c-810f66d99ea4','送沈倉曹赴江西','白居易','唐','唐诗','tang','','[]','落日驅單騎，涼風換袷衣。',66,'全唐诗/poet.tang.51000.json','["落日驅單騎，涼風換袷衣。", "遠魚傳信至，秋雁趁行飛。", "洛下閑居住，城東醉伴稀。", "莫辭船舫重，多覓酒錢歸。", "（《白氏長慶集》五九《三教論衡》）。"]'),
('30b4055e-b978-472c-8623-0b4248091b60','東山寺（在黃梅縣）','白居易','唐','唐诗','tang','','[]','直上青霄望八都，白雲影裏月輪孤。',95,'全唐诗/poet.tang.51000.json','["直上青霄望八都，白雲影裏月輪孤。", "茫茫宇宙人無數，幾箇男兒是丈夫。", "（《弘治黃州府志》七《藝文》）（曹汛謂《全唐詩》卷八五八呂巖《絶句》三十二首之十四，後二句與此全同，前句稍異，作白詩疑誤。", "）。"]'),
('4c9aa7f4-583a-4c17-a2b9-aa63e1625faf','句（《全唐詩》七八四作織錦人「如今」句。「士」《白香山詩集·補遺》作「事」○汪立名輯《白香山詩集·補遺》）','白居易','唐','唐诗','tang','','[]','空（〖1〗《盧氏雜話》云：盧氏子合下第，步出都門，投逆旅。',123,'全唐诗/poet.tang.51000.json','["空（〖1〗《盧氏雜話》云：盧氏子合下第，步出都門，投逆旅。", "有一人續至。", "吟詩云云。", "盧愕然，憶是白居易詩，問之，曰：）（「某世織綾錦，以薄藝投本行，皆云如今花樣與前不同，且東歸去。", "」〖2〗此段出《太平廣記》卷二五七引《盧氏雜說》，汪氏所引爲節文。", "）。"]'),
('c3cd31ec-1767-4086-b419-55b64aee3f49','漢文帝母薄太后廟賦詩','牛僧孺','唐','唐诗','tang','','[]','香風引上大羅天，月地花宮拜洞仙。',95,'全唐诗/poet.tang.51000.json','["香風引上大羅天，月地花宮拜洞仙。", "具道人間惆悵事，不知今夕是何年。", "（《唐詩紀事》二九引《周秦行紀》（《周秦行紀》，一般認爲是李黨託牛僧孺之作，《賈氏談錄》謂韋瓘作。", "詩繫牛僧孺名下，恐未允。", "）。"]'),
('35fbe497-6800-4add-a563-f84d7c28003e','答張郎中分寄翰林貢餘筆歌','張碧','唐','唐诗','tang','','[]','圓金五寸輕錯刀，天人摘落霜兔毛。',194,'全唐诗/poet.tang.51000.json','["圓金五寸輕錯刀，天人摘落霜兔毛。", "我之宗兄掌文檄，翰林分與神仙毫。", "東風吹柳作金線，狂湧辭波力生健。", "此時捧得江文通，五色光從掌中見。", "江龍角嫩無精彩，盡日揮空射煙靄。", "誰能邀得懷素來，晴明書破琉璃海。", "揚雄得之《甘泉賦》，胸中白鳯無因飛。", "他年擬把補造化，穿江入海剜天涯。", "昨宵夢見歐率更，先來醉我黃金觥。", "手擎瑟瑟三十斗，博歸天上書《黃庭》。", "夢中擺手不相許，悵望空乘碧雲去。", "（《文房四譜》二《筆譜》）。"]'),
('a0598b28-f586-487c-948b-5805d6b540df','遊安禪寺','徐凝','唐','唐诗','tang','','[]','欲到安禪遊聖概，先觀湧塔出香城。',73,'全唐诗/poet.tang.51000.json','["欲到安禪遊聖概，先觀湧塔出香城。", "樓臺有日連雲漢，壑谷無年斷水聲。", "倚竹並肩青玉立，上橋如踏白虹行。", "傷嗟置寺碑交碎，不見梁朝施主名。", "（《嚴陵集》一）。"]'),
('fd904a40-322e-42a7-ba67-679caf9a79a7','蘇小小墓','徐凝','唐','唐诗','tang','','[]','古木寒鴉噪夕陽，六朝遺恨草茫茫。',134,'全唐诗/poet.tang.51000.json','["古木寒鴉噪夕陽，六朝遺恨草茫茫。", "水如香篆船如葉，咫尺西陵不見郎。", "（《輿地紀勝三《嘉興府·古迹》（熊飛云《宋詩紀事》卷二十二據《嘉興府志補》收此詩爲沈括作。", "今按徐凝有《嘉興寒食》詩詠及蘇小小墓，此詩疑因脫冒而誤歸其名下。", "沈括《長興集》存本詩皆缺失，尚難定讞，姑仍存。", "）。"]'),
('fa4611fe-5bcc-441f-9574-916afb401c71','砥柱','柳公權','唐','唐诗','tang','','[]','禹鑿鋒鈚後，巍峨直至今。',164,'全唐诗/poet.tang.51000.json','["禹鑿鋒鈚後，巍峨直至今。", "孤峰浮水面，一柱釘波心。", "頂壓三門險，根隨九曲深。", "拄天形突兀，逐浪勢浮沉。", "岸嚮秋濤射，祠斑夜漲侵。", "噴香龍上下，刷羽鳥登臨。", "祇有尖迎日，曾無柱影陰。", "舊碑文字在，遺事可追尋。", "（《古今圖書集成·山川典》三九《底柱山部》（《記纂淵海》卷二十四收此詩「頂壓三門險」以下四句，題作《題砥柱山》。", "「拄天」作「撑天」。", "）。"]'),
('d0869e2f-7c16-4cb9-a941-9d7af7b7c58c','謝廬山僧寄谷簾水','張又新','唐','唐诗','tang','','["\u5e90\u5c71"]','消渴陵客，甘涼廬阜泉。',131,'全唐诗/poet.tang.51000.json','["消渴陵客，甘涼廬阜泉。", "瀉從千仞石，寄逐陰江船。", "竹櫃新茶出，銅鐺活火煎。", "育花浮晚菊，沸沫響秋蟬。", "啜憶吳僧共，傾宜越椀圓。", "氣清寧怕睡，骨健欲成仙。", "吏役尋無暇，詩情得有緣。", "深疑嘗沆瀣，猶欠聽潺湲。", "迢遞康王谷，塵埃陸羽篇。", "何當結茅屋，長在水簾前。", "（《正德南康府志》十）。"]'),
('7531332b-05e4-4083-af1c-1fc91959003b','題常雲峯（常雲峯，去樂清縣東八十里，在雁蕩山西谷。以其「常」有雲霧，登者心志則爲澄霽。又名靈府山。）','張又新','唐','唐诗','tang','','[]','仙府雲壇莫謾登，綵雲香霧晝常烝。',65,'全唐诗/poet.tang.51000.json','["仙府雲壇莫謾登，綵雲香霧晝常烝。", "君能到此消塵慮，隱豹垂天亦爲澄。", "（《永樂溫州府樂清縣志》二《山川》。", "又《廣雁蕩山誌》三《山水》）。"]'),
('c1308f73-427f-4c78-ad2f-d33797288d15','太玉洞（句）','張又新','唐','唐诗','tang','','[]','一國洞天三十六，東嘉幸得一仙居。',42,'全唐诗/poet.tang.51000.json','["一國洞天三十六，東嘉幸得一仙居。", "（《永樂大典》一三○七五「洞」字韻引《元一統志》）。"]'),
('c7b6096b-4190-4e10-937d-c461534b1b41','龍虎山','吳武陵','唐','唐诗','tang','','[]','龍虎山中紫翠烟，青精顏色四時妍。',88,'全唐诗/poet.tang.51000.json','["龍虎山中紫翠烟，青精顏色四時妍。", "桃枝慣見花成實，瀛島宜聞海變田。", "五斗米仙真有道，一神樓藥豈無緣。", "秋風吹綠茂陵草，的的黃金飛上天。", "（《古今圖書集成·山川典》一四七《龍虎山部》）。"]'),
('05f7198d-5a70-4527-85af-8fbfa2acf615','傳奇小說（詩句）','沈亞之','唐','唐诗','tang','','[]','命笑無人笑，含嬌何處嬌。',140,'全唐诗/poet.tang.51000.json','["命笑無人笑，含嬌何處嬌。", "徘徊花上月，空（一作「虛」）度可憐宵。", "（《藝林伐山》十七。", "又《詩人玉屑》十二《品藻》引後二句（《太平廣記》卷三二六《沈警》條引《異聞錄》載此爲沈警詩。", "《詩人玉屑》以爲沈亞之作，未詳所據。", "程毅中《〈異聞集〉考》因疑《沈警》篇爲沈亞之作。", "惜尚乏他證佐定之。", "）。"]'),
('d1749816-3621-4579-b0ed-a1a665866a5d','長揖詩（貞元中，劉忠州任大夫科選，多濫進。有無名子自云山東野客，移書於劉，附長揖詩曰：）','山東野客','唐','唐诗','tang','','[]','三銓選客不須嗔，五箇登科各有因。',81,'全唐诗/poet.tang.51000.json','["三銓選客不須嗔，五箇登科各有因。", "無識伯和憐吉獠，弄權虞候爲王申。", "載華甲第歸丞相，裴子門徒入舍人。", "莫怪邵南書判好，他家自有景監親。", "（《唐摭言》十三《無名子謗議》）。"]'),
('1bebe1d2-248c-4f65-9e96-07414057b14e','桂花曲','李德谷','唐','唐诗','tang','','[]','仙女侍，董雙成，桂殿夜涼（一作「寒」）吹玉笙。',204,'全唐诗/poet.tang.51000.json','["仙女侍，董雙成，桂殿夜涼（一作「寒」）吹玉笙。", "曲終却從仙宮去，萬戶千門空月明。", "河漢女，玉練顏，雲軿往往到人間。", "九霄有路去無際（一作「迹」），裊裊大風吹珮環。", "《苕溪漁隱業話後集》十二：「戰鬥曲《許彦周詩話》謂是李衛公作，《桐江詩話》謂是均州武當山石壁上刻之，云神仙所作，未知孰是。", "」（《全唐詩補逸》卷五以前五句作李栖筠詩，未妥，今刪彼存此。", "詳參書末之修訂說明。", "《全唐詩》卷八九○收作李白《桂殿秋》詞，恐誤。", "）。"]'),
('d6f4b1aa-b63a-43a9-b488-7d01caf50c8b','寄家書','李德谷','唐','唐诗','tang','','[]','琼與中原隔，自然音信疎。',102,'全唐诗/poet.tang.51000.json','["琼與中原隔，自然音信疎。", "天涯無去雁，船上有回書。", "一別五年外，相思萬里餘。", "開緘更多感，老泪濕霜鬚。", "（《光緒崖州志》二一《藝文》（周建國云：李德裕大中元年貶崖州，三年冬卒。", "「別五年外」之「五「當作「三」。", "）。"]'),
('0ee21f98-eb0d-4032-988f-c2ca51f6ef3e','謫崖州過北流鬼門關作（《輿地紀勝》一○四《容州·景物》。又《永樂大典》二三三八及二三四○「梧」字韻兩見）','李德谷','唐','唐诗','tang','','[]','空（《全唐詩》一二一作楊炎詩，《唐詩紀事》三二同。',96,'全唐诗/poet.tang.51000.json','["空（《全唐詩》一二一作楊炎詩，《唐詩紀事》三二同。", "第三句「何處在」《輿地紀勝》作「在何處」。", "〖周建國云此當爲李德裕作，宋初樂史《太平寰宇記·嶺南道·容州》已收爲李作，比《唐詩紀事》可靠。", "〗）。"]'),
('afe6b909-4e6c-4192-ad09-91788204e067','詠吐綬雞（句）','李德谷','唐','唐诗','tang','','[]','葳蕤散綬輕風裏，若銜（御）若垂何可擬。',241,'全唐诗/poet.tang.51000.json','["葳蕤散綬輕風裏，若銜（御）若垂何可擬。", "（《詩話總龜後集》二七《詠物門》引《蔡寬夫詩話》。", "○今按：《全唐詩》四七五引《事文類聚》，上句缺「散綬」二字，又無序，故重錄之。", "）（〖1〗《蔡寬夫詩話》今佚，《總龜》所引，系據《苕溪漁隱業話前集》卷二十轉錄。", "二書所引，皆未以此段文字爲序。", "按其文意，僅「出剡溪」三字爲李德裕所云，餘皆蔡寬夫之語。", "此處誤讀。", "《說郛》卷二十二引《山家清供》錄二句，後句作「若衍若垂何可據」。", "周建國告《劉賓客文集》卷三七《吐綬鳥詞》序提及此首，題應作《吐綬鳥詞》。", "）。"]'),
('b81957f5-7868-4cad-9322-2eea021e8ab0','南竄途中感憤（句）','李德谷','唐','唐诗','tang','','[]','（李衛公歷三朝大權，出門下者多矣。',65,'全唐诗/poet.tang.51000.json','["（李衛公歷三朝大權，出門下者多矣。", "及南竄，怨嫌併集，途中感憤，有句云：）十五餘年車馬客，無人相送到崖州。", "（《唐語林》七《補遺》）。"]'),
('8ed12645-8064-44ec-80ba-b683169b219b','詩','廣文諸生','唐','唐诗','tang','','[]','（《唐語林》七《補遺》云：「李衛公頗升寒素。',260,'全唐诗/poet.tang.51000.json','["（《唐語林》七《補遺》云：「李衛公頗升寒素。", "舊府解有等第，衛公既貶，崔少保龜從在省，子殷夢爲府解元。", "廣今諸生爲詩云云。", "盧渥司徒以府元爲第五人，自此廢等第。", "」又《唐摭言》七云：「李太尉德裕頗爲寒畯〖《紀事》爲素〗開路，及謫官南去，或有詩曰：「八百孤寒齊下淚，一時南望李崖州。", "」〖又《雲谿友議》云：「後之文場困辱者，若周人之思鄉焉。", "皆曰：『八百孤寒齊下淚，一時回首望崖州』。", "」《唐新的紀事》及《全唐詩》無名氏詩句同，亦均只存後二句。", "）省司府局正綢繆，殷夢元知作解頭。", "三百孤寒齊下淚，一時南望李崖州。", "（《唐語林》七《補遺》）。"]'),
('408c76e2-ec43-468b-a92b-7b69068a6967','金庭洞','裴通','唐','唐诗','tang','','[]','寂寂金庭洞，清香發桂枝。',63,'全唐诗/poet.tang.51000.json','["寂寂金庭洞，清香發桂枝。", "魚吞左慈釣，鵝踏右軍池。", "（《永樂大典》一三○七四「洞」字韻（此詩未全，全篇見《全唐詩續拾》卷二六。", "）。"]'),
('89f75321-11fd-4ecc-8e8e-342cbbd4a057','白雲亭（《全唐詩》八六○作許宣平《見李白詩又吟》，出入較多，故重錄。）','羅萬象','唐','唐诗','tang','','[]','一池荷葉衣無盡，數樹松花食有餘。',227,'全唐诗/poet.tang.51000.json','["一池荷葉衣無盡，數樹松花食有餘。", "剛被世人知住處，不如依舊再移居。", "（《嚴陵集》二）（原列入無世次作者。", "按《雲笈七籤》卷一一三錄沈汾《續仙傳》云：「羅萬象，不知何所人。", "有文學，明天文，洞深於）（《易》，節操奇特。", "惟布衣遊天下，居王屋山。", "久之，遊羅浮山，遂結庵以居。", "」《輿地紀勝》卷八引晏殊《類要》云：「唐羅萬象者分水縣人也。", "隱於紫邏山。", "節度使李德裕使人召之，聞之，更移入深山，依白雲而居，終身不出。", "」今移此。", "曹汛謂《五燈會元》卷三收大梅法常偈，與此多同。", "）。"]'),
('ed150864-bd14-455a-8327-e261f7d6a8ad','泰伯井','李紳','唐','唐诗','tang','','[]','至德今何在，平墟井有泉。',36,'全唐诗/poet.tang.51000.json','["至德今何在，平墟井有泉。", "梁鴻重濬後，又歷幾千年。", "（《梅里志》三《詩》）。"]'),
('98207084-c2f1-4c75-a2fc-650c5766586f','鶯鶯歌（逸句〖1〗）','李紳','唐','唐诗','tang','','[]','（董解元《西廂記諸宮調》徵引公垂《鶯鶯歌》凡四處。',50,'全唐诗/poet.tang.51000.json','["（董解元《西廂記諸宮調》徵引公垂《鶯鶯歌》凡四處。", "卷一有「伯勞飛遲燕飛疾」八句，已見《全唐詩》。", "）。"]'),
('d5780913-088b-40b7-bf02-4ee72cd45700','鶯鶯歌（逸句〖1〗） 一','李紳','唐','唐诗','tang','','[]','河橋上將亡官軍，虎騎長「戟」（戰）交壘門。',121,'全唐诗/poet.tang.51000.json','["河橋上將亡官軍，虎騎長「戟」（戰）交壘門。", "鳳凰詔書猶未到，滿城戈甲如「雲」（雪）屯。", "家家玉帛棄泥土，少女嬌妻愁被虜。", "出門走馬皆健兒，紅粉潛藏欲何處？", "鳴鳴阿母啼向天，窗中抱女投金鈿。", "鉛華不顧欲藏艷，玉颜轉瑩如神仙（《董解元西廂記》卷二〖2〗）。"]'),
('33205615-7370-4ceb-bc7e-2217caf89d98','鶯鶯歌（逸句〖1〗） 二','李紳','唐','唐诗','tang','','[]','此時潘郎未相識，偶住蓮館對南北。',89,'全唐诗/poet.tang.51000.json','["此時潘郎未相識，偶住蓮館對南北。", "潛歎悽惶阿母心，爲求白馬將軍力。", "明明飛詔五雲下，將選金門兵悉罷。", "阿母深居雞犬安，八珍玉食邀郎餐。", "千言萬語對生意，小女初笄爲姊妹。", "（同上〖卷三〗）。"]'),
('5fc6c38a-8b2a-4e1f-84f6-b702f53223ff','鶯鶯歌（逸句〖1〗） 三','李紳','唐','唐诗','tang','','[]','丹誠寸之難自比，寫在紅箋方寸紙。',105,'全唐诗/poet.tang.51000.json','["丹誠寸之難自比，寫在紅箋方寸紙。", "寄與春風伴落花，彷彿隨風綠楊裏。", "窗中暗讀人不知，剪破紅綃裁作詩。", "還怕香風易飄蕩，自令青鳥口啣之。", "詩中報郎含隱語，郎知暗到花深處。", "三五月明當戶時，與郎相見花間路。", "（同上〖卷四〗）。"]'),
('e4a5bca5-b8e8-4338-815d-70950adac4ef','鶯鶯歌（逸句〖1〗） 四','李紳','唐','唐诗','tang','','[]','恍然夢作瑤臺客。',95,'全唐诗/poet.tang.51000.json','["恍然夢作瑤臺客。", "（《施注蘇詩》十五《見月詩》注引）（〖1〗《董解元西厢記》卷一、卷二、卷三所引，皆作《鶯鶯本傳歌》，卷四作《本傳歌》。", "〖2〗兩處校改，均據人民文學出版社出版淩景埏校注本。", "）。"]'),
('9df0489d-3b63-4015-a489-649d53d40e4f','石佛谷','皇甫曙','唐','唐诗','tang','','[]','空（〖1〗《全唐詩》三六九作皇甫湜詩，第十五句「鳥跡」《圖書集成》作「鳥趾」，十七句「間」作「闊」。',185,'全唐诗/poet.tang.51000.json','["空（〖1〗《全唐詩》三六九作皇甫湜詩，第十五句「鳥跡」《圖書集成》作「鳥趾」，十七句「間」作「闊」。", "〖2〗《古今圖書集成·職方典》三六四《澤州部》〖《金石錄》卷十著錄：「唐皇甫曙《題石佛谷詩》，李道夷正書，開成元年十一月。", "」《寶刻業編》卷二十亦著錄。", "皇甫曙於大和九年至開成二年間任澤州刺史，詳郁賢皓《唐刺史考》卷八。", "詩即曙刺澤州時作。", "《全唐詩》誤歸皇甫湜，應移正。", "〗）。"]'),
('5fe08a04-7245-419a-a36a-b007a00cf3b2','九華山謝雨詩','費冠卿','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','青嶂廟前纔滴酒，白龍湫上氣如蒸。',44,'全唐诗/poet.tang.51000.json','["青嶂廟前纔滴酒，白龍湫上氣如蒸。", "一聲霹靂驚風雨，萬頃秋田水溢堘。", "（《嘉靖池州府志》五）。"]'),
('a929552e-dccb-42aa-a4ec-d07229b8045a','過桐廬場鄭判官','施肩吾','唐','唐诗','tang','','[]','榮陽鄭君游說餘，偶因榷茗來桐廬。',176,'全唐诗/poet.tang.51000.json','["榮陽鄭君游說餘，偶因榷茗來桐廬。", "幽奇山水引高步，暐煜風光隨使車。", "算緍百萬日不虛，吏人業裏唯簿書。", "眼前橫製斷犀劍，心中暗轉靈蛇珠。", "有時退公兼退食，一尊長在朱軒側。", "胡商大鼻左右趍，趙妾細眉前後直。", "醉來引客上紅樓，面前一道桐溪流。", "登臨山色在掌內，指點霞光隨杖頭。", "東郭野人慵櫛沐，使將破履升華屋。", "數杯酩酊不得歸，樓中便蓋江雲宿。", "卻被江郎濕我衣，賴君借我貂襜歸。"]'),
('f4138ffa-537b-4677-a3e2-2b2cd66291b8','西山即事奉寄故園徐處士','施肩吾','唐','唐诗','tang','','[]','僕作江西少施氏，君爲城北老徐翁。',64,'全唐诗/poet.tang.51000.json','["僕作江西少施氏，君爲城北老徐翁。", "詩篇憶昔歡相接，颜貎如今恨不同。", "世界盡憂蔬上露，時人皆怕燭前風。", "唯余獨慕神仙道，芥子雖窮壽不窮。"]'),
('b849a1ed-cbc3-4e1e-ad11-a77f70421200','夏日過從叔幽居','施肩吾','唐','唐诗','tang','','[]','且將一葉繫垂陽，角對清溪夏日長。',64,'全唐诗/poet.tang.51000.json','["且將一葉繫垂陽，角對清溪夏日長。", "林下喜逢青竹卷，局邊輸卻紫羅囊。", "碧蹄駿馬銜芻細，紅粉佳人挈榼香。", "伯仲歷官年盡少，那知不笑漢馮唐。"]'),
('a69904a0-a985-4af2-9a3d-edf344c1be08','贈族叔處士','施肩吾','唐','唐诗','tang','','[]','我家名士已無求，若見翔鴻便舉頭。',65,'全唐诗/poet.tang.51000.json','["我家名士已無求，若見翔鴻便舉頭。", "紫有巖邊吟繡段，青苔紙上落銀鉤。", "高人酒席稱無醉，細字經書讀未休。", "定是仙山足靈藥，年過八十轉風流。", "。"]'),
('c48f9021-fa6b-454d-ad6d-776bab94d3e6','桐廬廳覩論事叟','施肩吾','唐','唐诗','tang','','[]','擾擾廳前走羸瘵，中有老人扶杖拜。',32,'全唐诗/poet.tang.51000.json','["擾擾廳前走羸瘵，中有老人扶杖拜。", "天公霹靂耳不聞，猶爲子孫争地界。"]'),
('bdf8a06d-523b-4973-8111-cc6ca25da293','秋日桐江送裴秀才歸淮南（〖1〗《全唐詩》四九四題爲《送裴秀才歸淮南》，第二句「楓葉」《嚴陵集》作「桐樹」，「夕」作「葉」。）','施肩吾','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('4537d402-311c-434d-ae2b-86bb379214c2','題釣臺蘭若','施肩吾','唐','唐诗','tang','','[]','山僧不釣臺下魚，幾年空寄臺邊坐。',32,'全唐诗/poet.tang.51000.json','["山僧不釣臺下魚，幾年空寄臺邊坐。", "有時手把乾松枝，沿江乞得沙上火。"]'),
('d2886292-97c1-4ad5-8dc5-12acc58d2ee7','歸分水留贈王少府','施肩吾','唐','唐诗','tang','','[]','仙吏飲冰多玉聲，新詩麗句遺狂生。',43,'全唐诗/poet.tang.51000.json','["仙吏飲冰多玉聲，新詩麗句遺狂生。", "不愁日暮歸山去，故把隋珠入夜行。", "（以上《嚴陵集》一）。"]'),
('383c49d5-14ed-4ee8-aa47-223e13de5eaa','寺居清晨（〖1〗《全唐詩》三○五作劉復詩，第四句「虛光」《文苑英華》作「靈光」。○《文苑英華》二三六《寺院》。）','劉三復','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('4b73a0c7-8b5c-4471-a04b-5bb64dc3d187','憂旱吟','張祜','唐','唐诗','tang','','[]','炎熇肆蒸溽，南薫日飄颺。',177,'全唐诗/poet.tang.51000.json','["炎熇肆蒸溽，南薫日飄颺。", "田疇苦焦烈，龜坼無潤壤。", "嘉禾穟爲實，灌注期穰穰。", "午火雲熾，虐焰彌穹蒼。", "桔槹置無用，何計盈倉箱。", "老農力耕耨，捫心熱衷腸。", "公租與私稅，焉得俱無傷？", "今年已憔悴，斗米百錢償。", "富豪索高價，閉廩幾絕糧。", "引領望甘雨，傾城禱林桑。", "匹夫動天地，奚俟暴巫尫。", "浹旬竟弗驗，神明果茫茫。", "彼蒼豈降割，以重吾民殃。", "（《古今圖書集成·庶徵典》五九《旱災部》）。"]'),
('48cdfb0e-e92b-4da7-801b-d84fab5e3ddc','平望驛寄吳興徐使君玄之〖1〗','張祜','唐','唐诗','tang','','[]','故人爲作郡，百里到吳興。',178,'全唐诗/poet.tang.51000.json','["故人爲作郡，百里到吳興。", "藻思江湖滿，公平道路稱。", "包山方峻直，霅水況澄清。", "佇聽司空第，遙知下詔徵。", "（《百城烟水》四《吴江》）（〖1〗《嘉泰吳興志》卷十四《郡守題名》云：「徐玄之，開元七年自諫議大夫授，改邠王府長史。", "《統紀》云：開元十五年。", "」郁賢皓《唐刺史考》從《統紀》之說。", "張祜約生於貞元間，卒於大中中，於徐玄之不同時，詩顯非其作。", "確作者不詳，姑仍存此。", "）。"]'),
('16df6328-f394-4442-b62a-94fb0698f8a6','伊山','張祜','唐','唐诗','tang','','[]','晉代衣冠夢一場，精藍往是讀書堂。',57,'全唐诗/poet.tang.51000.json','["晉代衣冠夢一場，精藍往是讀書堂。", "桓伊曾弄柯亭笛，吹落梅花萬點香。", "（《古今圖書集成·職方典》一二五三《衡州府部》）。"]'),
('63a53316-12e4-4263-bb44-4662b45e0295','即席爲詩獻徐州節度王智興（時於使院會飲賦詩）','張祜','唐','唐诗','tang','','[]','古來英傑動寰區，武德文經未有餘。',162,'全唐诗/poet.tang.51000.json','["古來英傑動寰區，武德文經未有餘。", "王氏柱天動業外，李陵章句右軍書。", "（《唐詩紀事》五十四王智興名下引此詩，前三句作「十年受命鎮方隅，孝節忠規兩有餘。", "誰信將壇嘉政外（第四句同）。", "」又《全唐詩》三百十四王智興《徐州使院賦》，第一句「三十年前老健兒」，《劇談錄》作「平生弓劍自相隨」，第四句「獨」作「自」。", "附注於此。", "○《劇談錄》上。", "。"]'),
('51a0e084-a815-4004-a44b-893872df8388','文學泉（〖1〗《全唐詩》一二九裴迪《西塔寺陸羽茶泉》，共八句，最後二句爲此詩所無。題下注《統籤》云：「此詩楊慎以爲見之石刻，然羽自在大曆後，則非迪詩矣。」〖楊慎語見《升庵詩話》卷十二。按裴迪爲玄、肅間人，代宗時似已不存，陸羽約生於開元末，卒於貞元末，與裴迪時代相接。然詩中云：「景陵西塔寺，……曾經陸羽居。草堂荒產蛤，茶井冷生魚。」似應爲陸羽身後作。裴夷直長慶、大和間在世，與詩意正合。《統籤》疑僞是，當從《輿紀勝》歸夷直。〗〖2〗《輿地紀勝》七六《復州》）','裴夷直','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('aa03e403-6e20-45b9-b909-7d93befd6197','和李衛公漳浦驛留題','楊發','唐','唐诗','tang','','[]','南盡封郵見好山，蒼蒼桂嶺類商颜，誰憐後夜思鄉處，白草黃茅舊漢關。',67,'全唐诗/poet.tang.51000.json','["南盡封郵見好山，蒼蒼桂嶺類商颜，誰憐後夜思鄉處，白草黃茅舊漢關。", "（《輿地紀勝》一三一《漳州》。", "又《康熙漳浦縣志》十九《雜志·古蹟》）。"]'),
('961eb5cb-078c-4647-81ff-0c14f9358f24','','李郃','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('d63c5246-f463-4a25-9a86-51218bf79f25','賀州思九疑作','李郃','唐','唐诗','tang','','[]','我世家九疑，山在宅之陽。',289,'全唐诗/poet.tang.51000.json','["我世家九疑，山在宅之陽。", "林業倚虛壁，峭拔絕坤方。", "卓植斗杓南，序列儼成行。", "煙嵐緲相接，午影常中堂。", "去留如有期，勝覽誇新妝。", "少懷不羈思，那能繫空桑？", "對此疑山高，目懸幾成尩。", "飄風微我蕩，此興頎然長。", "幸隨長者車，身便神亦爽。", "詎仍手中扶，扶搖上翱翔。", "雲開躋巒頂，萬丈誠孤亢。", "俯瞷總羣植，纖纖若毫芒。", "上與舉汗漫期，倒景徹罔浪。", "璇璣盤胸次，燦爛皆文章。", "清風時掀髯，世慮渾相忘。", "伸手叩元關，閶闔鳴金琅。", "九垓若可極，縱身托穹蒼。", "四眺憑空忽，興盡思弓藏。", "翩然下其肩，稽首來帝旁。", "有嚴淑多士，登戶皆賢良。", "探懷攄忠藎，吾亦傾吾囊。", "鋒鋩避英銳，鉛槧費揮張。", "臚傳動天閽，颜厚何可當。", "騰章控多遜，遺珠映奎光。"]'),
('1517038e-c9bb-465d-a36f-c0f400fa3a6a','過九疑山有懷','李郃','唐','唐诗','tang','','["\u601d\u4e61", "\u60c6\u6005", "\u8fb9\u585e"]','晚度疑山道，依然想重華。',72,'全唐诗/poet.tang.51000.json','["晚度疑山道，依然想重華。", "雲飄上苑葉，雪映御溝花。", "行歎戍麾遠，坐令衣帶賒。", "交何通絕徼，弱水浸流沙。", "旅思徒漂梗，歸期未及瓜。", "兩階干羽絕，夜夜泣胡笳。"]'),
('8a7c859b-969c-4c92-bdee-a0c9b3823172','詠舜廟古杉','李郃','唐','唐诗','tang','','[]','總負億年質，高臨千仞峯。',72,'全唐诗/poet.tang.51000.json','["總負億年質，高臨千仞峯。", "貞心欺晚桂，勁節掩寒松。", "任彼風飙折，挺然霜雪衝。", "莖凌霄漢表，根蟠龍窟中。", "仙客頻棲舞，良工何渺逢。", "枝頭連理翠，擁護聖神宮。"]'),
('1a9d8e27-f651-435a-a257-e06dc0221206','遊九疑黃庭觀（《全唐詩》七八作駱賓王《遊靈公觀》，詩中字句多有異同）','李郃','唐','唐诗','tang','','[]','靈峯標舜境，神府枕疑川。',143,'全唐诗/poet.tang.51000.json','["靈峯標舜境，神府枕疑川。", "玉殿斜臨漢，金堂逈架烟。", "斷風疎晚竹，流水切寒絃。", "別有月帔上，寄懷騎鶴仙。", "（《文苑英華》卷二二六、江標影宋本《駱賓王集》卷中、《唐人三家集》本《駱賓王文集》〖據影宋蜀刻本翻雕〗卷四均收此詩爲駱作，作李詩恐非是。", "）（以上《古今圖書集成·山川典》一七○《九疑山部》）。"]'),
('44017ef7-213b-461f-8e15-2c6dfb2699e4','還故居','江全銘','唐','唐诗','tang','','[]','路入豐溪上，超然絕世氛。',71,'全唐诗/poet.tang.51000.json','["路入豐溪上，超然絕世氛。", "懶尋書作伴，長與鶴爲羣。", "千慮凈如水，一身閒似雲。", "梅花領幽賞，疎雪隔簾分。", "（嘉慶《旌德縣志》七《選舉》及十九《藝文》）。"]'),
('3523a3bc-0f83-432c-9eac-e63e72b7f3b8','九華山','杜牧','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','昔年幽賞快疎慵，每喜佳山在邑封。',209,'全唐诗/poet.tang.51000.json','["昔年幽賞快疎慵，每喜佳山在邑封。", "江上重來六七載，雲間略見兩三峯。", "凌空瘦骨寒如削，照水清光翠且重。", "却憶謫仙才格俊，解吟秀出九芙蓉。", "（《輿地紀勝》二二《池州》（吳在慶謂此詩又見於嘉靖《池州府志》卷八，僅錄後四句。", "又云杜牧僅在會昌四年九月至六年九月在池州任刺史，此外別無到池州之迹，亦無游九華山之作。", "相據此詩前四句，顯爲詩人重游九華山之作，所謂「昔年」乃距重游時六七年，而這一情況，顯然與杜牧生平不合。", "因疑此詩非杜牧作。", "）。"]'),
('bafcc947-f881-41f3-ba0d-751109add461','句','杜牧','唐','唐诗','tang','','[]','江聲秋入寺（一作「峽」），雨氣（一作「色」）夜侵樓。',26,'全唐诗/poet.tang.51000.json','["江聲秋入寺（一作「峽」），雨氣（一作「色」）夜侵樓。"]'),
('af82cb3c-898a-45c3-a81e-59fc82ad46b9','句','杜牧','唐','唐诗','tang','','[]','閉門客到常疑（一作「如」）病，滿院花開不似（一作「未是」）貧。',91,'全唐诗/poet.tang.51000.json','["閉門客到常疑（一作「如」）病，滿院花開不似（一作「未是」）貧。", "（以上《雲谿友議》上《馮生佞》。", "又《唐詩紀事》五六、《詩話總龜》三《知遇門》、《詩人玉屑》十《知音》、《唐才子傳》七）。"]'),
('8ca3b0f7-351b-476c-8296-2db63a84186a','題陰陽井','許渾','唐','唐诗','tang','','[]','仙人修煉地，玉井著神功。',65,'全唐诗/poet.tang.51000.json','["仙人修煉地，玉井著神功。", "日月雙輪見，陰陽兩竅通。", "可堪清徹底，那更施無窮。", "尚冀丹砂力，當澆俗慮空。", "（《弘治句容縣志》八《題詠類》）。"]'),
('a3ad055c-b008-46b5-8643-5792b5b05c27','白雲潭禪院（在寧國白雲山）','許渾','唐','唐诗','tang','','[]','一片白雲千丈峯，殿略樓閣架虛空。',50,'全唐诗/poet.tang.51000.json','["一片白雲千丈峯，殿略樓閣架虛空。", "山僧不語捲簾坐，遙看世間如夢中。", "（嘉靖《寧國府志》卷四、卷五兩見）。"]'),
('4ff68291-86c7-4f89-80bc-7c0083bf5382','晉元帝廟','李商隱','唐','唐诗','tang','','[]','青山遺廟與僧鄰，斷鏃殘碑鎖暗塵。',124,'全唐诗/poet.tang.51000.json','["青山遺廟與僧鄰，斷鏃殘碑鎖暗塵。", "紫蓋適符江左運，翠華空憶洛中春。", "夜臺無月照珠戶，秋殿有風開玉宸。", "弓劍神靈定何處？年年春綠上麒麟。", "（《浩然齋雅談》（見《四庫全書》本《浩然齋雅談》卷中，四庫館臣注：「案此詩李商隱集不載，未詳所據何本，疑姓名有誤。", "」）。"]'),
('652818ca-a487-480d-849a-c124e57d2969','缺題','李商隱','唐','唐诗','tang','','[]','重午雲陰日正長，佳辰早至浴蘭湯。',43,'全唐诗/poet.tang.51000.json','["重午雲陰日正長，佳辰早至浴蘭湯。", "涼風入座無消扇，彩索靈符映羽觴。", "（《錦繡花谷別集》）。"]'),
('5c12a997-dc34-4b67-bc69-49ec7e23637a','詠雪（句）','李商隱','唐','唐诗','tang','','[]','郊野鵝毛滿，江湖雁影空。',21,'全唐诗/poet.tang.51000.json','["郊野鵝毛滿，江湖雁影空。", "（《合璧事類》）。"]'),
('c47b2d09-015a-48cd-8098-85d81cd32c55','詠桃（句）','李商隱','唐','唐诗','tang','','[]','酥胸酣暖日，玉臉笑春風。',22,'全唐诗/poet.tang.51000.json','["酥胸酣暖日，玉臉笑春風。", "（《錦繡萬花谷》）。"]'),
('aace3aa4-f8df-4982-b914-cb1fc3cb1379','桐柏觀','鄭薰','唐','唐诗','tang','','[]','深山桐柏觀，殘雪路猶分。',107,'全唐诗/poet.tang.51000.json','["深山桐柏觀，殘雪路猶分。", "數里踏紅葉，全家穿但是雲。", "月寒巖障曉，風遠蕙蘭芬。", "明日出雲去，吹笙不可聞。", "（《古今圖書集成·山川典》一二六《桐柏山部》（見《嘉定赤城志》卷三十。", "《天台前集》卷中題作《冬暮挈家宿桐拍觀》。", "）。"]'),
('017c2cea-1cfe-4e10-ac25-53bec19ffe82','松江','趙嘏','唐','唐诗','tang','','[]','松江菰葉正芳繁，張翰逢秋憶故園。',78,'全唐诗/poet.tang.51000.json','["松江菰葉正芳繁，張翰逢秋憶故園。", "千里帆遮館娃寺，一川風暖采香村。", "潮聲漸遇仙人宅，鶴市曾迷子夜魂。", "我有五湖烟艇在，不堪殘日動征鞍。", "（《百城烟水》四《吳江》）。"]'),
('7b45f713-78f5-4a52-93b1-5a6ce9a524d9','題開元寺水閣（在宣州）','趙嘏','唐','唐诗','tang','','[]','年來獨向此遊頻，謝氏青山與寺鄰。',64,'全唐诗/poet.tang.51000.json','["年來獨向此遊頻，謝氏青山與寺鄰。", "朱檻夜飛溪路雪，碧林晴隔馬蹄塵。", "波穿十里橋連寺，絮壓千家柳送春。", "（《輿地紀勝》一九《寧國府》）。"]'),
('2780bf81-6fb3-4926-9948-78aae7bb036a','廣陵','趙嘏','唐','唐诗','tang','','[]','廣陵城中饒花光，賺得英雄盡白頭。',126,'全唐诗/poet.tang.51000.json','["廣陵城中饒花光，賺得英雄盡白頭。", "（《國史補》曰：「進士科得之艱難，其有老死於文場者，亦無所恨。", "故詩云云。", "」《畫墁錄》以爲趙嘏作。", "（李肇《國史補》無此則。", "《唐摭言》卷一錄此二句，不云作者，《全唐詩》卷七九六收作無名氏句。", "《畫墁錄》謂趙嘏作，未言所據。", "）。"]'),
('0e11d072-0217-4f2d-9711-f76e567d3d32','謁天柱山真君祠','韋曾','唐','唐诗','tang','','[]','天柱吐白雲，仙宮隔青靄。',310,'全唐诗/poet.tang.51000.json','["天柱吐白雲，仙宮隔青靄。", "新亭皇黃家，舊封傳漢代。", "猶持蘋藻奠，永荷閻閭泰。", "彷彿見羣仙，凌風振青珮，仰攀丹鳳翼，俯躍蒼龍背。", "暫息三峯前，還逐九霄外。", "灊嶽高似掌，皖水遙疑帶。", "半壁風雨來，空林鬼神會。", "今我何爲者，赤紱仍皂蓋。", "遠愧黃與龔，流芳及千載。", "（《古今圖書集成·山川典》八六《灊山部》）（〖1〗韋曾，原列入「無世次」作者。", "今考《元和姓纂》卷二韋氏西眷房有韋曾，爲萬年令光朝之子，任舒州刺史、職方）（員外郎。", "《寶刻業編》卷十八載韋曾貞元二十年撰《巴郡太守嚴颜廟碑》。", "《郎官石柱題名》司動員外郎有韋曾，勞格《郎官考》卷八錄山東益都元和十四年石刻《寶鞏等題名》有「裏行韋曾」字樣。", "天柱山在舒州懷寧，此詩當即韋曾任舒州刺史時作。", "）。"]'),
('612c4670-eb52-4bb9-811f-d5feef9203d6','丫髻岩','韋膺','唐','唐诗','tang','','[]','丫髻山頭殘月，臘岩洞口斜陽。',291,'全唐诗/poet.tang.51000.json','["丫髻山頭殘月，臘岩洞口斜陽。", "啼鳥喚人歸去，此身猶在他鄉。", "（同上《職方典》一○二六《溫州府部》）（〖1〗韋膺，原列入「無世次」作者。", "今考《新唐書》卷七四《宰相世系表》韋氏逍遙公房有韋膺，爲衢州刺史光輔之子。", "《元和姓纂》卷二載光輔爲京兆杜陵人，任大理少卿。", "《唐會要》卷六六載光輔大曆十年任太府少卿，《寶刻業編》卷十三載其貞元三年任衢州刺史。", "可知韋膺應爲貞元以後人。", "嘉靖《瑞安縣志》卷九有刺史韋庸，喜慶《浙江通志》卷一一二載韋鏞，宣宗時任溫州刺史，同書卷一五六引《明一統志》云會昌中溫州刺史韋庸興水利而爲民所頌，何誤。", "其任溫州刺史的時間，當從《唐刺史考》作會昌中爲是。", "〖參張忱石考證〗）。"]'),
('874f7878-7fc1-4542-a394-d66f758c594e','行桐柏山','姚鵠','唐','唐诗','tang','','[]','際海禮冰碧，穿雲來玉清。',72,'全唐诗/poet.tang.51000.json','["際海禮冰碧，穿雲來玉清。", "千山盤鳥道，十里入猿聲。", "草木飄香異，雲霞引步輕。", "誰言鼇頂上，此處是蓬瀛。", "（《古今圖書集成·山川典》一二六《桐拍山部》）。"]'),
('053a7435-5b88-4c45-ab8d-d9f822dca24c','過灊嶽','馬戴','唐','唐诗','tang','','[]','塞上徵兵久，淮南賦歛多。',69,'全唐诗/poet.tang.51000.json','["塞上徵兵久，淮南賦歛多。", "抱琴方此去，爲縣欲如何。", "灊嶽積蒼翠，皖溪生素波。", "真君松廟近，公退爲誰過？", "（《古今圖書集成·山川典》八六《灊山部）。"]'),
('a8dc72a8-038e-41be-b4d0-c52f6f3cb32c','方城懷古（句）','馬戴','唐','唐诗','tang','','[]','申胥枉向秦庭哭，靳尚終貽楚國羞。',97,'全唐诗/poet.tang.51000.json','["申胥枉向秦庭哭，靳尚終貽楚國羞。", "（《唐語林》二《文學》〖1〗○今按：《全唐詩》五五六缺題，又無出處。", "）（〖1〗此則出《金華子雜編》，見原本《說郛》卷十一，《四庫全書》輯本《金華子雜編》失收。", "）。"]'),
('ff9193a4-42fc-4846-88a1-5478386b95b1','題銅官山廟（靈祐王祠在銅官山）','裴休','唐','唐诗','tang','','[]','潯陽賢太守，遺廟古溪邊。',71,'全唐诗/poet.tang.51000.json','["潯陽賢太守，遺廟古溪邊。", "樹影入流水，石門當洞天。", "幡花凝寶座，香案儼爐煙。", "若到千年後，重修事宛然。", "（《嘉靖銅陵縣志》八、又《嘉靖池州府志》五）。"]'),
('25cf8191-9e7c-4de0-b104-a7ea01d1accd','白鹿寺釋迦瑞相詩','裴休','唐','唐诗','tang','','[]','無相無虧有相圓，多生檀越種因緣。',90,'全唐诗/poet.tang.51000.json','["無相無虧有相圓，多生檀越種因緣。", "三千境見閻浮土，丈六身留兜率天。", "紺目輝騰滄海月，玉毫光射寶爐煙。", "道人參到非非處，不是丹霞破佛禪。", "（《同治湖南通志》二三八《方外志·寺觀·益陽縣》）。"]'),
('e9a47d24-68fa-4a56-83bb-e0f5825f979a','東林寺','張毅夫','唐','唐诗','tang','','[]','駐斾息東林，清泉洗病心。',226,'全唐诗/poet.tang.51000.json','["駐斾息東林，清泉洗病心。", "爐峯霄漢近，煙樹荔蘿陰。", "溪浚龍蛇隱，喦高雨露侵。", "猿聲雲壑斷，罄韻竹房深。", "欲問吾師法，衰年力不任。", "（《永樂大典》六六九九江字韻引《江州志》）（〖1〗張毅夫，原列「無世次」作者。", "今檢《舊唐書》卷一六二《張正甫傳》附其事迹，節引如次：毅夫，南陽人。", "正甫之子。", "登進士第，位至戶部侍郎、弘文館學士判院事。", "《唐僕尚丞郎表》卷三謂其任戶部侍郎約在咸通間。", "《舊唐書·宣宗紀》載其大中十一年四月自江西觀察使爲京兆尹，十二年正月出爲鄂岳觀察使。", "）。"]'),
('839b5456-9e6c-4e02-aad1-f480b4162a4b','句','鄭嵎','唐','唐诗','tang','','[]','春遊雞鹿塞，家在鷓鴣天。',24,'全唐诗/poet.tang.51000.json','["春遊雞鹿塞，家在鷓鴣天。", "（《藝需要伐山》十八）。"]'),
('6fd1ad68-cc34-4b3d-bd17-30cd99231e1c','寄鄭碏疊石硯歌','莊南傑','唐','唐诗','tang','','[]','媧皇補天殘錦片，飛落人間爲石硯。',110,'全唐诗/poet.tang.51000.json','["媧皇補天殘錦片，飛落人間爲石硯。", "孤峯削疊一尺雲，虎幹熊跪勢皆徧。", "半掬走泉澄淺清，洞天徹底寒泓泓。", "筆頭搶起松烟輕，龍蛇怒閗秋雲生。", "我今得此以代耕，如探禹穴披峥嶸。", "披峥嶸，心骨驚，坐中髣髴到蓬瀛。", "（《文房四譜》三《硯譜》）。"]'),
('4a40d6c1-b9af-4031-a9ed-34641dc6a37b','明月湖醉後薔薇花歌（《文苑英華》三三七《歌行》。《全唐詩》七八五無名氏第一首）（〖1〗《文苑英華》錄詩皆署作者姓名，不署字，此說恐未允。）','英才','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('df6c5884-5f1f-4690-83a6-a13724a8c171','石榴歌','莊布','唐','唐诗','tang','','[]','玳瑁殻皴枝婀娜，馬牙硝骨綿敷裏。',127,'全唐诗/poet.tang.51000.json','["玳瑁殻皴枝婀娜，馬牙硝骨綿敷裏。", "霜風擊破錦香囊，鸚鵡啄殘紅豆顆。", "美人擎在金盤腹，錯認海螺斑碌碌。", "滿口含嘗瓊液甘，一堂齒冷敲寒玉。", "（《古今圖書集成·草木典》二八二《石榴部》〖1〗）（〖1〗此詩見宋祝穆《事文類聚後集》卷二六、陳景沂《全芳備祖後集》卷六。", "）。"]'),
('566860d2-1939-443a-8f2f-a7ab925d329e','四面寺瀑布','李忱','唐','唐诗','tang','','[]','穿山度石不辭勞，到底還他地步高。',81,'全唐诗/poet.tang.51000.json','["穿山度石不辭勞，到底還他地步高。", "溪澗豈能留得住，終層大海作波濤。", "（《古今圖書集·職方典》七八五《安慶府部》。", "又《全唐詩》以前二句爲黃蘗禪師聯句，且文字多不同。", "）。"]'),
('a3edbc59-8bd3-4114-88b1-ec12721de573','贈隱者','溫庭筠','唐','唐诗','tang','','[]','楚客隱名姓，圍碁當薜蘿。',57,'全唐诗/poet.tang.51000.json','["楚客隱名姓，圍碁當薜蘿。", "亂溪藏釣石，一鶴在庭柯。", "敗堰水聲急，破窗山色多。", "南軒新竹逕，應許子猷過。", "（《又玄集》中）。"]'),
('f5356e7c-2423-427b-af40-05a9c3fe89db','蜂蝶（句）','溫庭筠','唐','唐诗','tang','','[]','蜜官金翼使，花賊玉腰奴。',21,'全唐诗/poet.tang.51000.json','["蜜官金翼使，花賊玉腰奴。", "（《清異錄》三）。"]'),
('32a2410a-da7a-4c9b-9cde-1b93da40faf6','與溫庭筠雲藍紙絕句（幷序。詩見《全唐詩》五八四。現補序）','段成式','唐','唐诗','tang','','[]','一日辱飛卿九寸小紙，兩行親書，云要采箋十番，錄少詩「稿」（爲）。',339,'全唐诗/poet.tang.51000.json','["一日辱飛卿九寸小紙，兩行親書，云要采箋十番，錄少詩「稿」（爲）。", "予有雜箋數角，多抽揀與人，既玩之輕明，復用殊麻滑。", "尚愧大庾所得，猶至四百枚，豈及右軍不節，盡付九萬幅。", "因知碧雲棋上，重翻懊惱之辭，紅葉溝中，更擬相思之曲。", "固應桑根作本，藤角爲封，古拙不重蔡侯，新樣偏饒桓氏。", "何啻奔墨馳騁，有貴長簾，下筆縱橫，偏求側理。", "所恨無色如鴨卵，狀如馬肝，稱寫《璇璣》，且題裂帛者。", "予在九江，出意造雲藍紙。", "既乏左伯之法，全無張永之功。", "輙分五十枚，並絕句一首，或得閑中暫當藥餌也。", "（原注：今《飛卿集》中有《播掿詞》○蘇易簡《文房四譜》四《紙譜》。", "〖1〗）（〖1〗據《知不足齋業書》本《文房四譜》校改。", "另「碧雲棋上」，作「碧聯棋上」；「裂帛」，作「裂錦」；「全無張永之功」之「全」字作「今」字。", "）。"]'),
('9057d892-a95b-4806-a8d3-268d4ec40a84','老僧續得貴妃襪（李羣玉同作）','李遠','唐','唐诗','tang','','[]','墜仙遺襪老僧收，一鎖金函八十秋。',76,'全唐诗/poet.tang.51000.json','["墜仙遺襪老僧收，一鎖金函八十秋。", "霞色尚鮮宮錦靿，彩光依舊夾羅頭。", "輕香爲著紅酥踐，微絢曾經玉指搆。", "三十六宮歌舞地，唯君獨步占風流。", "（《青瑣高議前集》六）。"]'),
('3e476ed3-ecb1-40b3-a769-a4e63aeaa3d6','李遠獲貴妃襪（各賦詩一首）','李羣玉','唐','唐诗','tang','','[]','故物存事渺茫，把來忍見舊時香。',76,'全唐诗/poet.tang.51000.json','["故物存事渺茫，把來忍見舊時香。", "抝連綺錦分奇樣，終合飛蟬飲瑞光。", "常束凝酥迷聖主，應隨玉步浴溫湯。", "如今落在吾兄手，無限幽情付本子郎。", "（《青瑣高議前集》六）。"]'),
('e5ed4663-a493-4bc6-8b91-7f11d916eb71','滄洲〖1〗','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','童兒待郭伋，竹馬空遲留。',194,'全唐诗/poet.tang.51000.json','["童兒待郭伋，竹馬空遲留。", "路指雲漢津，誰能吟《四愁》。", "銀壺傲海雪，青管羅名謳。", "賤子跡未安，謀身拙如鳩。", "分隨煙霞老，豈有風雲求。", "不逐萬物化，但貽知己羞。", "方窮力命說，戰勝心悠悠。", "不然蹲會稽，鈎下二五牛。", "所期波濤助，燀赫呈吞舟。", "（四部業刊影宋本《李羣玉詩便攜集》卷上）（〖1〗《全唐詩》卷五六八收作《洞庭驛樓雪讌集奉贈前湘州張員外》之後半篇，似誤。", "王安石《唐百家詩選》卷十七亦以此詩自爲一首。", "）。"]'),
('23fcb656-68f0-482c-af27-dced092fc664','送羣玉歸別業（句）','李壽朋','唐','唐诗','tang','','[]','秦樹有殘蟬，灃浦將歸客。',97,'全唐诗/poet.tang.51000.json','["秦樹有殘蟬，灃浦將歸客。", "（《輿地紀勝》七十《灃州》）（〖1〗作者原作「李朝士、李壽朋」。", "檢《輿地紀勝》原文作「唐季朝士李壽朋」知李壽朋爲唐末朝士，非另有「李朝士」其人。", "茲刪去「李朝士」三字。", "）。"]'),
('1fed5f9f-2ec9-47ef-ba10-a02d9e66a990','送羣玉（句）','韓續','唐','唐诗','tang','','[]','濡毫亂灑湘江月，整棹輕飛灃浦船。',21,'全唐诗/poet.tang.51000.json','["濡毫亂灑湘江月，整棹輕飛灃浦船。", "（同上）。"]'),
('726cea4b-aabe-446c-9339-3c942dc7163c','望南郡城（《全唐詩》引《方輿勝覽》缺題）','李頻','唐','唐诗','tang','','[]','楚地八千里，槃槃此都會。',40,'全唐诗/poet.tang.51000.json','["楚地八千里，槃槃此都會。", "巍峨數里城，遠水霜映帶。", "（《輿地紀勝》六五《江陵府》）。"]'),
('0e057302-5276-40c4-b104-3b7066b44398','寄舊友西乾耕隱童先輩','李頻','唐','唐诗','tang','','[]','種竹參差長，栽松次第成。',61,'全唐诗/poet.tang.51000.json','["種竹參差長，栽松次第成。", "戎衣遍江漢，未厭子真耕。", "（《四部業刊三編》影明抄本《梨嶽詩集·輯補》（原注：「右見徐璈刊本。", "」）。"]'),
('9a93d3b1-6c03-4196-94e0-df08d2f2af9d','送春','儲嗣宗','唐','唐诗','tang','','[]','無語共春別，細腰枝上紅。',41,'全唐诗/poet.tang.51000.json','["無語共春別，細腰枝上紅。", "來年又相見，還恐是愁中。", "（江標影刻宋本《唐五十家小集》）。"]'),
('0f2489cf-0e1c-4110-bbf6-2cb24216c5b3','九華樓','霍總','唐','唐诗','tang','','[]','東門帶溪路，上有三丈樓。',119,'全唐诗/poet.tang.51000.json','["東門帶溪路，上有三丈樓。", "層基接重阜，一覽山水周。", "天邊九芙蓉，出沒不可求。", "鴻驚曉霜凈，花明雨初收。", "巉然倚圭璧，爽氣凌尊籌。", "主人金閨彦高興思窮幽。", "時來據繩床，山色供遠眸。", "危峯曳遊雲，嶺月懸曲鈞。", "吟嘨意不淺，浩然追軻丘。", "明年雞省夢，肯忘江上州。"]'),
('f4c03145-5fcb-421a-a48f-81c79304d121','樓望','霍總','唐','唐诗','tang','','[]','樓高九華近，極目望峯頂。',62,'全唐诗/poet.tang.51000.json','["樓高九華近，極目望峯頂。", "雲破松風寒，路濃山色迥。", "古剎軒層簷，白水浮小艇。", "願結一間茅，歸來就丹鼎。", "（以上《嘉靖池州府志》八）。"]'),
('d55355aa-8bbe-4a83-8d5f-294863f5b8ca','贈妓（相牧廬州，有朝客留意飲妓，祖送短亭，妓車後至，相贈之曰：）','敬相','唐','唐诗','tang','','[]','望斷蘇娘小小坡，竹埿金雁展輕莎。',141,'全唐诗/poet.tang.51000.json','["望斷蘇娘小小坡，竹埿金雁展輕莎。", "客卿幸有凝情意，何必臨尊始轉波？", "（《詩話總龜》二三《寓情門》引《唐賢抒情》）（〖1〗敬相，當作敬湘。", "《新唐書·宰相世系表五上》敬氏有「湘，廬州刺史」，爲敬括曾孫。", "《郎官石柱題名考》卷十六金部員外郎有敬湘，約咸通末年任。", "原列「無世次」作者，今移此。", "）。"]'),
('92952b4f-e235-4f95-aeed-f45b3cc15360','泛石岐海','鄭愚','唐','唐诗','tang','','[]','此日攜琴劍，飄然事遠遊。',126,'全唐诗/poet.tang.51000.json','["此日攜琴劍，飄然事遠遊。", "臺山初罷霧，岐海正分流。", "漁浦颺來笛，鴻逵翼去舟。", "鬂愁蒲柳早，衣怯芰荷秋。", "未卜虞翻宅，休登王粲樓，愴然懷伴侶，徒爾賦離憂。", "（《嘉慶廣東通志》一○一《山川略·香山縣》）（〖1〗《全唐詩》卷五九七收「臺山」以下四句，題爲《幼作》。", "）。"]'),
('764c17b8-fa53-489e-bba0-805797ea424b','春日遊南山（句）','劉蛻','唐','唐诗','tang','','[]','屏開十里畫，江渡兩歧風。',29,'全唐诗/poet.tang.51000.json','["屏開十里畫，江渡兩歧風。", "（《輿地紀勝》一五四《潼川府》）。"]'),
('8f0dc253-16a7-4170-83f7-8a894db55b37','武侯墓','張演','唐','唐诗','tang','','[]','動業伊周亞，經綸楚漢前。',76,'全唐诗/poet.tang.51000.json','["動業伊周亞，經綸楚漢前。", "有才真命世，無地與中天。", "大統《春秋》意，謄章《說命篇》。", "吾家子房後，千載英賢。", "（《關中勝蹟圖志》二十二《漢中府·古蹟·郊邑》）。"]'),
('71732ac5-a5c5-4f7e-b163-8c88f7f5b4cd','贈劉郎中','李郢','唐','唐诗','tang','','[]','東南秀氣動文星，天子應教掃內庭。',66,'全唐诗/poet.tang.51000.json','["東南秀氣動文星，天子應教掃內庭。", "湘渚雪晴弧鶴唳，錦江雲盡一峰青。", "仁含楚樹花先發，爽照賓「筵」□□□。", "□□定宜端劍珮，上仙風骨紫蘭馨。"]'),
('432d2498-b100-4b19-9df5-dc5f147d124a','題水精釵','李郢','唐','唐诗','tang','','[]','脉脉兩條秋水色，農夫賤賣古城旁。',64,'全唐诗/poet.tang.51000.json','["脉脉兩條秋水色，農夫賤賣古城旁。", "何年偶墮青絲髮，問價應齊白玉璫。", "插去定難分鏡彩，看時長似滴珠光。", "人間更有不足貴，金雀徒誇十二行。"]'),
('1fbabd35-53d0-4865-a2c7-70eeccc2f3e7','放鷓鴣','李郢','唐','唐诗','tang','','[]','玉樓珠戶養經時，放出雕籠久不飛。',64,'全唐诗/poet.tang.51000.json','["玉樓珠戶養經時，放出雕籠久不飛。", "秦地遊僧一彈指，楚城遷客重思歸。", "崗田戲下晴風暖，茅壠驚啼返照微。", "山畔家家有羅網，莫教傷損好毛衣。"]'),
('7fd835b3-9f8c-4adb-bb36-34da1132a2a4','渡淮後却泗州秦處士','李郢','唐','唐诗','tang','','[]','淮上風吹別酒醒，淮南潮落見沙汀。',65,'全唐诗/poet.tang.51000.json','["淮上風吹別酒醒，淮南潮落見沙汀。", "正愁客路逢山雨，更憶雲外臥草亭。", "野鷺獨飛仙嶂綠，農田□植晚苗青。", "何人得及秦居士，藥化丹砂劍有靈。", "。"]'),
('091be757-bc63-4180-b62a-fc65c7a2851c','山中','李郢','唐','唐诗','tang','','[]','清濁山中一氣分，洞中仙籟靜時聞。',65,'全唐诗/poet.tang.51000.json','["清濁山中一氣分，洞中仙籟靜時聞。", "竹花生□□□□，桑葉抱風蠒蛾紛紛。", "夜月泛琴絃似磬，秋潭洗硯墨成雲。", "海邊兄弟無音息，斜日愁看綠嶠曛。"]'),
('e2fe0e3b-75a8-46bb-a589-28402391040f','送友生下第出關','李郢','唐','唐诗','tang','','[]','天牓無名玉未焚，幾飄凝淚泣青雲。',63,'全唐诗/poet.tang.51000.json','["天牓無名玉未焚，幾飄凝淚泣青雲。", "挈將孤劍家何在，叫斷重閽帝不聞。", "花笑旅人惟賴酒，鏡欺雙鬢莫言文。", "糟床滴瀝餘聲盡，典重裘又送君。"]'),
('b784150e-f7de-40dc-9f9f-7361e088105a','早春送友人歸江南','李郢','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭歸客莫相催，予憶滄江久未迥。',64,'全唐诗/poet.tang.51000.json','["洞庭歸客莫相催，予憶滄江久未迥。", "歸渡遇霜楊柳盡，寒郊欲雪鶺鴒來。", "舟依青路帆初挂，鳥出紅塵眼漸開。", "千里同來不同去，莫驚愁淚濺離杯。"]'),
('773a6774-bd36-4cb4-ae05-1adb4e1d3f53','讀《漢武內傳》','李郢','唐','唐诗','tang','','[]','雲錦囊開得畫圖，岳神森聳耀靈軀。',63,'全唐诗/poet.tang.51000.json','["雲錦囊開得畫圖，岳神森聳耀靈軀。", "青真小童捧訣籙，紫府道士攜瓊蘇。", "金鼎未成悲濁世，玉緘時捧望青都。", "一辭姥長昏醉，方朔留言盡記無。"]'),
('70b08685-f43f-4628-b048-3e3e9cd91849','不睡','李郢','唐','唐诗','tang','','[]','沃洲山裏苦心人，十五年來少睡身。',65,'全唐诗/poet.tang.51000.json','["沃洲山裏苦心人，十五年來少睡身。", "詩句每多閒夜得，鬢毛終爲半愁新。", "紛紛落燼看將久，歷歷寒更聽轉頻。", "家寄江南斷音信，一憑歸夢去無因。", "。"]'),
('1e502cd8-2f7e-4295-b7e4-7f2b8f096fcb','春晚思江上舊遊寄城中知己','李郢','唐','唐诗','tang','','[]','一春江上好韶光，劉阮相隨醉幾場。',48,'全唐诗/poet.tang.51000.json','["一春江上好韶光，劉阮相隨醉幾場。", "令節輕雲著羅綺，曉天晴色在壺觴。", "紫雲樓畔金絲發，紅杏園中玉輦香。"]'),
('743a7a15-e568-4874-86c3-4d19741d0d54','寄友人乞菊栽（〖1〗《全唐詩》八八四有缺字。第五句「及」《石渠寶笈》作「近」，第七句《全唐詩》缺首字「孺」，末句「鳩」《石渠寶笈》作「鴛」。）','李郢','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('61ffad51-10f8-40de-a5ec-876977771e2d','送澗水陜東二十里自江南來作','李郢','唐','唐诗','tang','','[]','泠泠孤澗陜城東，我有飛泉此路通。',64,'全唐诗/poet.tang.51000.json','["泠泠孤澗陜城東，我有飛泉此路通。", "行客莫驚黃葉盡，家山祇在白雲中。", "秋聲可亂鳥魚意，遠色偏依蒲稗業。", "過去多應不相待，殷勤重掬洒西風。"]'),
('2d260bae-68fc-47ae-9820-9f79af1d3a6f','五湖冬日','李郢','唐','唐诗','tang','','[]','楚人家住五湖東，斜掩柴門水石中。',64,'全唐诗/poet.tang.51000.json','["楚人家住五湖東，斜掩柴門水石中。", "獵獵夜山明遠燒，騷騷寒葦動疎風。", "園林向臘停霜果，葭菼和烟宿暝鴻。", "范蠡扁舟不知處，一將前事話漁翁。"]'),
('1a462602-8b46-42a9-a64a-753dd1d2a7e9','江南冬日喜遇故人','李郢','唐','唐诗','tang','','[]','江南木落塞鴻飛，江漢離人久未歸。',64,'全唐诗/poet.tang.51000.json','["江南木落塞鴻飛，江漢離人久未歸。", "客舍無成重相見，雪天留宿可相違。", "篇章只使容颜改，名利空教翰墨稀。", "終擬全家漾舟去，五湖高掩白雲扉。"]'),
('aedaa700-4818-4eb7-b024-35d518fe63a2','春夜','李郢','唐','唐诗','tang','','[]','街鼓初殘百八聲，小園芳樹宿孤鶯。',65,'全唐诗/poet.tang.51000.json','["街鼓初殘百八聲，小園芳樹宿孤鶯。", "人迴野寺昏醉，月照閑房悄悄明。", "杏酪香濃寒食近，梨花影散夜風輕。", "誰家靜捻參差管，一曲《霓裳》學鳳清。"]'),
('5af63259-523e-4187-af03-ba18c8ba04d8','雨夜','李郢','唐','唐诗','tang','','[]','蛩聲雨思夜迢迢，空館何人問寂寥。',64,'全唐诗/poet.tang.51000.json','["蛩聲雨思夜迢迢，空館何人問寂寥。", "寒燭細烟搖寢幌，濕螢微影綴芭蕉。", "正當孤枕鴻初過，況復窮居葉盡凋。", "閒憶秋江釣船裏，洒篷沾浪聽蕭蕭。"]'),
('657547af-0b83-4035-b775-9b9f615f5eba','送僧遊天台（〖1〗《全唐詩》五九○題作《送圓鑑上人遊天台》。末句《石渠寶笈續編》作「幽澗泠泠竹室開」）','李郢','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('ef0a5374-48c9-4b85-b55d-dde6d4a16e33','試日上主司侍郎 一','李郢','唐','唐诗','tang','','[]','十年多病到京遲，到日風霜逼試期。',63,'全唐诗/poet.tang.51000.json','["十年多病到京遲，到日風霜逼試期。", "線不因針何處入，水難投石古來知。", "青烟羃寒更恨，白髮星星曉鏡悲。", "可惜龍門好風水，何人一爲整鱗鬐。"]'),
('402720ac-2441-4e3e-aec1-1d8376b229c9','試日上主司侍郎 二','李郢','唐','唐诗','tang','','[]','石帆山下有靈源，修竹茅堂寄此村。',64,'全唐诗/poet.tang.51000.json','["石帆山下有靈源，修竹茅堂寄此村。", "閉戶偶多鄉老譽，讀書精得聖人言。", "來時已作青雲意，試夜憂生白髮根。", "十五年餘詩弟子，名成豈合在他門。"]'),
('d8fd0d7e-56b8-4dce-90b2-7b457b088345','送李商隱侍御奉使入關','李郢','唐','唐诗','tang','','[]','梁園相遇管絃中，君踏仙梯我轉蓬。',66,'全唐诗/poet.tang.51000.json','["梁園相遇管絃中，君踏仙梯我轉蓬。", "《白雪》詠歌人似玉，青雲頭角馬生風。", "相逢幾日虛懷待，賓幕連期醉蝶同。", "如有扁舟棹歌思，題詩時寄五湖東。"]'),
('29b7e6e0-68b8-4294-9cce-1ff2909e6d03','板橋重送','李郢','唐','唐诗','tang','','[]','梁苑城西蘸水頭，玉鞭公子醉風流。',64,'全唐诗/poet.tang.51000.json','["梁苑城西蘸水頭，玉鞭公子醉風流。", "幾多紅粉低鬟恨，一部清商駐拍留。", "王事有程須仃仃，客身如夢正悠悠。", "洛陽浸畔逢神女，莫墜金樓醉石榴。"]'),
('5f088612-28d7-4007-a1e8-1c0e9fd93e38','紫極宮上元齋日呈諸道流（〖1〗《全唐詩》「日」作「次」。又詩中第五句「風拂亂燈山磬曙」，《全唐詩》缺「曙」字。）','李郢','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('a5b17146-fff8-46ed-a309-90e801eea931','贈羅道士','李郢','唐','唐诗','tang','','[]','子訓成仙色似花，每人思見禮烟霞。',48,'全唐诗/poet.tang.51000.json','["子訓成仙色似花，每人思見禮烟霞。", "氣呵雲液變白髮，爪入水精嘗綠瓜。", "五岳真官隨起坐，百年風燭笑榮華。"]'),
('e7df0bab-67c7-4fe7-b162-f892c2723b4b','終南山','李郢','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','終南雨後絶纖埃，太乙先生石室開。',64,'全唐诗/poet.tang.51000.json','["終南雨後絶纖埃，太乙先生石室開。", "漢史烟霞通楚塞，秦風章句有條梅。", "歸逢四皓收靈朮，幾見千官祝壽杯。", "會得功成畢婚嫁，幅巾藜杖獨歸來。"]'),
('8639e4e4-fc45-4b5d-9706-40669b8b7228','春山夜雨','李郢','唐','唐诗','tang','','[]','詩成數盞兀忘思，瞑目昏昏倒接䍦。',64,'全唐诗/poet.tang.51000.json','["詩成數盞兀忘思，瞑目昏昏倒接䍦。", "無魚無愁且須醉，好風好月更何爲。", "長留酒在花堆雪，不厭身閒鬢聚絲。", "一夕春山到明坐，杜鵑啼歇麑啼時。"]'),
('531f8ac2-ad6e-4558-868d-b88ff04ec0a5','驪山懷古（五首） 一','李郢','唐','唐诗','tang','','[]','武帝尋仙駕海遊，禁門高閉水空流。',64,'全唐诗/poet.tang.51000.json','["武帝尋仙駕海遊，禁門高閉水空流。", "深宮帶日年年靜，翠柏凝烟夜夜愁。", "鸞鳳影沉歸萬古，歌鐘聲斷夢千秋。", "晚來惆悵無人會，雲水猶飛傍玉樓。"]'),
('d9bd191b-a3e4-4df5-a9b1-f2df33b7eab0','驪山懷古（五首） 二','李郢','唐','唐诗','tang','','[]','烟深樹老蔽蒼蒼，樓殿參差隱夕陽。',64,'全唐诗/poet.tang.51000.json','["烟深樹老蔽蒼蒼，樓殿參差隱夕陽。", "白玉砌寒苔自碧，真珠簾斷月無光。", "驪山南去侵天盡，渭水東流入海長。", "唯有春風舊情在，不將花艷出宮牆。"]'),
('aacbd527-e0ee-4bfd-acfe-11fc6a6eef0f','驪山懷古（五首） 三','李郢','唐','唐诗','tang','','[]','紫府靈壇降玉真，華清臺殿影長新。',64,'全唐诗/poet.tang.51000.json','["紫府靈壇降玉真，華清臺殿影長新。", "雪翻曉豔御階秀，風送夜香宮樹春。", "杉桂靜同無夢客，烟花深似有愁人。", "自從霜落芙蓉死，空使秦山鬼哭頻。"]'),
('14c9e668-cece-4d83-95f7-79d0fdc65ff1','驪山懷古（五首） 四','李郢','唐','唐诗','tang','','[]','碧瓦雕牆擁翠微，泉聲一去杳難期。',48,'全唐诗/poet.tang.51000.json','["碧瓦雕牆擁翠微，泉聲一去杳難期。", "一聞緱嶺仙成日，空想鈞天夢盡時。", "青嶂淺深當雨靜，古松疎密向風悲。"]'),
('24226b96-86b2-496b-a55e-5f55baee5a3d','驪山懷古（五首） 五','李郢','唐','唐诗','tang','','[]','當時事事笑秦皇，今日追思倍可傷。',64,'全唐诗/poet.tang.51000.json','["當時事事笑秦皇，今日追思倍可傷。", "珠玉影搖千樹冷，綺羅風動滿川香。", "雖名金殿長生字，誤說茅山不死方。", "獨向逝波無問處，古槐花落路茫茫。"]'),
('7c6cc7ba-136f-4a8a-b91e-8a254a0b39ed','夜思','李郢','唐','唐诗','tang','','[]','軒墀寂寞夜如何，沙渚頻驚候雁過。',48,'全唐诗/poet.tang.51000.json','["軒墀寂寞夜如何，沙渚頻驚候雁過。", "一點秋燈人夢覺，萬重寒葉雨聲多。", "酒衝肺腑愁生病，詩役心神漸有魔。"]'),
('56bc1361-b543-4018-b976-a3f6f612f48f','贈李商隱贈佳人','李郢','唐','唐诗','tang','','[]','金珠約臂近笄年，秋月嫦娥漢浦仙。',64,'全唐诗/poet.tang.51000.json','["金珠約臂近笄年，秋月嫦娥漢浦仙。", "雲髮膩垂香挅妥，黛眉愁入翠連娟。", "花庭避客鳴環珮，鳳閣持杯泥管絃。", "聞道彩鶯三十六，一雙雙映碧池蓮。"]'),
('34a956ce-9e57-4412-ad16-e962f42705f5','傷賈島無可（《全唐詩》五九○收此詩，文字異同較多，故重錄）','李郢','唐','唐诗','tang','','[]','却到城中（《全唐詩》作「京師」）事事傷。',93,'全唐诗/poet.tang.51000.json','["却到城中（《全唐詩》作「京師」）事事傷。", "惠休歸去（寂）賈生亡。", "誰人收得章句（文章）篋。", "獨我重（來）經苔蘚房。", "一命未沾爲逐客。", "萬緣初盡別空王。", "蕭蕭竹塢殘（斜）陽在。", "葉拂（覆）閒堦雪擁墻。", "。"]'),
('fd58259d-eb57-4e17-9dbf-e27abe637303','闕題','李郢','唐','唐诗','tang','','[]','一道春江枕驛樓，聞君此處泊行舟。',64,'全唐诗/poet.tang.51000.json','["一道春江枕驛樓，聞君此處泊行舟。", "花當粉檻人閒立，燕拂青蘋水漫流。", "芳草引歸南國夢，和風吹起故園愁。", "余今自是迷津者，爲勸王孫莫遠遊。"]'),
('0c0525e9-389c-4f03-8c0f-71950ff1c74a','闕下獻楊侍郎','李郢','唐','唐诗','tang','','[]','滄洲垂釣本無名，十月風霜偶到京。',64,'全唐诗/poet.tang.51000.json','["滄洲垂釣本無名，十月風霜偶到京。", "羸馬未曾諳道路，片文誰爲達公卿？", "聽殘曉漏愁終在，畫盡寒灰計不成。", "心苦篇章頭早白，十年江漢憶先生。"]'),
('6f39643d-bc59-4700-a03e-6c0744526674','江州城樓','李郢','唐','唐诗','tang','','[]','灘頭獨鳥立枯楂，灘上行人踏淺沙。',64,'全唐诗/poet.tang.51000.json','["灘頭獨鳥立枯楂，灘上行人踏淺沙。", "秋色池塘無限草，夕陽門外幾千家。", "寺連山谷松聲遠，川繞閻閭水勢斜。", "常恐郡城砧杵動，秋風吹盡古槐花。"]'),
('6a99cac6-6b24-4786-8fc8-28dd0d6debcb','春日題園林','李郢','唐','唐诗','tang','','[]','東園落盡綠絲長，風觸誰家酒瓮香。',64,'全唐诗/poet.tang.51000.json','["東園落盡綠絲長，風觸誰家酒瓮香。", "紅粉人閑教鸚鵡，碧波池暖漾鴛鴦。", "新蒲長疾看齊岸，晚蝶飛高欲過墻。", "記取因逢賣樵客，囑教春暮採松篁。"]'),
('77e6b712-48a5-496c-bdd2-182c518b57bc','贈（據《壯陶閣帖》卷二補。）','李郢','唐','唐诗','tang','','[]','建陽門外柳千條，斜插鸞篦小錯刀。',487,'全唐诗/poet.tang.51000.json','["建陽門外柳千條，斜插鸞篦小錯刀。", "紫袖握蟬聲欲絕，紅巾撲蝶勢潛高。", "愁眉對照烟江柳，嫩臉初開露井桃。", "閑把金釵惱鸚鵡，亂聲啞嘎落輕毛。", "（以上《秘殿珠林石渠寶笈續編》。", "）（《秘殿珠林石渠寶笈續編》收李郢詩卷，原藏於淳化軒。", "卷末有樂全居士、柯九思、陳繹曾、周仁榮、張翥五人附跋。", "茲錄前三人跋如次。", "）（〖1〗其一：李公嘗出守房陵商州，有善政，以能詩聞諸公間，有文集行於世。", "此詩翰墨豪健，自成一家。", "宣和六年季夏一日，樂全居士書。", "〖原注：張密學諱確，字子固。", "〗〖2〗其二：右唐李郢字楚望書七言詩真跡，後有張樂全跋，曾入紹興內府，合縫小璽具存。", "詩法清麗，筆意飄撇，自有一種風氣。", "僕僅見宣和所收許渾詩稿，精緻亦如之，足以見唐人所尚，流風餘韻，令人興起。", "至治初，以佳本定武《蘭亭》易得之，愛玩不能去手。", "丹丘柯九思識。", "〖3〗其三：唐李楚望端公大中十年七言詩一卷。", "楚望以是歲登進士第，其上主司詩云：「閉戶偶多鄉老譽，讀書精得聖人言。", "」視「一日看盡長安花」，殆有間矣。", "宜其疏於馳競，以藩鎮從事終也。", "此紙鳥絲欄絕精緻，字畫有歐柳意。", "楚望居餘杭，豈出於故家遺俗之所傳者歟？", "泰定元年十月十三日，吳興陳繹曾書。"]'),
('32848f7a-35db-439d-b840-a6806fe481c9','平望驛感先輩李從實處士周鉷二故人','李郢','唐','唐诗','tang','','[]','蘆葦風多驛堠長，昔年携手上河梁。',77,'全唐诗/poet.tang.51000.json','["蘆葦風多驛堠長，昔年携手上河梁。", "青雲才子鴛鴻季，白石山人芝木香。", "華驥欲陪先道路，大川斯濟戢舟航，少微星沒桂枝重，正掛孤帆過水鄉（《百城烟水》四《吳江》）。"]'),
('a9fc9cee-c08e-449e-a088-48add41f4996','賞花短歌','李漼','唐','唐诗','tang','','[]','長生白，久視黃，共拜金剛不壞王（謂菊花也。',29,'全唐诗/poet.tang.51000.json','["長生白，久視黃，共拜金剛不壞王（謂菊花也。", "《清異錄》二）。"]'),
('fbdf53d1-3a88-4d48-83e2-9423de1f1dd8','題惠山泉（二首） 一','皮日休','唐','唐诗','tang','','[]','丞相長思煮泉時，郡侯催發只憂遲。',32,'全唐诗/poet.tang.51000.json','["丞相長思煮泉時，郡侯催發只憂遲。", "吳關去國三千里，莫笑楊妃愛荔枝。"]'),
('507be5e5-55e0-4a91-838f-60b67a5f5e4b','題惠山泉（二首） 二','皮日休','唐','唐诗','tang','','[]','馬卿消瘦年纔有，陸羽茶門近始閒。',66,'全唐诗/poet.tang.51000.json','["馬卿消瘦年纔有，陸羽茶門近始閒。", "時借僧爐拾寒葉，自來林下煮潺湲。", "（元《無錫縣志》卷四上辭章詠歌。", "又明《弘治無錫縣志》二八《詞章》）。"]'),
('3cfdb3f4-8f4a-49ec-92f4-0c87fbdc5798','泰伯廟','皮日休','唐','唐诗','tang','','[]','蠻荆古服屬南荒，大聖開基闢草堂。',32,'全唐诗/poet.tang.51000.json','["蠻荆古服屬南荒，大聖開基闢草堂。", "載造文明追二帝，尚餘揖讓補三王。"]'),
('f4b0576e-284a-4005-86db-29d3b32f40ee','望虞亭','皮日休','唐','唐诗','tang','','[]','盤迴曲澗數峯青，雲護皇山一古亭。',48,'全唐诗/poet.tang.51000.json','["盤迴曲澗數峯青，雲護皇山一古亭。", "千里月明回首望，飛烟冲起海虞濱。", "（以上清初《梅里志》三《詩》）。"]'),
('5b9b4868-1ef9-4ac5-bb07-de003469d2c9','松江秋書','陸龜蒙','唐','唐诗','tang','','[]','張翰深心怕禍機，不緣蓴脆與鱸肥。',78,'全唐诗/poet.tang.51000.json','["張翰深心怕禍機，不緣蓴脆與鱸肥。", "如何狗世浮沉去，可要拋官獨自歸？", "風度野烟侵醉帽，雨來秋浪濺吟衣。", "無人好尚無人責，吟嘯低頭又掩扉。", "（《百城烟水》四《吳江》）。"]'),
('5bcb5bee-11c4-454b-95e5-5196d8ca9975','蓬傘','陸龜蒙','唐','唐诗','tang','','[]','吾江善編蓬，圓者柄爲傘。',48,'全唐诗/poet.tang.51000.json','["吾江善編蓬，圓者柄爲傘。", "所至以自隨，清陰覆一墠。", "自吾爲此計，簑笠□□短。", "何須詣亭陰，風雨皆足緩。"]'),
('98ae706f-bb86-4a05-9d4e-8436c4b951a5','謝人詩卷（句）','陸龜蒙','唐','唐诗','tang','','[]','談仙忽似朝金母，說艷渾如見玉兒。',29,'全唐诗/poet.tang.51000.json','["談仙忽似朝金母，說艷渾如見玉兒。", "（以上吳聿《觀林詩話》）。"]'),
('77561997-eb56-4873-9df5-7beca7a1eec6','{巩/言}光大師草書歌','司空圖','唐','唐诗','tang','','[]','羸病愛師書勁逸，翻作長歌助狂筆。',193,'全唐诗/poet.tang.51000.json','["羸病愛師書勁逸，翻作長歌助狂筆。", "乘高攂鼓震川原，驚迸驊騮幾千匹。", "落筆縱橫不離禪，方知草聖本非顛。", "歌成與掃松齋壁，何似曾題《說劍篇》。", "（《六藝之一錄》二九○引朱長文《墨池編》十三原書目錄作{巩/言}光詩）（《四庫全書》本《墨池編》卷四錄此詩無作者，附司空圖《書屏記》後。", "《宣和書譜》卷九錄司空圖贈{巩/言}光詩云：「看）（師逸說蹟兩相宜，高適歌行李白詩」，此詩中無。", "是砧圖作，頗可疑。", "）。"]'),
('6f456597-e3ca-44eb-90c5-03a466420996','恭州界（舊《圖經》及《寰宇記》、《九域志》皆日渝州，《輿地廣記》曰恭州。）','司空圖','唐','唐诗','tang','','[]','山容地脈本清涼，不解爲霖卻作湯。',49,'全唐诗/poet.tang.51000.json','["山容地脈本清涼，不解爲霖卻作湯。", "草木龜魚困薰煮，漫贏塵垢涴僧坊。", "（《輿地紀勝》一七五《重慶府》）。"]'),
('8e0200d7-52a0-44a4-9d77-b4ac57629351','春晚（句）','司空圖','唐','唐诗','tang','','[]','憑高憐酒韻，引滿未能已。',12,'全唐诗/poet.tang.51000.json','["憑高憐酒韻，引滿未能已。"]'),
('f8ef7f3d-0f09-4eb8-9b0e-5267294276d0','撫事寄同游（句）','司空圖','唐','唐诗','tang','','[]','春添茶韻時過寺。',26,'全唐诗/poet.tang.51000.json','["春添茶韻時過寺。", "（以上元李治《敬齋古今黈逸文》二）。"]'),
('77dcf474-032b-4ced-859e-0490813b5e5a','過平泉莊（李朱厓〖德裕〗平泉莊，佳景可愛。洛中士人詫於「汪」〖江〗遵，遵有詩曰：）','汪遵','唐','唐诗','tang','','[]','平泉風景好高眠，水色風光滿目前。',60,'全唐诗/poet.tang.51000.json','["平泉風景好高眠，水色風光滿目前。", "剛欲平他不平事，至今惆悵滿南遷。", "（今按：此一首與《唐詩紀事》及《全唐詩》字句多不同。", "）。"]'),
('1782bedd-b79a-4f65-84a4-60987c36f31e','又過楊相宅','汪遵','唐','唐诗','tang','','[]','倚伏從來事不遙，無何平地起青霄。',117,'全唐诗/poet.tang.51000.json','["倚伏從來事不遙，無何平地起青霄。", "纔到青霄却平地，門對古槐空寂寥。", "（以上《詩話總龜》二四《感事門》引《唐賢抒情》）（〖1〗《萬首唐人絕句》卷六九以此詩爲尹璞作，文字稍異。", "《全唐詩》卷五一七收尹璞名下，幷注出《抒情錄》作江遵詩之異文。", "）。"]'),
('d457994a-b968-47f2-8316-594d0bf1b31a','句','童漢卿','唐','唐诗','tang','','[]','願假中流便，滋茲發棹歌。',53,'全唐诗/poet.tang.51000.json','["願假中流便，滋茲發棹歌。", "（《古今圖書集成·友誼典·請託部》選句。", "此二句疑非童詩。", "但應爲誰作，尚俟考詳。", "）。"]'),
('9c4e3829-10fd-46f6-ab43-7ff548f4fb8d','詠柳','童漢卿','唐','唐诗','tang','','[]','灞橋晴來送別頻，相偎相依不勝春。',206,'全唐诗/poet.tang.51000.json','["灞橋晴來送別頻，相偎相依不勝春。", "自家飛絮猶無定，爭把長條絆得人。", "（《詩話總龜》二一《詠物門》引羅隱《績本事詩》。", "按此處注出處引錄有誤。", "《詩話總龜》此條原注云：「《唐宋詩》云羅隱作。", "《續本事詩》。", "」《唐宋詩》指宋初人編《唐宋類詩》。", "《續本事詩》則爲吳處常子作，非羅隱作。", "《全唐詩》卷六五七收作羅隱《柳》詩，另《甲乙集》卷三、《才調集》卷八、《文苑英華》卷三二四亦作羅詩。", "因《續本事詩》成書之時較早，姑仍兩存之。", "）。"]'),
('5066b72b-1708-409b-9e64-7e5320c648a1','代張孜幻夢李白歌','李山甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','天使翰林生我前，相去歿（一作「後」）來二百年。',366,'全唐诗/poet.tang.51000.json','["天使翰林生我前，相去歿（一作「後」）來二百年。", "英神傑（一作「絕」）氣歸玄天，日月星辰空蹙然。", "我識翰林文，不識翰林面。", "上天知我憶其人，使向人間夢中見。", "瑞光閃爍天關（一作「門」）開，五雲著地長裾來，華山秀作英雄骨，黃河瀉作縱橫才。", "巍峨宛似神仙客，一段風雷扶氣魄。", "低頭語了却擡頭，指點胸前稱李白。", "夢中一面何殷勤，高吟大語喧青雲。", "自言天府偶閑暇，與我握手論高文。", "一論耳目清，再論心骨驚，豁如混沌初鑿破，天地海岳何分明。", "利若劍戟堅，健如虬龍爭，神機聖法說略盡，造化與我新精靈。", "不問塵埃人，不語塵埃事，罇前酒半（一作「半日」）空，歸雲掃筵起。", "自言天上作先生，許向人間爲弟子。", "夢破青霄春，煙霞無去塵。", "若誇郭璞五色筆，江淹却是尋常人（《全唐詩》卷六○七收「華山」二句及末四句，卷八六八收「上天」二句，均誤繫於張孜名下。", "）（《鑑誡錄》九《夢太白》）。"]'),
('70c665fb-30c0-4d70-9864-7528ec46fc70','','胡曾','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('6c589d3b-57f4-457d-9291-c704832c2989','緱山','胡曾','唐','唐诗','tang','','[]','緱山崗翠孕仙靈，古柏新松滿洞馨。',55,'全唐诗/poet.tang.51000.json','["緱山崗翠孕仙靈，古柏新松滿洞馨。", "借問吹笙王子晉，定從何處上□冥。", "（《四部業刊三編》影宋鈔本《胡曾詠史詩》三）。"]'),
('a08453a3-3b32-469d-809c-f34628e8beee','懷桐江舊居','方干','唐','唐诗','tang','','[]','長向新郊話故園，四時清峭似山源。',64,'全唐诗/poet.tang.51000.json','["長向新郊話故園，四時清峭似山源。", "春潮撼動鶯花郭，秋雨閒藏砧杵邨。", "市井多通諸國貨，鄉音自是一方言。", "此中別有無歸計，唯把歸心付酒尊。"]'),
('bd4b2aba-faee-4f83-9d88-2f1a4f79deab','贈桐溪主人','方干','唐','唐诗','tang','','[]','嶺猿沙鶴似同遊，竹汊荷灣可漾舟。',41,'全唐诗/poet.tang.51000.json','["嶺猿沙鶴似同遊，竹汊荷灣可漾舟。", "更入深溪見溪主，蒼苔石上臥垂鈎。", "（《嚴陵集》二）。"]'),
('9cd08d76-e707-462f-9272-a9adea43c075','題惠山寺詩（幷序） 讀惠山若冰師詩集因題古院（一作「故園」）五首（前三首《全唐詩》已收） 一','李隲','唐','唐诗','tang','','[]','陰陰垂露跡，苔壁幾年書。',49,'全唐诗/poet.tang.51000.json','["陰陰垂露跡，苔壁幾年書。", "種樹青松老，傳衣白髮居。", "字工窮八體，詩律繼三閭。", "豈是多年學，真空任性理餘。"]'),
('f5723a8a-9493-4d97-9cdf-e61f91b43c47','題惠山寺詩（幷序） 讀惠山若冰師詩集因題古院（一作「故園」）五首（前三首《全唐詩》已收） 二','李隲','唐','唐诗','tang','','[]','常聞鑿洞碑，此立爲冰師。',84,'全唐诗/poet.tang.51000.json','["常聞鑿洞碑，此立爲冰師。", "意刻山泉解，功深造化疑。", "碧雲終一謝，飛錫久無期。", "惆悵人間世，空傳樂府詞。", "（元《無錫縣志》卷四上《辭章詠歌》、又明《弘治無錫縣志》二八《詞章》）。"]'),
('2cb9c3f0-75eb-4b28-8913-bdef5f8f85ed','晨過昌師院（〖1〗《全唐詩》二七一作竇羣詩。《縣志》第八句「滿」作「漏」○同前〗〖《竇氏聯珠集》不收此詩，作竇詩疑誤。）','李隲','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('c75291e3-b678-4af0-b4a3-e08e728b7f3a','九華山協濟祠','羅鄴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','靈廟門依山半開，松庭瀟洒絕塵埃。',97,'全唐诗/poet.tang.51000.json','["靈廟門依山半開，松庭瀟洒絕塵埃。", "時聞樵者經過說，數有神仙變化來。", "龍起陰雲生畫壁，鳥歸寒粟落蒼苔。", "自從鼓吹喧闐日，千里封疆不復災。", "（《嘉靖池州府志》五。", "又《圖書集成·職方典》八一○《池州府部》）。"]'),
('889b143f-eca5-4deb-a353-10eb40eceaa3','化城寺','羅鄴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','慶雲生處梵王宮，躡磴攀蘿一徑通。',74,'全唐诗/poet.tang.51000.json','["慶雲生處梵王宮，躡磴攀蘿一徑通。", "金殿忽開青嶂裏，天人疑在白雲中。", "秋霄爽朗空潭月，暑氣蕭寥古柏風。", "況是慈悲清淨地，香煙像設固無窮。", "（《九華山志》八）。"]'),
('57585f9b-c061-4790-aae6-54d52f6aa7bf','謝友人惠箋紙幷筆','周朴','唐','唐诗','tang','','[]','范陽從事獨相憐，見惠霜毫與彩箋。',81,'全唐诗/poet.tang.51000.json','["范陽從事獨相憐，見惠霜毫與彩箋。", "三副緊纏秋月兔，五般方翦蜀江煙。", "宵徵覺有文通夢，日習慚無子諒篇。", "欲着不將兩處用，歸山閑向墨池前。", "（蘇易簡《文房四譜》四《紙譜》）。"]'),
('655e4998-5575-47e5-b386-655ace27fc36','梨花','溫憲','唐','唐诗','tang','','[]','綠陰寒食晚，猶自滿空園。',104,'全唐诗/poet.tang.51000.json','["綠陰寒食晚，猶自滿空園。", "兩歇芳菲白，蜂稀寂寞繁。", "一枝橫野路，數樹出江村。", "悵望頻回首，何人共酒尊。", "（《古今圖書集成·草木典·梨部》（見宋陳景沂《全芳備祖前集》卷九《梨花》。", "「蜂稀」，《全芳備祖》作「蜂聲」。", "）。"]'),
('45dceae6-0b72-438f-b768-5498026e746d','留贈司空圖（盧相攜還朝，過陜虢，訪圖，深愛重，留詩曰：）','盧攜','唐','唐诗','tang','','[]','氏族司空貴，官班御史雄。',79,'全唐诗/poet.tang.51000.json','["氏族司空貴，官班御史雄。", "老夫如且在，未可歎途窮。", "（《北夢鎖言》三及《唐才子傳》司空圖下。", "《全唐詩》有此詩，與《紀事》同依據《南部新書》甲，多異文，故重錄。", "）。"]'),
('da170227-ceaf-455e-9d3f-8a80df88b969','贈妓行雲等感恩多詞（句）（路侍中具有，風貌之美，爲世所聞。鎮成都日，委執政于孔目吏邊咸，以官妓行雲等十人侍宴。移鎮渚宮日，于合江亭離筵，贈行雲等《口恩多》詞。有「離魂」云云。至今播于倡樓也。）','路巖','唐','唐诗','tang','','[]','離魂何處斷？',136,'全唐诗/poet.tang.51000.json','["離魂何處斷？", "烟雨江南岸。", "（《唐語林》四《容止》、《北夢瑣言》三）（〖1〗《全唐詩》無路巖詩，茲據《舊唐書》卷一七七補傳如次：路巖，字魯瞻，陽平冠氏人。", "幼聰敏過人，方鎮交辟，數年間出入禁署，累遷中書舍人、戶部侍郎。", "咸心目三年以本官同平章事，在相位八年。", "後出鎮劍南、荆南。", "）。"]'),
('0021f887-dbca-4f6a-85bb-afbdd3e25ade','','吳融','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('0dce7fbe-0eab-4701-b1b8-519a311448a3','西昌新亭（句）','吳融','唐','唐诗','tang','','[]','暖漾魚遺子，晴遊鹿引麛。',43,'全唐诗/poet.tang.51000.json','["暖漾魚遺子，晴遊鹿引麛。", "（《唐詩紀事》五八《李洞》（出《唐摭言》卷十《海敍不遇》。", "）。"]'),
('331671b5-0e06-4d4f-938a-fda8474a1684','永和縣上巳','王駕','唐','唐诗','tang','','[]','記得蘭亭祓禊辰，今朝兼是永和春。',72,'全唐诗/poet.tang.51000.json','["記得蘭亭祓禊辰，今朝兼是永和春。", "一觴一詠無詩侶，病倚山窗憶故人。", "（桑世昌《蘭亭考》十二（陸心源《宋詩紀事補遺》卷八八收此詩於事蹟無考作者內。", "）。"]'),
('17142a54-9792-4c05-8a4b-1ac577750288','冬日書黎少府山齋','唐廩','唐','唐诗','tang','','[]','愛此林亭絕，重遊亦似新。',48,'全唐诗/poet.tang.51000.json','["愛此林亭絕，重遊亦似新。", "山秋同鶴過，水落見鳥頻。", "映沼荷全綠，侵簷柳尚春。", "惜哉無別墅，共作白雲人。"]'),
('ca33b9fb-730f-4f2f-aaf2-0bdade8cfd21','雲蓋山泉','唐廩','唐','唐诗','tang','','[]','危嶠高高幾十層，梵王宮裏一泉澄。',65,'全唐诗/poet.tang.51000.json','["危嶠高高幾十層，梵王宮裏一泉澄。", "引來石竇明如玉，瀉落山厨冷似冰。", "淨影不關秋賦客，清音時警夜禪僧。", "從茲渡口潺湲去，勢入滄溟豈可仍。", "。"]'),
('229da854-d5b2-4347-8a5b-1c64ca03438d','題蔡處士居','唐廩','唐','唐诗','tang','','[]','一畝周旋幾十家，舂輪相次好生涯。',99,'全唐诗/poet.tang.51000.json','["一畝周旋幾十家，舂輪相次好生涯。", "鷓鴣近晚啼深竹，鸂𪆟新晴立淺沙。", "沃衍共知多黍稷，寬平仍覺富桑麻。", "當年何事拋耕釣，木笏藍衫兩鬢華。", "（以上《純常子枝語》四十引《萍鄉縣志》（均見同治《萍鄉縣志》卷六。", "）。"]'),
('59f65bab-fdb8-4f28-b8fc-edda2cfb17d5','別家（句）','唐備','唐','唐诗','tang','','[]','兄弟惜分離，揀日皆言惡。',22,'全唐诗/poet.tang.51000.json','["兄弟惜分離，揀日皆言惡。", "（《唐才子傳》九）。"]'),
('547d241f-b244-4fad-89b6-8cc90a506ba5','送友人南中訪舊知','喻坦之','唐','唐诗','tang','','[]','送友人南中訪舊知（《全唐詩》五四三作喻鳧詩。',82,'全唐诗/poet.tang.51000.json','["送友人南中訪舊知（《全唐詩》五四三作喻鳧詩。", "第五句「急」《文苑英華》作「接」○《文苑英華》二八二《送行》（席刻本《喻鳧詩集》不收此詩。", "《全唐詩》收作喻鳧詩恐誤。", "）。"]'),
('95e73ca7-e898-4cf3-aeda-96618ff14f8d','','裴說','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('b1c27d2c-9355-43b5-8ff5-ffd0a95f55cf','上岳守','裴說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','入郭寬萬里，岳陽堪畫圖。',39,'全唐诗/poet.tang.51000.json','["入郭寬萬里，岳陽堪畫圖。", "及窺賢太守，不見洞庭湖。", "（《輿地紀勝》六九《岳州》）。"]'),
('20e0049c-d5d9-4c33-aefc-8d773afd4381','句','裴說','唐','唐诗','tang','','[]','自己情雖切，他人未肯忙。',23,'全唐诗/poet.tang.51000.json','["自己情雖切，他人未肯忙。", "（《老學庵筆記》四）。"]'),
('5ff5ef30-61e7-4ea9-9f90-287e80ba2af7','題建造寺','張爲','唐','唐诗','tang','','[]','疊嶂橫空向郡西，迥然高峭衆山低。',53,'全唐诗/poet.tang.51000.json','["疊嶂橫空向郡西，迥然高峭衆山低。", "樹梢缺處見城郭，日影落時聞鼓鼙。", "（《輿地紀勝》卷一三○《福建路·泉州》）。"]'),
('262f6174-75b5-468b-9af9-3cb67840aa17','宿江館（句）','張爲','唐','唐诗','tang','','[]','吟登晚驛亭，醉罷紅燈落。',68,'全唐诗/poet.tang.51000.json','["吟登晚驛亭，醉罷紅燈落。", "（《詩學指南》四（《吟窗雜錄》卷十四正字王玄《詩中旨格》，「醉罷」作「醮罷」，幷云「此比君子欲仕于明時也」。", "）。"]'),
('b60bd412-a6d1-4788-9da5-cffaf1d81979','','韓氏','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('23667d13-06d2-4331-9e92-8e534f984f07','得于祐題詩後又作詩','韓氏','唐','唐诗','tang','','[]','獨步天溝岸，臨流得葉時。',24,'全唐诗/poet.tang.51000.json','["獨步天溝岸，臨流得葉時。", "此情誰會得？腸斷一聯詩。"]'),
('5fdb6be0-0a71-447d-8c3c-0ecb271acf77','婚宴席上索筆爲詩','韓氏','唐','唐诗','tang','','[]','一聯佳句題流水，十載幽思滿素懷。',279,'全唐诗/poet.tang.51000.json','["一聯佳句題流水，十載幽思滿素懷。", "今日却成鸞鳳友，方知紅葉是良媒。", "（《青瑣高議前集》（均見《青瑣高議前集》卷五引張實《流紅記》。", "按紅葉題詩故事，唐詩已有數傳，《雲溪友議》卷下記顧況與天寶宮人、盧渥與宣宗宮人事，《本事詩》亦載顧況事，《北夢瑣言》卷九作李茵與雲芳子事，《全唐詩》卷七九九又有賈全虛與鳳兒事。", "《流紅記》即張實據以上故事敷衍而成的小說。", "《苕溪漁隱業話後集》卷十六云：「《青瑣》乃互竄二事，合爲一傳，曰《流紅記》，仍託他人姓名。", "嗚呼，孰謂小說可盡信乎！」龐元英《談藪》亦謂此篇「最爲鄙妄」。", "宋人對小說的鄙夷雖不足取，但此篇爲宋人依說，當可據以論定。", "）。"]'),
('2cb8ff95-ee73-4a41-b816-21b45b34e398','觀夢龜草書','可朋','唐','唐诗','tang','','[]','欲盡金鍾數斗餘，從容攘臂立踟躕。',85,'全唐诗/poet.tang.51000.json','["欲盡金鍾數斗餘，從容攘臂立踟躕。", "先教侍者濃磨墨，不揖傍人欻便書。", "畫狀倒松橫洞壑，點麄飛石落空虛。", "興來抹亦成字，祇恐張顛顛不如。", "（《六藝之一錄》二九四引陳思《書苑菁華》）。"]'),
('0be794d8-72f0-42da-bf24-9b38783ab63c','岳陽悼賈島（《全唐詩》七六八作安錡《題賈島墓》，末一字「忡」，《鑑誡錄》作「㤏」）（崔錡評事倅岳陽日，爲詩悼賈島。岳是，普州地名。今因創墓在岳陽山上，山下有岳陽池。○《鑑誡錄》八《賈忤旨》）','崔錡','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('7decc698-68b9-4765-aa4b-aeaec2008508','水（《文苑英華》又有《柳》、《松》二首，《全唐詩》均作韓溉，應別出互見。）','韓喜','唐','唐诗','tang','','[]','方圓不定性空求（柔），東注滄溟早晚休。',157,'全唐诗/poet.tang.51000.json','["方圓不定性空求（柔），東注滄溟早晚休。", "高截碧塘長耿耿，遠飛青嶂更悠悠。", "瀟湘月浸千年色，夢澤煙含萬古愁。", "別有嶺頭鳴咽處，爲君分（更）作斷腸流。", "（《文苑英華》一六三《地部》。", "又《詩話總龜》二一《詠物門》引《續末流事詩》）（〖1〗《全唐詩》卷六七一唐彥謙有《逢韓喜》詩，知韓喜爲唐末人。", "原列入「無世次」作者，今移此。", "）。"]'),
('89c44187-cfe9-45f2-bf69-8ee65f2f33fc','見人衣鮮華作詩','歸處訥','唐','唐诗','tang','','[]','昂藏騎馬出朱門，服色鮮華不可論。',32,'全唐诗/poet.tang.51000.json','["昂藏騎馬出朱門，服色鮮華不可論。", "盡是殺人方始得，一絲絲上有冤魂。"]'),
('61a05fd0-cc0a-433c-b5d6-e00f79ebb2f4','詠虺漢（黃巢犯京後，守亮、守信等悉爲楊軍容復恭義兒，勢奪諸侯，亦一時之威也。歸有不平之色詠虺漢以刺之曰：）','歸處訥','唐','唐诗','tang','','[]','草頭灰面惡形儀，盡是軍容表裏兒。',64,'全唐诗/poet.tang.51000.json','["草頭灰面惡形儀，盡是軍容表裏兒。", "昔日水牛攀角上，而今細馬劈腰騎。", "錢多內藏猶嫌少，位等三公尚厭卑。", "更有一般堪笑處，鍍金牙齒咬銀匙。"]'),
('0c96f9a8-c8a5-4f78-b27e-41b01c57735f','詠奸漢','歸處訥','唐','唐诗','tang','','[]','輕脣利舌傍侯門，送諂承顏日月新。',64,'全唐诗/poet.tang.51000.json','["輕脣利舌傍侯門，送諂承顏日月新。", "愛與大官添弟子，能將小藥獻夫人。", "秤頭不放分毫過，對面常如割骨貧。", "更有一般奸太曬，聚錢唯趁買金銀。"]'),
('58238acf-eb20-4745-93e5-3b5980b40b8b','代村婦詠邊將','歸處訥','唐','唐诗','tang','','[]','紫袍金帶不須誇，動便經年鎮海涯。',32,'全唐诗/poet.tang.51000.json','["紫袍金帶不須誇，動便經年鎮海涯。", "爭似我家田舍壻，朝驅牛去暮還家。"]'),
('2519b296-a88e-4ac8-ba24-24d45692c977','詠石校書（欽若）（石校書，本東川人。文章四六，與王超齊名。天復初應舉，值大駕東遷，蜀路不心目，干戈繼起，遂客寄天水，荏苒一紀有餘。後知父亡，方乃舉慟，廣於寺院追薦懺罪而已。歸與石遽因小隟，荼毒詠之。石氏聲名，因茲減價。詩曰：）','歸處訥','唐','唐诗','tang','','[]','十二年來匿父喪，三年之罪遣誰當。',48,'全唐诗/poet.tang.51000.json','["十二年來匿父喪，三年之罪遣誰當。", "如今追薦應無益，已被牛頭煮幾場。", "（以上《鑑誡錄》十《歸生刺》）。"]'),
('dbf99ca3-cfab-4da5-86ee-b126bf7b270d','游四頂山（《方輿勝覽》：四頂用在合肥縣東南。《寰宇記》作四鼎，《郡國志》云：魏伯陽煉丹之所。）','張彥修〖1〗','唐','唐诗','tang','','[]','翠巒齊聳壓平湖，晚綠朝紅畫不如。',147,'全唐诗/poet.tang.51000.json','["翠巒齊聳壓平湖，晚綠朝紅畫不如。", "寄詩紀商山閑四皓，好來各占一峰居。", "（《光緒重修廬州府志》六《山川志》上〖2〗）（〖1〗《新唐書》卷七二下《宰相世系表》二下河東張氏有彥修，爲憲宗朝宰相已經弘靖之孫，河南少尹張嗣慶之子。", "據張忱石考證，彥修當爲文宗至僖宗時人。", "〖2〗見《輿地紀勝》卷四五《廬州》。", "）。"]'),
('a6ba3730-7b24-4f01-a713-5a7b8d2b3fa5','羅浮','小白','唐','唐诗','tang','','[]','危閣閒登思渺漫，九天如在掌中看。',32,'全唐诗/poet.tang.51000.json','["危閣閒登思渺漫，九天如在掌中看。", "遊人莫著單衣去，六月飛雲帶雪寒。"]'),
('1c65bbae-8811-4f1f-af61-165a16b248a4','中閣','小白','唐','唐诗','tang','','[]','棱層高閣倚巖扃，俯瞰塵仰摘星。',45,'全唐诗/poet.tang.51000.json','["棱層高閣倚巖扃，俯瞰塵仰摘星。", "晝夜泉聲混天樂，遊人好向靜中聽。", "（以上《羅浮志》十《詩》）。"]'),
('c698d32b-5ca3-47d0-92c5-db1c530b0e0a','宿金庭觀（在嵊縣東南七十二里）','小白','唐','唐诗','tang','','[]','羽客相留宿上方，金庭風月冷如霜。',174,'全唐诗/poet.tang.51000.json','["羽客相留宿上方，金庭風月冷如霜。", "直饒人世三千歲，未抵仙家一夜長。", "（《嘉慶浙江通志》二三一《寺觀》〖2〗）（〖1〗《增廣聖宋高僧詩選後集》卷上收秀登《送小白上人歸華頂》、《送貫微歸天台》等詩，齊己《白蓮集》中有寄贈貫微詩多首，因知小白亦應爲齊己同時人。", "〖參《全唐詩續拾》卷四一〗原列入時代未詳僧，今移此。", "〖2〗見宋高似孫《剡錄》卷八，參前張說條。", "）。"]'),
('fb2a7e0d-31cf-4407-8678-2bceaf7e1930','贈樊川長老','清尚〖1〗','唐','唐诗','tang','','[]','贈樊川長老（《全唐詩》八二五作可止詩○《瀛奎律髓》四七《釋梵類》〖2〗）（原列無世次作者。',108,'全唐诗/poet.tang.51000.json','["贈樊川長老（《全唐詩》八二五作可止詩○《瀛奎律髓》四七《釋梵類》〖2〗）（原列無世次作者。", "今檢齊己《白蓮集》卷三有《覽清尚卷》，知爲唐末人，故移此。", "〖2〗另《唐詩紀事》卷七七作可止詩，《唐僧弘秀集》卷十作清尚詩。", "）。"]'),
('77c49aec-7a40-4cd8-a4d8-fb90f1abc406','詠石硯','李琪','唐','唐诗','tang','','[]','遠來柯嶺外，近到玉堂間。',50,'全唐诗/poet.tang.51000.json','["遠來柯嶺外，近到玉堂間。", "乍琢文猶澀，新磨墨尚慳。", "不能濡大筆，何要別秋山。", "（《文房四譜》三《硯譜》）。"]'),
('1f525451-3a15-4d7c-b4d9-75df41f09bdb','梁宗廟樂舞辭（《舊五代史·樂志》曰：「梁開平初，太祖受禪，始建宗廟，凡四室，每室有登歌、酌獻之舞：肅祖宣元皇帝室曰《大合之舞》，敬祖光獻皇帝室曰《象功之舞》，憲祖昭武皇帝室曰《來儀之舞》，烈祖文穆皇帝室曰《昭德之舞》，登歌樂章各一首。」《五代會要》七《廟樂》曰：「太常少卿楊煥撰。」）','楊煥','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('41d90904-f630-4898-8b88-7f0545d0b1a1','梁宗廟樂舞辭（《舊五代史·樂志》曰：「梁開平初，太祖受禪，始建宗廟，凡四室，每室有登歌、酌獻之舞：肅祖宣元皇帝室曰《大合之舞》，敬祖光獻皇帝室曰《象功之舞》，憲祖昭武皇帝室曰《來儀之舞》，烈祖文穆皇帝室曰《昭德之舞》，登歌樂章各一首。」《五代會要》七《廟樂》曰：「太常少卿楊煥撰。」） 大合舞（獻肅祖）','楊煥','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('aa1b6549-2ecd-4f35-85fe-fd4ef8fb088b','梁宗廟樂舞辭（《舊五代史·樂志》曰：「梁開平初，太祖受禪，始建宗廟，凡四室，每室有登歌、酌獻之舞：肅祖宣元皇帝室曰《大合之舞》，敬祖光獻皇帝室曰《象功之舞》，憲祖昭武皇帝室曰《來儀之舞》，烈祖文穆皇帝室曰《昭德之舞》，登歌樂章各一首。」《五代會要》七《廟樂》曰：「太常少卿楊煥撰。」） 象功舞（獻敬〖恭〗祖）','楊煥','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('94ad739b-5434-4150-9f2d-1862a3baffee','梁宗廟樂舞辭（《舊五代史·樂志》曰：「梁開平初，太祖受禪，始建宗廟，凡四室，每室有登歌、酌獻之舞：肅祖宣元皇帝室曰《大合之舞》，敬祖光獻皇帝室曰《象功之舞》，憲祖昭武皇帝室曰《來儀之舞》，烈祖文穆皇帝室曰《昭德之舞》，登歌樂章各一首。」《五代會要》七《廟樂》曰：「太常少卿楊煥撰。」） 來儀舞（獻憲祖）','楊煥','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('cea441db-70dc-45ed-8cd5-2416b9089393','梁宗廟樂舞辭（《舊五代史·樂志》曰：「梁開平初，太祖受禪，始建宗廟，凡四室，每室有登歌、酌獻之舞：肅祖宣元皇帝室曰《大合之舞》，敬祖光獻皇帝室曰《象功之舞》，憲祖昭武皇帝室曰《來儀之舞》，烈祖文穆皇帝室曰《昭德之舞》，登歌樂章各一首。」《五代會要》七《廟樂》曰：「太常少卿楊煥撰。」） 昭德舞（獻烈祖○《樂府詩集》十二。詩見《全唐詩》十六《郊廟歌辭》）','楊煥','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('183250ef-f7b0-476a-953d-4f8ccee11a88','致李深之（鄭舉舉，巧談諧，常有名賢醵宴。乾符中，狀元孫偓頗惑之，與同年數人，多在其舍。一日，同年宴，而舉舉有疾不來，遂令同年李深之邀爲酒糾。坐久，狀元乃吟一篇曰：）','孫偓','唐','唐诗','tang','','[]','南行忽見李深之，手舞如蜚令不疑。',230,'全唐诗/poet.tang.51000.json','["南行忽見李深之，手舞如蜚令不疑。", "任爾風流兼蘊藉，天生不似鄭都知。", "（曲內妓之頭角者都知。", "《北里志》（陶敏云此詩《全唐詩》卷七一五收作劉崇魯《席上吟》。", "並謂《北里志》云：「今左史劉郊文崇及第年亦惑於舉舉，同年宴而舉舉有疾不來，其年酒糾多非舉舉，遂令同年李深之邀爲酒糾，坐久，覺狀元微哂，良久乃詠一篇曰……」文中之新的郊文崇即劉崇魯，字郊文，文中脫一「魯」字。", "文云「覺狀元微哂，良久乃詠一篇」，則「覺」與「詠」者均劉崇魯。", "謂詩乃狀元孫偓作，似于理未安。", "陶說可參。", "）。"]'),
('07117985-0603-4fbf-a1dc-5d452dc15a82','答崔素娥（《全唐詩》名媛有崔素娥《別韋洵美詩》，韋詩以小字附後。）','韋洵美','唐','唐诗','tang','','[]','別恨商羣離羣自古聞，此心難捨意難論。',95,'全唐诗/poet.tang.51000.json','["別恨商羣離羣自古聞，此心難捨意難論。", "承恩必若頒時服，莫使霑濡有淚痕。", "（《全五代詩》八詳引《侍兒小名錄》（韋洵美二詩，皆出自《燈下閑談》卷下《行者雪怨》。", "「離羣」，《燈下閑談》作「離情」。", "）。"]'),
('e3b9ffbf-b4a7-4bfb-9b30-5c2f1c37c421','假僧榻悶吟','韋洵美','唐','唐诗','tang','','[]','門壁紛紛蟋蟀聲，背燈欹枕夢難成。',68,'全唐诗/poet.tang.51000.json','["門壁紛紛蟋蟀聲，背燈欹枕夢難成。", "人間有此不平事，何處人能報不平。", "（《萬首唐人絕句》四十《鬼詩》）（「紛紛」，《燈下閑談》作「忙忙」。", "）。"]'),
('243b14e4-6e0d-4478-8ec1-889e6c1e439b','答杜荀鶴（句）（杜荀鶴贈詩云：「祇恐爲僧心不了，爲僧心了總輪僧。」瀾答詩云：）','清瀾','唐','唐诗','tang','','[]','如何即是僧心了，了得何心是了僧？',55,'全唐诗/poet.tang.51000.json','["如何即是僧心了，了得何心是了僧？", "（《輿地紀勝》二十《徽州·仙釋》。", "又見弘治《徽州府志》十。", "又康熙《志》十八）。"]'),
('6fafd067-db3b-4965-8620-2ed9f8b523ad','上張相（石晉時，張相從恩自南院宣徽使官才檢校司徒權西京留守。到洛陽後未久，少師自東京得假，往洛陽數日，寄上張相云云。張公知世其貧，贈遺甚厚。）','楊凝式','唐','唐诗','tang','','[]','南院司徒鎮洛京，未經三月政聲成。',75,'全唐诗/poet.tang.51000.json','["南院司徒鎮洛京，未經三月政聲成。", "四方羣后皆如此，端坐庸夫見太平。", "（《全五代詩·補遺》引《洛陽縉紳舊聞記》）（見《洛陽縉紳舊聞記》卷一《少師佯狂》。", "）。"]'),
('6257f8a2-1520-4525-b5c9-52a46d66f403','詠橘（莊宗小酌，進新橘，命諸伶詠之。唐朝美詩先成云云。帝大笑，賜所御軟金杯。）','唐朝美','唐','唐诗','tang','','[]','金香大丞相，兄弟八九人。',41,'全唐诗/poet.tang.51000.json','["金香大丞相，兄弟八九人。", "剝皮去滓子，若箇是汝身。", "（《全五代詩》九引《清異錄》二）。"]'),
('de65e344-0b40-4043-bff5-bcddd0e6dede','洋川','和凝','唐','唐诗','tang','','[]','自陪台斾到洋川，兩載優遊漢水邊。',71,'全唐诗/poet.tang.51000.json','["自陪台斾到洋川，兩載優遊漢水邊。", "官閒最好遊僧舍，江近應須買釣船。", "更待浹旬無事後，遍題清景作詩仙。", "（此處拼合未妥，另詳《全唐詩續拾》卷四二。", "）。"]'),
('924e4ea2-53cf-416d-8302-5b9cc5bbb009','題真符縣（句）','和凝','唐','唐诗','tang','','[]','雖有黃金額，其如赤子貧。',30,'全唐诗/poet.tang.51000.json','["雖有黃金額，其如赤子貧。", "（以上《輿地紀勝》一九○《洋州》）。"]'),
('03850290-0ad6-4343-acd1-b2f9bed1bf79','','陶晟','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('ace51e9a-adf6-42fd-a16d-4d39dc238549','句','陶晟','唐','唐诗','tang','','[]','河經蕃地濁，山到漢家青。',12,'全唐诗/poet.tang.51000.json','["河經蕃地濁，山到漢家青。"]'),
('202d15fc-1a1a-471e-99ca-603e9696cf20','句','陶晟','唐','唐诗','tang','','[]','擬拋丹禁去，試著白衣看。',71,'全唐诗/poet.tang.51000.json','["擬拋丹禁去，試著白衣看。", "（以上《全五代詩補遺》引《洛陽縉紳舊聞記》）（見《洛陽縉紳舊聞記》卷一《陶副車求薦見忌》，後二句爲「在環衛時詩」。", "）。"]'),
('527e515b-c0de-4781-8ee0-8f466d10f573','舌','馮道','唐','唐诗','tang','','[]','口是禍之門，舌是斬身刀。',107,'全唐诗/poet.tang.51000.json','["口是禍之門，舌是斬身刀。", "閉口深藏舌，安身處處牢。", "（《古今圖書集成·人事典》一四《口部》）（見宋胡穉《增廣箋注簡齋詩集》卷四《寄新息家叔》注引。", "《群書通要丙集》卷一引前二句。", "《喻世明言》卷三十八引此詩，不云作者。", "）。"]'),
('1231e1da-fa00-4591-a034-dce138c6c7d9','透明巖（亦名棲真巖，在大蓬山，前視空曠，俯瞰縣郭。天氣清明，渠、達諸山，隱隱可數。縣令李九齡詩云云。〖李九齡爲宋初乾德間進士，其任縣令，當在登第後。〗）','李九齡','唐','唐诗','tang','','[]','乍脫塵埃夢寐安，透明巖上一開顏。',67,'全唐诗/poet.tang.51000.json','["乍脫塵埃夢寐安，透明巖上一開顏。", "晚霞收處似聞雁，遠目盡時猶有山。", "仙跡不隨巖桂花，禪心長共嶺雲閑。", "（《輿地紀勝》一八八《蓬州·景物》）。"]'),
('a22c54cd-5e59-4df5-953e-7b318f5ded3b','句（度，工詩，有句云云，人多誦之。王朴爲樞密，止以此一聯薦於申文炳知舉，遂擢爲第三。人嘲曰：「主司只誦一聯詩。」）','李度','唐','唐诗','tang','','[]','醉輕浮世事，老重故鄉人。',22,'全唐诗/poet.tang.51000.json','["醉輕浮世事，老重故鄉人。", "（《玉壺清話》七）。"]'),
('a6db25ea-ccab-4e82-acc5-899ddf453900','','田敏','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('c8860747-dd75-4cc0-8bdd-0ef6f38cbf2a','明德舞（後周宗廟樂舞辭。太祖廟堂）','田敏','唐','唐诗','tang','','[]','《五代會要》七《廟樂》曰：「太祖聖神齒數肅文武孝皇帝廟室酌獻舞《明德之舞》，登歌樂章一首，太常卿田敏撰。',190,'全唐诗/poet.tang.51000.json','["《五代會要》七《廟樂》曰：「太祖聖神齒數肅文武孝皇帝廟室酌獻舞《明德之舞》，登歌樂章一首，太常卿田敏撰。", "（參《舊五代史》一四四《樂志》）」惟彼岐陽，德大流光。", "載造周室，澤及遐荒。", "於鑠聖祖，上帝是皇。", "迺聖迺神，知微知章。", "新廟弈弈，豐年穰穰。", "取彼血膋，以往烝嘗。", "黍稷惟聲，籩豆大房。", "工祝致告，受福無疆。", "（《樂府詩集》十二《郊廟歌辭》）（《全唐詩》卷十六《郊廟歌辭》收入，不署作者。", "）。"]'),
('8791ae3b-5795-4408-8336-207938f91270','瘞筆磚文（趙光逢薄遊襄漢，濯足溪上，見一方磚碑，上題字云云。獨孤貞節立。磚後積土如盎，微有苔蘚，蓋好事者瘞筆所在。）','獨孤貞節','唐','唐诗','tang','','[]','禿友退鋒郎，功成鬢髮傷。',33,'全唐诗/poet.tang.51000.json','["禿友退鋒郎，功成鬢髮傷。", "冢頭封馬鬣，不敢負恩光。", "（《清異錄》四）。"]'),
('c35f67bf-56c1-420c-b94a-14d3f277ecc2','','陶穀','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('41ee4606-5219-4573-9b79-ada4b2e5acc1','春（一作「風」）光好（今按：《全宋詞》亦未收，故補之）（穀爲學士，奉使。恃上國勢，下視江左，辭色毅然不可犯。韓熙載命歌妓秦弱蘭詐爲驛卒女，每日敝衣持帚灑掃，陶悅之，與狎，因贈一詞，名《春光好》云云。明日，後〖一作中〗主設宴于澄心堂，陶辭色如前。乃命弱蘭歌前闋勸酒，陶大醉，爲主禮所薄，即日還朝，止遣數小吏餞于郊亭。迨歸京，鸞膠之曲已喧，陶因是竟不大用。）','陶穀','唐','唐诗','tang','','[]','好因緣，惡因緣，奈何天，只得郵亭一夜眠，別神仙。',296,'全唐诗/poet.tang.51000.json','["好因緣，惡因緣，奈何天，只得郵亭一夜眠，別神仙。", "琵琶撥盡相思調，知音少。", "待（一作「安」）得鸞膠續斷絃，是何年？", "（《玉壺清話》四，參《南唐近事》二）（〖1〗此詞異說較多，舉其要者有五說：一、陶穀於周世宗時使江南贈韓熙載歌妓秦弱蘭之作，見《南唐近事》卷二。", "《苕溪漁隱業話後集》卷四十引《靖康緗素雜記》事同，但不云作詞。", "二、時在入宋後，事同，見《冷齋夜話》及《玉壺清話》。", "三、陶穀乾興中何吳越時贈任社娘之作，見沈遼《雲巢編》卷八《任社娘傳》，《研北雜志》引其說。", "四、陶穀使錢唐日贈驛女詞，見《苕溪漁隱業話前集》卷二四引《本事曲》。", "五、曹翰使江南娼妓詞，見前書引《江南野錄》。", "以孰爲是，尚俟考詳。", "）。"]'),
('98113bdb-7c2e-40e5-93ed-7245eeb7f918','獻詩吳越王（句）','陶穀','唐','唐诗','tang','','[]','陶穀又嘗奉使兩浙，獻詩二十韻於錢俶，其末云云。',83,'全唐诗/poet.tang.51000.json','["陶穀又嘗奉使兩浙，獻詩二十韻於錢俶，其末云云。", "時穀官是丞郎，職爲學士，奉命小邦，獻詩已是失體，復有掃門之句，何辱命之甚也。", "此生頭已白，無路掃王門。", "（《國老談苑》一）。"]'),
('f1688f7d-589f-40e0-872d-156be2bf236c','','張振祖','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('acab50ca-daef-442b-aa67-ae9337669c40','句（沙門愛英，住池陽村，示人之語曰：「萬論千經，不如無念無營。」因郡娼滿瑩娘，多姿而富情，真妓女中麟鳳。進士張振祖以無念無營，有情有色，製一聯云：）','張振祖','唐','唐诗','tang','','[]','門前草滿無無老，牀底錢多有有娘。',91,'全唐诗/poet.tang.51000.json','["門前草滿無無老，牀底錢多有有娘。", "（「錢多」，上引二本作「花多」。", "）（《清異錄》一）（〖1〗張振祖，《惜陰軒業書》本《清異錄》卷上、原本《說郛》卷六一引《清異錄》，皆作「湯振祖」。", "）。"]'),
('a4bae63d-af38-406b-9b12-afc37bfb38a0','飛龍磵飲茶（句）','胡嶠','唐','唐诗','tang','','[]','沾牙舊姓餘甘氏，破睡當封不夜侯。',25,'全唐诗/poet.tang.51000.json','["沾牙舊姓餘甘氏，破睡當封不夜侯。", "（《清異錄》四）。"]'),
('333d1f25-fa37-4f06-af88-8dd20aa5d3e0','朗吟（河陽釋法常，性英爽，酷嗜酒，無寒暑陰雨常醉，醉即熟睡，覺即朗吟曰：）','法常','唐','唐诗','tang','','[]','優遊麯世界，爛熳枕神仙。',21,'全唐诗/poet.tang.51000.json','["優遊麯世界，爛熳枕神仙。", "（《清異錄》四）。"]'),
('ace640ee-a412-4be3-a7c7-9ef65441393d','湯戲（注湯幻茶）（饌茶而幻出物象于湯面者，茶匠通神之藝也。沙門福全生于金鄉，長于茶海，能注湯幻茶成一句詩，並點四甌。共一絕句，泛乎湯表，小小物類，唾手辦耳。檀越日造門求觀湯戲，全自詠曰：）','福全','唐','唐诗','tang','','[]','生成盞裏水丹青，巧畫工夫學不成。',41,'全唐诗/poet.tang.51000.json','["生成盞裏水丹青，巧畫工夫學不成。", "却笑當時陸鴻漸，煎茶贏得好名聲。", "（《清異錄》四）。"]'),
('28ba0956-2918-456b-9e40-08263d6f0f3a','詩（句）（《類說》卷十二引《紀異錄》云：龔林有卷投和凝，《登太行山詩》云：「『但得路可上，更高人也行。』」可據以補題。《紀異錄》，全名《洛中紀異錄》，宋秦再思撰。）','龔霖','唐','唐诗','tang','','[]','但有路可上，更高人也行。',23,'全唐诗/poet.tang.51000.json','["但有路可上，更高人也行。", "（《老學庵筆記》四）。"]'),
('3127c30f-65da-41e1-8a3a-3c784d6e50fb','','張文伏','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('3a489108-57ab-4a10-a0a5-f3b584980caa','蒼嶺','張文伏','唐','唐诗','tang','','[]','絕壁不可攀，懸崖不可下。',64,'全唐诗/poet.tang.51000.json','["絕壁不可攀，懸崖不可下。", "路險心自平，由來無取舍。", "穩穩須教著步行，前途荆棘胡從生？", "（《古今圖書集成·山川典》一二○《括蒼山部》）。"]'),
('a55b9a79-77f0-413e-a05d-3e8bdb729d57','渡江（〖1〗《十國春秋》三。前四句引《江表志》，後四句引《五國故事》。吳任臣按：《南唐書》此李後主詩也，後人誤以爲吳睿帝作。〖2〗《全唐詩》八作南唐後主李煜詩，題下注云：《江表志》作吳讓皇楊溥詩，題作《泰州永寧宮》。第四句「殿」，《十國春秋》作「榭」，第五、六二句爲「煙凝楚岫愁千點，雨滴吳江淚萬行。」末句「閒坐」作「端坐」。〖3〗此詩，鄭文寶《江表志》卷上、佚名《江南餘載》卷下、佚名《五國故事》卷上作吳讓皇楊溥作，三書皆宋初人著，鄭文寶先仕南唐後入宋；龍衮《江南野錄》卷三、馬令《南唐書》卷五作李','楊溥','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('02ba19c8-5e5f-4649-81f4-19273a252197','樓上看九華（三首） 一','殷文圭','唐','唐诗','tang','','[]','九朵連雲勢欲騰，鳥飛難到最高層。',33,'全唐诗/poet.tang.51000.json','["九朵連雲勢欲騰，鳥飛難到最高層。", "誰家寫在屏風上，巖下松間盡九僧。", "。"]'),
('df1d2703-736a-4bbb-8016-cf6bc0675e94','樓上看九華（三首） 二','殷文圭','唐','唐诗','tang','','[]','九條寒玉罩雲中，雨外霞分海日紅。',32,'全唐诗/poet.tang.51000.json','["九條寒玉罩雲中，雨外霞分海日紅。", "疑是巧人新畫出，與他天柱作屏風。"]'),
('030a2cfc-f1bf-4c48-bba7-511d60550f6b','樓上看九華（三首） 三','殷文圭','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','四顧巒峯峭莫羣，翠峯長與曉光分。',58,'全唐诗/poet.tang.51000.json','["四顧巒峯峭莫羣，翠峯長與曉光分。", "盡分明處要清白，獨倚青天絕片雲。", "（《嘉靖池州府志》八。", "又《九華山志》八有一三兩首）。"]'),
('f4dbad26-1e83-4daa-a2df-1acfa619eba2','歌（二章）（高祖行密改元開國時，廣陵殷盛，士庶駢闐。道人狀如病狂，手持一竿，竿頭懸一木，刻爲鯉魚形，行歌於市云云。其類此意者，凡數十章，時人莫能曉。後徐知誥禪代，復姓李氏，其言始應。） 一','黃冠道人','唐','唐诗','tang','','[]','盟澤鯉魚肉爲角，濠梁鯉魚金刻鱗。',32,'全唐诗/poet.tang.51000.json','["盟澤鯉魚肉爲角，濠梁鯉魚金刻鱗。", "盟津鯉魚死欲盡，濠梁鯉魚始驚人。"]'),
('80261c65-cd1a-4309-a61e-686f2af4f24e','歌（二章）（高祖行密改元開國時，廣陵殷盛，士庶駢闐。道人狀如病狂，手持一竿，竿頭懸一木，刻爲鯉魚形，行歌於市云云。其類此意者，凡數十章，時人莫能曉。後徐知誥禪代，復姓李氏，其言始應。） 二','黃冠道人','唐','唐诗','tang','','[]','橫排三十六條鱗，個個圓如紫磨真。',70,'全唐诗/poet.tang.51000.json','["橫排三十六條鱗，個個圓如紫磨真。", "爲甚竿頭挑着定，世間難遇識魚人。", "（《十國春秋·吳》十二。", "又《全五代詩》二十三轉引）（〖1〗見《釣磯立談》）。"]'),
('96484dbf-da5f-48aa-99fb-1a22523191cc','應天長（〖1〗後主云：「先皇御製歌詞。」墨蹟在晁公留家○王國維輯《南唐二主詞》。今按：《全唐詩》八八九作李煜詞。）','李璟','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('f0f5f9e4-fe6a-469e-b9e3-1248e19d1669','金銅蟾蜍硯滴銘','李煜','唐','唐诗','tang','','[]','捨月窟，伏棐几，爲我用，貯清泚。',163,'全唐诗/poet.tang.51000.json','["捨月窟，伏棐几，爲我用，貯清泚。", "端溪石，澄心紙，陳玄氏，毛錐子。", "微我潤澤烏用汝，同列無譁聽驅使。", "（《五代詩話》一）（〖1〗此則見鄭方坤《五代詩話》卷十，原出元陸友《研北雜志》卷下，云「李仲芳家有南唐金銅蟾蜍硯滴，重厚奇古，磨滅處金色愈明，非近世塗金比也。", "腹下有篆銘」云云。", "銘文末二句原書互乙，似失韻。", "此歸李煜名下，無確據。", "）。"]'),
('6f14aae7-6e14-408b-82c1-b7d0c75c8f7b','子夜歌（《全唐詩》八九九詞句只存首二句，題作《菩薩蠻》）','李煜','唐','唐诗','tang','','[]','尋春須是先春早，看花莫待花枝老。',109,'全唐诗/poet.tang.51000.json','["尋春須是先春早，看花莫待花枝老。", "縹色玉柔擎，醅浮盞面清。", "何妨頻笑粲，禁苑春歸晚。", "同醉與閒平（一作「評」），詩隨羯鼓成。", "（南詞本注。", "參《歷代詩餘》）（〖1〗《歷代詩餘》卷九收此詞，調屬《菩薩蠻》，「羯鼓」作「疊鼓」。", "）。"]'),
('e5c37df8-fb65-47cd-bf24-54e53b6b5b25','謝新恩（六首） 一','李煜','唐','唐诗','tang','','[]','秦樓不見吹簫女，空餘上苑風光。',68,'全唐诗/poet.tang.51000.json','["秦樓不見吹簫女，空餘上苑風光。", "粉英含蕊自低昂。", "東風惱我，纔發一襟香。", "瓊窗夢□留殘日，當年得恨何長。", "碧闌干外映垂楊。", "暫時相見，如夢懶思量。"]'),
('d17be52e-bcd6-4c06-9ddc-85fefc62a6ee','謝新恩（六首） 二','李煜','唐','唐诗','tang','','[]','櫻花落盡階前月，象牀愁倚薰籠。',51,'全唐诗/poet.tang.51000.json','["櫻花落盡階前月，象牀愁倚薰籠。", "遠似去年今日恨還同。", "雙鬟不整雲憔悴，淚沾紅抹胸。", "何處相思苦？", "紗窗醉夢中。"]'),
('f19078e3-94dd-4f66-a1c1-888ca22e171e','謝新恩（六首） 五','李煜','唐','唐诗','tang','','[]','櫻花落盡春將困，秋千架下歸時。',52,'全唐诗/poet.tang.51000.json','["櫻花落盡春將困，秋千架下歸時。", "漏暗（疑作「滿階」）斜月遲遲，花在枝。", "（缺二十字）徹曉紗窗下，待來君不知。"]'),
('54890b82-cf00-4c9f-8d96-6635b3f5b8f7','謝新恩（六首） 六','李煜','唐','唐诗','tang','','[]','冉冉秋[光]（色）留不住，滿階紅葉暮。',101,'全唐诗/poet.tang.51000.json','["冉冉秋[光]（色）留不住，滿階紅葉暮。", "又是過重陽，臺榭登臨處。", "茱萸花墜，紫菊氣，飄庭戶，[晚]烟籠細[雨]（細）。", "嗈嗈新雁咽寒聲，愁恨年年長相似。", "（以上南詞本注）（〖1〗據詹安泰《李璟李煜詞》校改。", "）。"]'),
('637eefcb-d15c-4959-9651-27090271b1bd','娼樓行（句）','王貞白','唐','唐诗','tang','','[]','龍腦香調水，教人染退紅。',23,'全唐诗/poet.tang.51000.json','["龍腦香調水，教人染退紅。", "（《老學庵續筆記》）。"]'),
('e445b3be-12db-44f7-9132-9480e0046fe5','莫思歸（即《拋球樂》）','馮延巳','唐','唐诗','tang','','[]','花滿名園酒滿觴，且開笑口對穠芳。',56,'全唐诗/poet.tang.51000.json','["花滿名園酒滿觴，且開笑口對穠芳。", "秋千風暖鸞釵嚲，綺陌春深翠袖香。", "莫惜黃金貴，日日須教貰酒嘗。", "（《花草粹編》一）。"]'),
('f1fefbe4-af8e-46b4-95f4-68c4b6be63b4','采春子','馮延巳','唐','唐诗','tang','','[]','櫻桃謝了梨花發，紅白相催。',84,'全唐诗/poet.tang.51000.json','["櫻桃謝了梨花發，紅白相催。", "燕子歸來，幾處香風綠戶開。", "人生樂事知多少，且酌金杯。", "管咽弦哀，慢引蕭娘舞袖迴。", "（《萬代詩餘》）（〖1〗見《歷代詩餘》卷十，調屬《采桑子》。", "）。"]'),
('befd8155-bdef-4d9c-9777-14f18eff22b0','玉樓春','馮延巳','唐','唐诗','tang','','[]','雪雲乍變春雲簇，漸覺年華堪縱目。',95,'全唐诗/poet.tang.51000.json','["雪雲乍變春雲簇，漸覺年華堪縱目。", "北枝梅蕊犯寒開，南浦波紋如酒綠。", "芳菲次第長相續，自是情多何處足。", "尊前百計得春歸，莫爲傷春眉黛蹙。", "（《尊前集》）（〖1〗此詞又見《歐陽文忠公近體樂府》卷二。", "）。"]'),
('878c403d-a570-430f-a554-c4e74b04ff6c','感懷','潘佑','唐','唐诗','tang','','[]','幽禽喚杜宇，宿蝶夢莊周。',53,'全唐诗/poet.tang.51000.json','["幽禽喚杜宇，宿蝶夢莊周。", "席地一尊酒，思與元化浮。", "但莫孤明月，何必秉燭游。", "（〖1〗見《法藏碎金錄》卷六。", "）。"]'),
('77e619f1-1f50-4f84-b78a-0c7ab42a62fc','獨坐（句）','潘佑','唐','唐诗','tang','','[]','凝神入混茫，萬象成空虛（一作「萬有成虛空」。',101,'全唐诗/poet.tang.51000.json','["凝神入混茫，萬象成空虛（一作「萬有成虛空」。", "）（《詩話總龜後集》四三《釋氏門》引《法藏碎金》。", "又《全五代詩》三一引）（〖1〗《法藏碎金錄》卷七收二句，作「凝神入混沌，萬法成虛空」。", "同書卷六錄前一句。", "）。"]'),
('f6cf8f52-91bf-473d-9bdf-34a64df18692','愛敬寺（句）','李建勳','唐','唐诗','tang','','[]','雲散經窗濕，山晴石路香。',35,'全唐诗/poet.tang.51000.json','["雲散經窗濕，山晴石路香。", "（《六朝事迹編類》卷下《寺院門·大愛敬寺》）。"]'),
('6634b107-d426-4829-a2c9-e929aa78b006','句','李建勳','唐','唐诗','tang','','[]','牆陰沙岸靜，島色海山孤。',27,'全唐诗/poet.tang.51000.json','["牆陰沙岸靜，島色海山孤。", "（《輿地紀勝》七《鎮江府》）。"]'),
('a552d241-e431-4534-9fe8-6089ec3dcba6','觀山水障歌','江爲','唐','唐诗','tang','','[]','適來一觀山水障，萬里江山在其上。',186,'全唐诗/poet.tang.51000.json','["適來一觀山水障，萬里江山在其上。", "遠近猶如二月春，咫尺分成百般像。", "一巖嵯峨入雲際，七賢鎮在青松裏。", "潭水澄泓不見波，孤帆滉漾張風勢。", "釣魚老翁無伴侶，孑然此地輕寒暑。", "灘頭坐久髩絲垂，手把魚竿不曾舉。", "樹婀娜，山崔嵬，片雲似去又不去，雙鶴如飛又不飛。", "良工巧匠多分布，筆頭寫出江山[路]（頭）。", "垂柳風吹不動條，樵人負重難移步。", "（《全五代詩》三九）（〖1〗見宋孫紹遠《聲畫集》卷四。", "）。"]'),
('8c39b918-ad90-4174-b18f-1b11faac330b','句','江爲','唐','唐诗','tang','','[]','竹影橫斜水清淺，桂香浮動月黃昏。',80,'全唐诗/poet.tang.51000.json','["竹影橫斜水清淺，桂香浮動月黃昏。", "（《紫桃軒雜綴》）（〖1〗明李日華《紫桃軒雜綴》謂林逋名句「疎影橫斜水清淺，暗香浮動月黃昏」二句爲改江爲二句而成。", "所據不詳。", "）。"]'),
('1d5feafc-6d3d-409c-9d90-28389ddc72ff','岳陽樓（句）','張泌','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','檻外有天皆在照，望中無物敢潛行。',31,'全唐诗/poet.tang.51000.json','["檻外有天皆在照，望中無物敢潛行。", "（《輿地紀勝》六九《岳州》）。"]'),
('c3f9c99d-f8f2-4a91-92bc-6f8042e25ea1','浣溪沙（〖1〗詞《全唐詩》八九一作張曙詞，第二句「苦」，《花間集》作「兩」。○《花間集》〖2〗《北夢瑣言》卷八作張曙詞，《全唐詩》沿之。或疑張曙、張泌爲同一人。）','張泌','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('7a578467-0a03-4856-af04-22f75c8d08fe','送人遊南海','沈彬','唐','唐诗','tang','','[]','白煙和月藏巒洞，明月隨潮入瘴村。',47,'全唐诗/poet.tang.51000.json','["白煙和月藏巒洞，明月隨潮入瘴村。", "更想臨高見佳景，越王臺上酒盈罇。", "（《輿地紀勝》八九《廣州》）。"]'),
('c523b3b6-33cf-4903-8eeb-b35ef79c1ba7','句','沈彬','唐','唐诗','tang','','[]','龍約海船行有氣，象隈銅柱臥成痕。',28,'全唐诗/poet.tang.51000.json','["龍約海船行有氣，象隈銅柱臥成痕。", "（同上一○六《邕州》）。"]'),
('de7c0063-b78c-4dac-9b91-9e973b97a9ab','金陵覽古（〖1〗《全五代詩》三二引《十國春秋》：保大時，存嘗取吳大帝及六國興亡成敗之迹，作《覽古詩》二百章，章四句，地志家多援以爲證。又《金陵詩徵》引《建康志》略同。）','朱存','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('75e0d8d0-bb96-47fb-a8ce-4975ecb3ae8e','北渠（歷代宮苑殿閣制度）','朱存','唐','唐诗','tang','','[]','金殿分來玉砌流，黑龍湖徹鳳池頭。',69,'全唐诗/poet.tang.51000.json','["金殿分來玉砌流，黑龍湖徹鳳池頭。", "後庭花落恩波斷，翻與南唐作御溝。", "（〖1〗「南唐」，張敦頤《六朝事迹編類》卷上〖作楊修詩〗引作「南塘」。", "）。"]'),
('09f1ecba-dcec-4597-a1a3-d64ca380c08f','秦淮（以下景物）','朱存','唐','唐诗','tang','','[]','一氣東南王斗牛，祖龍潛爲子孫憂。',32,'全唐诗/poet.tang.51000.json','["一氣東南王斗牛，祖龍潛爲子孫憂。", "金陵地脈何曾斷，不覺真人已姓劉。"]'),
('b5cb906a-c6d2-4239-8bbe-c7c28639109c','東山','朱存','唐','唐诗','tang','','[]','鎮物高情濟世才，欲隨猿鶴老岩隈。',54,'全唐诗/poet.tang.51000.json','["鎮物高情濟世才，欲隨猿鶴老岩隈。", "山花處處紅粧面，髣髴如初擁妓來。", "（〖1〗以上二首，又見《記纂淵海》卷十。", "）。"]'),
('95c7c6d8-4f4a-428b-99f1-d3de6dbfd9f3','新亭','朱存','唐','唐诗','tang','','[]','滿目江山異洛陽，昔人何必重悲傷。',33,'全唐诗/poet.tang.51000.json','["滿目江山異洛陽，昔人何必重悲傷。", "倘能戮力扶王室，當自新亭復故鄉。", "。"]'),
('5eb16d63-1f52-42c0-8faf-0fd97e4d4a46','天闕山','朱存','唐','唐诗','tang','','[]','牛頭天際碧凝嵐，王導無稽亦妄談。',32,'全唐诗/poet.tang.51000.json','["牛頭天際碧凝嵐，王導無稽亦妄談。", "若指遠公爲上闕，長安應合指終南。"]'),
('a1e7124c-254b-4ccd-a64b-b6a23911f07c','石頭城','朱存','唐','唐诗','tang','','[]','五城樓雉各相望，山水英靈宅帝王。',32,'全唐诗/poet.tang.51000.json','["五城樓雉各相望，山水英靈宅帝王。", "此地定由天造險，古來長恃作金湯。"]'),
('960372d0-3380-43e4-b7ae-b0b0737e304a','烏衣巷','朱存','唐','唐诗','tang','','[]','人物風流往往非，空餘陋巷作烏衣。',32,'全唐诗/poet.tang.51000.json','["人物風流往往非，空餘陋巷作烏衣。", "舊時簾幕無從覓，祇有年年社燕歸。"]'),
('13c8c348-7f33-41de-a8dc-1f3cbfe647fa','段石崗','朱存','唐','唐诗','tang','','[]','孫吳紀德舊刊碑，草沒蟠螭與伏龜。',32,'全唐诗/poet.tang.51000.json','["孫吳紀德舊刊碑，草沒蟠螭與伏龜。", "惆悵崗頭三段石，至今猶似鼎分時。"]'),
('7960637d-3110-45cc-aaf3-19e3d194d7a8','玄武湖（〖1〗《全唐詩》七五七及《全五代詩》三一只存此一首，題作《後湖》，第二句「三翼」《全唐詩》作「三異」，第四句「下多時」《全唐詩》作「不多時」。）','朱存','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('8ad26321-cdcd-4d15-9e5a-f6a66c4877f3','阿育王塔','朱存','唐','唐诗','tang','','[]','窣堵凝然鎮梵宮，舉頭層級在雲中。',59,'全唐诗/poet.tang.51000.json','["窣堵凝然鎮梵宮，舉頭層級在雲中。", "金棺舍利藏何處？鐸繞危簷聲撼風。", "（以上《輿地紀勝》十七《建康府》。", "又《金陵詩徵》四）。"]'),
('6c40ff4a-e276-405d-8d8e-c6537d6bfc13','賦山別諸知己','鍾蒨','唐','唐诗','tang','','[]','暮景江亭上，雲山日望多。',72,'全唐诗/poet.tang.51000.json','["暮景江亭上，雲山日望多。", "只愁[辭]（解）輦轂，長恨隔嵯峨。", "有意圖功業，無心憶薜蘿。", "親朋將遠別，且共醉笙歌。", "（《徐鉉集》三。", "又《全五代詩》二九）。"]'),
('2db1fa85-3d2e-4d44-8c9c-16d72a9b6a26','小梅（句）（徐鉉《和亞元長歌》中有句云：「開緘試讀相思字，乃是多情喬亞元。短韻三篇皆麗絕，小梅寄意情偏切。」自注：「亞元詩云云。此語尤嘉。」）','喬舜','唐','唐诗','tang','','[]','借問小梅應得信，春風新自海邊來。',25,'全唐诗/poet.tang.51000.json','["借問小梅應得信，春風新自海邊來。", "（《徐鉉集》三）。"]'),
('2125724c-2cde-4385-b8a3-89bf6e20ac05','送季大夫牧舒州','湯悅','唐','唐诗','tang','','[]','却下烏臺建隼旟，侯封歸去襲龍舒。',48,'全唐诗/poet.tang.51000.json','["却下烏臺建隼旟，侯封歸去襲龍舒。", "嚴霜尚滿辭天闕，甘雨看隨入境車。", "（《輿地紀勝》四六《安慶府》）。"]'),
('2ad294f1-6ea3-4b21-9fc6-0a34a62c21fe','楊柳枝','成文幹','唐','唐诗','tang','','[]','欲趁寒梅趁得麽，雪中偷眼望陽和。',40,'全唐诗/poet.tang.51000.json','["欲趁寒梅趁得麽，雪中偷眼望陽和。", "陽和若不先留意，這箇柔條爭奈何。", "（《尊前集》）。"]'),
('fa12798f-be17-4112-9fbd-43d630af0c8d','東林寺天祚二年聯句','徐知證','唐','唐诗','tang','','["\u5e90\u5c71"]','古殿巍峩鎮碧峯，晉朝靈應顯神蹤。',197,'全唐诗/poet.tang.51000.json','["古殿巍峩鎮碧峯，晉朝靈應顯神蹤。", "林間野鳥驚朝梵，嶺上孤猿聽曉鐘。", "蝶戀半岩花灼灼，鹿眠深谷草茸茸。", "遊僧駐錫心皆佛，老樹擎煙勢似龍。", "竹蔭禪扃青靄合，嵐蒸幽逕綠苔封。", "老來欲脫塵寰境，閑訪空關不厭重。", "（《永樂大典》六六九七江字韻引《九江府志》，又六六九九引《江州志》）（〖1〗《吉石庵叢書》本《廬山記》收此詩，爲徐知證及其僚屬虔修、孟拱辰等七人聯句之作。", "又此處所錄亦未完。", "另詳《全唐詩續拾》卷四三。", "）。"]'),
('4634e2a3-62bd-422d-b121-98fd59ea8775','韻妙空（句）（妙空，名守納。嗣法於雪峯，卯一，齋住嘉祐禪院，江南李氏三召不起，刺史皇甫繼勳贈之詩云：）','皇甫繼勳','唐','唐诗','tang','','[]','白面山南靈慶院，卯齋道者雪峯禪。',28,'全唐诗/poet.tang.51000.json','["白面山南靈慶院，卯齋道者雪峯禪。", "（《嘉靖池州府志》九）。"]'),
('cf63eca5-5200-44e7-b4ef-41226226df15','喜賊平謁李將軍祠','危仔昌','唐','唐诗','tang','','[]','君向神重謁，天教君亦神。',59,'全唐诗/poet.tang.51000.json','["君向神重謁，天教君亦神。", "十年香火主，百物雨暘身。", "忠在偏誅賊，恩多每濟人。", "高歌震霄壑，朝野遍陽春。", "（《上饒縣志》二三）。"]'),
('2a15eb21-56f6-411e-9d34-3c54599eeddc','黃鶴樓（《宋詩紀事》亦未收）','盧郢','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','黃鶴何年去杳冥，高城千載倚江城。',129,'全唐诗/poet.tang.51000.json','["黃鶴何年去杳冥，高城千載倚江城。", "碧雲朝捲四山景，流水夜傳三峽聲。", "柳暗西州供騁望，草芳南浦徧離情。", "登臨一晌須回首，看却鄉心萬感生。", "（《古今圖書集成·職方典》一一二五《武昌府部》）（〖1〗見北宋熙寧間刻《鄂州雜詩碑》，參前「賈島」條。", "又見《方輿勝覽》卷二八。", "）。"]'),
('a47b552e-260d-428d-a79d-20065ed8ce16','','唐希雅','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('7b607ad8-c5d4-4e5c-80dc-66fe72fb1489','題畫','唐希雅','唐','唐诗','tang','','[]','誰潑煙雲六尺綃，寒山秋樹晚蕭蕭。',65,'全唐诗/poet.tang.51000.json','["誰潑煙雲六尺綃，寒山秋樹晚蕭蕭。", "十年來往吳淞口，錯認溪南舊板橋。", "（《全五代詩》三六引《槜李詩繫》）（〖1〗見《槜李詩繫》卷一。", "）。"]'),
('8bb87e02-9d4f-4010-bb63-912975409175','小桃源（一題《入黟吟》。《輿地紀勝》二十作李白詩）（未詳其所自來，客遊於黟，樂之，作詩云云，遂家焉。今桃源洞有許氏，蓋其後裔云。或曰：堅即宣平，堅其名，宣平其字，未知是否。〖1〗）','許堅','唐','唐诗','tang','','[]','黟邑桃源小，煙霞百里寬。',145,'全唐诗/poet.tang.51000.json','["黟邑桃源小，煙霞百里寬。", "地多靈草木，人尚古衣冠。", "市向晡時散，山經夜後寒。", "吏閒民訟簡，秋菊露漙漙。", "（康熙《徽州府志》十七《流寓傳》。", "又見《黟縣志》十六）（〖1〗此說誤。", "《太平廣記》卷二四引《續仙傳》謂許宣平爲景雲中人，許堅則爲南唐人，其間相隔二百餘年。", "又本詩前已收李白名下，惟此多末二句。", "）。"]'),
('fb067622-99a3-4baa-8e99-218b1e86a418','戢兵山（舊名石鼓山，在黟縣北十五里，高百仞，周十里，有石鼓、石人、石驢。相傳石鼓鳴即驢鳴，人哭而長官不利。後鑿其鼓破之，遂不復鳴。唐天寶六年改今名。）','許堅','唐','唐诗','tang','','[]','石鼓高懸藴大音，白雲峯頂始鋪金。',32,'全唐诗/poet.tang.51000.json','["石鼓高懸藴大音，白雲峯頂始鋪金。", "能來斯地鼓斯鼓，盡達曹溪聖祖心。"]'),
('8cb236b4-9a8e-4f7b-ad1f-36b319e35c7c','中秋詠月（詠詩後，乘興遂子夜鳴鐘，烈祖聞之，不罪也。召問其所求，唯願鵝生四脚，鼈著兩裙。）','謙明','唐','唐诗','tang','','[]','迢迢東海出，漸漸入雲衢。',447,'全唐诗/poet.tang.51000.json','["迢迢東海出，漸漸入雲衢。", "此夜一輪滿，清光何處無。", "（《江南餘載》下）（〖1〗《歲時廣記》三十一《中秋》上《得佳聯》引《漫叟詩話》：「南唐金輪寺有僧曰明光者，先一年中秋翫月，得詩一聯云：『團團離海角，漸漸出雲衢。", "』竟思下聯不就。", "次年中秋，再得一聯云：『此夜一輪滿，清光何處無？", "』遂不勝其喜，徑登寺樓鳴鐘。", "時有善聽聲聞之：『此鐘發聲通暢，若非詩人得句，即是禪僧悟道。", "』驗之果然。", "好事者有詩云：『爲思銀漢中秋月，誤擊金輪半夜鐘。", "』」〖2〗《全唐詩》八五一、《全五代詩》三九均作南唐失名僧《月詩》，前二句作「徐徐東海出，漸漸上天衢」。", "《全五代詩》引《江南野錄》：「李昪受禪之初，忽半夜寺僧撞鐘，一城皆驚，召將斬之，云夜來偶得月詩，乃云云。", "李昪喜而釋之。", "」〖3〗原以明光另列一則。", "今檢《苕溪漁隱叢話前集》卷二十六引《漫叟詩話》作「南唐僧謙明」詩，知明光之名爲南宋時之別傳，而非另有其人，故以明光一則移附於此。", "另《釣磯立談》謂作詩者爲「頭陀范忠嵩」。", "《江鄰幾雜識》作「南唐一詩僧」，當即爲《全唐詩》所本。", "）。"]'),
('fbaceb68-ec34-44a8-9775-d015c3986bbc','青史樓引賓從同登','錢鏐','唐','唐诗','tang','','[]','雲閣霞軒別構雄，下窺疆宇壯吳宮。',64,'全唐诗/poet.tang.51000.json','["雲閣霞軒別構雄，下窺疆宇壯吳宮。", "洪濤日日來滄海，碧嶂聯聯倚太穹。", "志仗四征平逆孽，力扶三帝有褒崇。", "如今分野無狼孛，青史樓標定亂功。"]'),
('7ccd8337-7689-474a-b435-eb11c29eb2b2','石鏡山（幷序）','錢鏐','唐','唐诗','tang','','[]','丱歲遨遊在此山，曾驚一石立山前。',64,'全唐诗/poet.tang.51000.json','["丱歲遨遊在此山，曾驚一石立山前。", "未能顯瑞披榛莽，蓋爲平兇有歲年。", "昨返錦門停駟馬，遂開靈岫種青蓮。", "三吳百粤興金地，永與軍民作福田。"]'),
('4494c7db-e391-4523-beb9-a367c2be5861','築塘','錢鏐','唐','唐诗','tang','','[]','天分浙水應東溟，日夜波濤不暫停。',105,'全唐诗/poet.tang.51000.json','["天分浙水應東溟，日夜波濤不暫停。", "千尺巨堤衝欲裂，萬人力禦勢須平。", "吳都地窄兵師廣，羅剎名高海衆獰。", "爲報龍神幷水府，錢塘且借作錢城。", "（〖1〗《全唐詩》卷八據《吳越備史》收「傳語龍王並水府，錢塘借與築錢城」二句。", "）。"]'),
('ec46cbe7-e9d1-4216-89ed-446b55f08115','九日同羣僚登高（幷序）','錢鏐','唐','唐诗','tang','','[]','淡蕩晴暉雜素光，碧峯遙襯白雲長。',64,'全唐诗/poet.tang.51000.json','["淡蕩晴暉雜素光，碧峯遙襯白雲長。", "好看塞雁歸南浦，宜聽砧聲搗夕陽。", "滿野旌旗皆動色，千株橘柚盡含芳。", "錦袍分賜功臣後，因向龍山醉羽觴。"]'),
('0527112d-9a30-4c9a-80ac-37806b06e453','功臣堂（幷序）','錢鏐','唐','唐诗','tang','','[]','今夕雖非豐沛酒，醪觥同醉洽吾鄉。',64,'全唐诗/poet.tang.51000.json','["今夕雖非豐沛酒，醪觥同醉洽吾鄉。", "兩邦父老趨旌府，百品肴羞宴桂堂。", "寶劍已頒王禮盛，錦衣重帶御爐香。", "越王冊後封吳王，大國宣恩達萬方。"]'),
('44120b02-b1fa-4f04-bba4-87957176791a','上元夜次序平江南','錢鏐','唐','唐诗','tang','','[]','四朝雙母顯真封，古往今來事一同。',16,'全唐诗/poet.tang.51000.json','["四朝雙母顯真封，古往今來事一同。"]'),
('d96cc8aa-23a4-4039-b2ec-d79ed3d45012','西園產芝','錢鏐','唐','唐诗','tang','','[]','五紀尊天立霸基，八方隣國盡相知。',64,'全唐诗/poet.tang.51000.json','["五紀尊天立霸基，八方隣國盡相知。", "興吳定越崇王道，殄物平兇建國儀。", "忽有靈根彰瑞應，皆由和氣感明祗。", "休言漢代芝房異，今日吾邦事更奇。"]'),
('928c645e-7d70-4a4c-9463-679e38a130d8','羅漢寺偶題','錢鏐','唐','唐诗','tang','','[]','九夏聽蟬吟，已知秋氣臨。',49,'全唐诗/poet.tang.51000.json','["九夏聽蟬吟，已知秋氣臨。", "高梧上明月，深巷搗寒砧。", "好對吳山秀，宜觀浙水深。", "一登靈鷲閣，寶地勝黃金。", "。"]'),
('b344cce5-7ad3-4d97-87e9-89a5eeeabef9','和高僧惠韻','錢鏐','唐','唐诗','tang','','[]','嵐高照目前，山下有蒙泉。',48,'全唐诗/poet.tang.51000.json','["嵐高照目前，山下有蒙泉。", "雲閣連天際，銀河傍斗邊。", "涼風宜散暑，清景好安禪。", "況是江山固，崇墉保萬年。"]'),
('a0db9501-17b7-40c1-9a27-769596454bdb','造寺保民','錢鏐','唐','唐诗','tang','','[]','百穀收成屆應鍾，南方景象喜重重。',64,'全唐诗/poet.tang.51000.json','["百穀收成屆應鍾，南方景象喜重重。", "三秋甘澤烟塵息，四序和風氣色濃。", "播種勤耕盈廩庾，兆民興讓洽溫恭。", "廣崇至道尊三教，蓋爲生靈奉聖容。"]'),
('4108e24a-b0c6-41bd-b1f3-f03cb0d22e91','秋景','錢鏐','唐','唐诗','tang','','[]','三秋才到退炎光，二曜分暉照四方。',64,'全唐诗/poet.tang.51000.json','["三秋才到退炎光，二曜分暉照四方。", "解使金風催物象，能教素節運清涼。", "天垂甘澤朝朝降，地秀佳苗處處香。", "率土吾民成富庶，虔誠稽顙荷穹蒼。"]'),
('650757ea-0f32-46b5-bfb9-0875059ed242','百花亭題梅二首 一','錢鏐','唐','唐诗','tang','','[]','穠華圍裡萬株梅，含蕊經霜待雪催。',32,'全唐诗/poet.tang.51000.json','["穠華圍裡萬株梅，含蕊經霜待雪催。", "莫訝玉顏無粉態，百花中最我先開。"]'),
('fdcf9092-5995-4e63-b617-3b1d9a2aae00','百花亭題梅二首 二','錢鏐','唐','唐诗','tang','','[]','吳山越岫種寒梅，玉律含芳待候催。',32,'全唐诗/poet.tang.51000.json','["吳山越岫種寒梅，玉律含芳待候催。", "爲應陽和呈雪貌，遊蜂難覺我先開。"]'),
('2dfefc5a-d533-4160-b3fe-fa193c89fcad','和太師藴讓韻','錢鏐','唐','唐诗','tang','','[]','羅漢親崇建法臺，龍峯鳳嶺四山隈。',32,'全唐诗/poet.tang.51000.json','["羅漢親崇建法臺，龍峯鳳嶺四山隈。", "遊人借問禪門路，還道吳王爲佛開。"]'),
('177cf044-ae61-4880-8146-f5a2be14e321','題羅隱壁','錢鏐','唐','唐诗','tang','','["\u9ec4\u6cb3"]','特到儒門謁老萊，老萊相見意徘徊。',138,'全唐诗/poet.tang.51000.json','["特到儒門謁老萊，老萊相見意徘徊。", "黃河信有澄清日，後代應難繼此才。", "（以上《吳越錢氏傳芳集》）（〖1〗錢泳案：「《吳越備史》云：『隱寢疾，王親臨撫問。", "因題其壁云：「黃河信有澄清日，後代應難繼此才。", "」隱起而續末句云：「門外旌旗屯虎豹，壁間章句動風雷。", "」由是以紅紗罩覆於其上。", "』」）。"]'),
('2e71ea01-2f4b-4ce8-b320-26cdaf96f34d','隱岳洞（在石城山，五代時有隱岳寺）','錢鏐','唐','唐诗','tang','','[]','百尺金容連翠岳，三層寶閣倚青霄。',44,'全唐诗/poet.tang.51000.json','["百尺金容連翠岳，三層寶閣倚青霄。", "手爐香暖申卑願，願降殊祥福帝堯。", "（萬曆《新昌縣志》三）。"]'),
('24f279e1-5013-4d71-8acd-cb90d4193cb3','送別十七哥','錢元瓘','唐','唐诗','tang','','[]','大伯東陽軫舊思，士民襦袴喜迴時。',32,'全唐诗/poet.tang.51000.json','["大伯東陽軫舊思，士民襦袴喜迴時。", "登臨若起鴒原念，八詠樓中寄小詩。"]'),
('9c614ae1-2864-44f7-ab97-bbb73a67b6cf','題得銅香爐（幷序）','錢元瓘','唐','唐诗','tang','','[]','莫記年華隱水中，忽於此日覩靈蹤。',78,'全唐诗/poet.tang.51000.json','["莫記年華隱水中，忽於此日覩靈蹤。", "三天瑞氣標金相，五色龍光儼聖容。", "節屆初秋興典教，時當千載慶遭逢。", "仙冠羽服聲清曲，共引金臺入九重。", "（以上《吳越錢氏傳芳集》）。"]'),
('f7463cd5-fb19-4d4f-8bcf-0dd6534ad8a4','佳辰小讌寄越州七弟湖州八弟','錢弘佐','唐','唐诗','tang','','[]','角黍佳辰社稷寧，靈和開讌樂羣英。',32,'全唐诗/poet.tang.51000.json','["角黍佳辰社稷寧，靈和開讌樂羣英。", "樽前只少鴒原會，百里江城隔二城。"]'),
('f8d741e6-0bf1-4ee8-bf42-fb6ceec1a41d','謁寶塔回賜僧錄','錢弘佐','唐','唐诗','tang','','[]','佛日輝光最有靈，真身寶塔鎮吳城。',78,'全唐诗/poet.tang.51000.json','["佛日輝光最有靈，真身寶塔鎮吳城。", "千尋獨拔乾坤聳，八面齊含日月明。", "幾曲朱欄瞻海浪，長時金鐸振風聲。", "禱祈祇願蒼生泰，更仗高僧法供精。", "（以上《吳越錢氏傳芳集》）。"]'),
('a6597ec9-307e-49cb-83a0-909e487216b5','登臥龍山偶成','錢弘倧','唐','唐诗','tang','','[]','暮山重疊勢崔嵬，溢目清光入酒杯。',64,'全唐诗/poet.tang.51000.json','["暮山重疊勢崔嵬，溢目清光入酒杯。", "幾處燒殘紅樹短，一帆航盡碧波來。", "安民未有移風術，徵句慚非夢錦才。", "四望樓臺無限景，檻前贏得且徘徊。"]'),
('d6545092-da89-4d42-8602-c2cb6ec377a5','禹廟','錢弘倧','唐','唐诗','tang','','[]','千古功勳孰可倫，東來靈宇壓乾坤。',220,'全唐诗/poet.tang.51000.json','["千古功勳孰可倫，東來靈宇壓乾坤。", "塵埃共鏁梁猶在，星斗俱昏劍獨存。", "蟾殿夜寒籠翠幌，麝爐春暖酹瓊樽。", "會稽山水秋風裏，長放松聲入廟門。", "（〖1〗北宋孔延之《會稽掇英總集》卷八收此詩，署「錢倧」，異文較多，錄如次：「功勳」作「英靈」，「東來」作「西來」，「靈宇」作「神宇」，「梁猶在」作「梅梁在」，「俱昏」作「俱分」，「劍獨存」作「劍韣存」，「籠翠幌」作「搖翠幌」，「山水」作「山下」。", "《嘉泰會稽志》卷十二引「塵埃」二句，文字同《會稽掇英總集》。", "）。"]'),
('b668b92d-2f47-442f-a249-3a8a3508b49c','登蓬萊閣懷武肅王','錢弘倧','唐','唐诗','tang','','[]','黃鶴摧殘漫有名，建時方始殄羅平。',64,'全唐诗/poet.tang.51000.json','["黃鶴摧殘漫有名，建時方始殄羅平。", "飛㭿疊栱重裝束，刻檻雕甍又葺成。", "十載興隆吳與越，二邦安肅弟兼兄。", "從茲登賞雲樓上，願祝江南永宴清。"]'),
('87f69135-bc16-41c0-bb62-7d436cf3104b','再遊聖母閣（《輿地紀勝》十《紹興府》詩摘第二聯題《遊天衣寺》）','錢弘倧','唐','唐诗','tang','','[]','越地靈蹤多少處，伽藍難上此樓臺。',142,'全唐诗/poet.tang.51000.json','["越地靈蹤多少處，伽藍難上此樓臺。", "有時風掣浪聲到，半夜月排山勢來。", "極目烟嵐迷遠近，百般花木雕塵埃。", "可憐光景吟無盡，知我登臨更幾迴。", "（以上《吳越錢氏傳芳集》）（〖1〗《會稽掇英總集》卷八收此詩，署「錢倧」，題作《再遊應天寺聖母閣》。", "第二句「難上」作「難尚」，第四句「山勢」作「山影」。", "）。"]'),
('a4e02be5-f9b8-4cae-943f-136061e8eadf','飛英寺（句）','錢弘偡','唐','唐诗','tang','','[]','兩岸槿花紅障步，一行山色綠屏風。',34,'全唐诗/poet.tang.51000.json','["兩岸槿花紅障步，一行山色綠屏風。", "（《輿地紀勝》四《安吉州·景物》）。"]'),
('cb266278-8c61-4c40-9c5f-e755caa3264f','過平望','錢弘俶','唐','唐诗','tang','','[]','風靜度長川，清吟倚畫船。',48,'全唐诗/poet.tang.51000.json','["風靜度長川，清吟倚畫船。", "未分山有樹，惟見水連天。", "沙嘴牛眠草，波心鳥觸烟。", "宵征還有興，皎皎玉輪圓。"]'),
('30ac185f-a2c0-42a4-900b-4f25c27c3fe1','讀聖壽詩','錢弘俶','唐','唐诗','tang','','[]','功格皇天僞國平，八方臣妾盡來庭。',64,'全唐诗/poet.tang.51000.json','["功格皇天僞國平，八方臣妾盡來庭。", "駿奔幸逐朝宗水，雀躍俄逢繞電星。", "就日心雖懸紫闕，祝堯身尚處洪溟。", "壽山聳峙將何願，泰華千霄萬仞青。"]'),
('7819be29-d4d6-4f7c-a924-e02df47c0482','感皇子遠降見迎','錢弘俶','唐','唐诗','tang','','[]','千年遭遇覲真王，敢望青宮賜顯揚。',64,'全唐诗/poet.tang.51000.json','["千年遭遇覲真王，敢望青宮賜顯揚。", "祇合承華趨令德，豈宜中道拜元良。", "深思轉覺乾坤大，力弱難勝雨露滂。", "早暮三思恩泰極，飽餐豐饌飽親光。"]'),
('8abc486a-e728-4043-8134-884836aeb8d9','感降內夫人賜家室藥物金器','錢弘俶','唐','唐诗','tang','','[]','魚軒相逐拜龍軒，聖主俄推望外恩。',64,'全唐诗/poet.tang.51000.json','["魚軒相逐拜龍軒，聖主俄推望外恩。", "錫寵便籓光石窌，內嬪迢遞下金門。", "嵩衡壓地何曾重，雞犬昇仙未足論。", "臣憨已平難展報，祇將忠孝訓兒孫。"]'),
('b28cbabb-e484-48b3-ada9-14c58dbe5446','金陵','錢弘俶','唐','唐诗','tang','','[]','不用論京口，先須問石頭。',53,'全唐诗/poet.tang.51000.json','["不用論京口，先須問石頭。", "虎山終自伏，帶水漫長遊。", "青蓋曾彰讖，黃奴肯識羞。", "分明前[鑒]（監）在，剛地弄戈矛。"]'),
('744086e8-65c9-4eb7-9fa3-974a575fa3fc','過楚州','錢弘俶','唐','唐诗','tang','','[]','駐馬楚城南，秋光帶雨寒。',48,'全唐诗/poet.tang.51000.json','["駐馬楚城南，秋光帶雨寒。", "地平無島嶼，淮近足波瀾。", "聖德常柔遠，烝民賴此安。", "行吟復行酌，朝野正多歡。"]'),
('d78049c7-deeb-4e09-8547-42bc923b7284','陳國','錢弘俶','唐','唐诗','tang','','[]','批破《陳書》後，都無禦敵心。',56,'全唐诗/poet.tang.51000.json','["批破《陳書》後，都無禦敵心。", "庭花春易盡，璧月夜難沉。", "臣爵妖姬醉，新詩[狎]（狹）客吟。", "江神如訪問，教到井中尋。", "。"]'),
('5d4f9b92-5b0a-43ad-8b4a-5402f4279254','路次再感聖恩','錢弘俶','唐','唐诗','tang','','[]','洪濤泛泛雨霏霏，芳草如茵柳裊絲。',64,'全唐诗/poet.tang.51000.json','["洪濤泛泛雨霏霏，芳草如茵柳裊絲。", "貼水碧禽飛一字，隔烟青嶂展雙眉。", "南風入隙開襟久，西照臨窗捲箔遲。", "慚愧聖恩優渥異，不教炎暑冒長歧。"]'),
('5003159d-ae63-4ed0-bacf-eb071892c3fa','小窗','錢弘俶','唐','唐诗','tang','','[]','粉雲牙貼小窗凉，坐見澄波泛夕陽。',32,'全唐诗/poet.tang.51000.json','["粉雲牙貼小窗凉，坐見澄波泛夕陽。", "更持夜深方有意，半環新月上重牀。"]'),
('c0215121-c861-405b-a603-f8341fe9a177','舟中偶書','錢弘俶','唐','唐诗','tang','','[]','輕舟畫舸枕江濱，眼底波濤日日新。',32,'全唐诗/poet.tang.51000.json','["輕舟畫舸枕江濱，眼底波濤日日新。", "瞑目穩收雙足坐，不勞詢問醉禪人。"]'),
('65f877aa-775b-4aba-9b5f-4ed0e90407a8','村家','錢弘俶','唐','唐诗','tang','','[]','竹樹參差處，危牆獨木橫。',48,'全唐诗/poet.tang.51000.json','["竹樹參差處，危牆獨木橫。", "鋤開芳草色，放過遠灘聲。", "稚子當門臥，雞雛上屋行。", "騎牛帶簑笠。", "侵曉雨中耕。"]'),
('dd5b4c1c-d70e-4cd7-9e35-ecf920693055','漁者','錢弘俶','唐','唐诗','tang','','[]','罟網是生涯，柴扉隔水遮。',62,'全唐诗/poet.tang.51000.json','["罟網是生涯，柴扉隔水遮。", "不辭粗俗氣，惟取大魚蝦。", "貰酒方登陸，憐春亦種花。", "等閑乘一葉，放曠入煙霞。", "（以上《吳越錢氏傳芳集》）。"]'),
('c996b577-5da1-4f05-9f54-2c87ff9c8214','追鮑約（侍郎鮑約，頗從臾忠懿王納土。及王歸宋，約竄處海上，王以詩追之曰〖見下〗。迄今有遐追廟焉。）','錢弘俶','唐','唐诗','tang','','[]','東遐追兮西遐追，鮑約何如罷釣歸。',56,'全唐诗/poet.tang.51000.json','["東遐追兮西遐追，鮑約何如罷釣歸。", "（《五代詩話》六引《十國春秋》）（〖1〗見《十國春秋》卷八七《崔仁冀傳》附。", "）。"]'),
('391f563f-599f-4560-8c29-e93e15285a83','滕王閣','羅隱','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','[江神]有意憐才子，歘忽威靈助去程。',200,'全唐诗/poet.tang.51000.json','["[江神]有意憐才子，歘忽威靈助去程。", "一席清風雷電疾，滿碑佳句雪冰清。", "煥然麗藻傳千古，赫爾英名動兩京。", "若匪幽冥[祐詞]客，至今佳景絕無聲。", "（《歲時廣記》三五《重九》）（〖1〗據《醒世恒言》卷四十《馬當神風送滕王閣》補缺文。", "《醒世恒言》錄此詩，前四句除「一席」作「一夕」外，餘全同。", "後四句改動稍多，錄如次：「直教麗藻傳千古，不但雄名動兩京。", "不是明靈祐祠客，洪都佳景絕無聲。", "」「祠客」顯爲「詞客」之誤。", "）。"]'),
('cc80c591-cb60-498e-bc82-148f69e89a80','文選閣（在貴池城西五里西廟。貯梁昭明文選。有址）','羅隱','唐','唐诗','tang','','[]','間生元子出蕭梁，作選爲書化萬邦。',85,'全唐诗/poet.tang.51000.json','["間生元子出蕭梁，作選爲書化萬邦。", "三代已來成冠絕，六朝餘外更無雙。", "今朝集是羣英仰，昨日談非衆耻降。", "輔國安民新試閣，滕王空作問臨江。", "（《嘉靖池州府志》卷三《建置篇·宮室》）。"]'),
('6867e10a-633d-4a34-b30d-6c5e813b3a03','昭明太子廟','羅隱','唐','唐诗','tang','','[]','秋浦昭明廟，乾坤一白眉。',39,'全唐诗/poet.tang.51000.json','["秋浦昭明廟，乾坤一白眉。", "神通高學識，天下鬼神師。", "（同上卷五《祀典篇·廟祠》）。"]'),
('b53e89a1-2c4e-46bb-954c-af5aae4dbe38','下山過梅根','羅隱','唐','唐诗','tang','','[]','岸葉經秋墜晚枝，裊烟凌鬢促征期。',79,'全唐诗/poet.tang.51000.json','["岸葉經秋墜晚枝，裊烟凌鬢促征期。", "家從澤國誰能問，路在侯門自不知。", "但恐老侵多病日，每憂忙過少年時。", "可憐江上人堪笑，獨倚殘陽弄釣絲。", "（同上卷八《雜著篇·藝文》）。"]'),
('a781e6c3-d9d7-46c0-a4be-92076b9eac7c','金雞石（在東流縣南二十五里。相傳羅隱道經其地，題云云，石遂迸裂，鷄飛鳴而去。或曰：隱題後，其石震雷劈焉。）','羅隱','唐','唐诗','tang','','[]','青山隱隱望長溪，獨墩無伴只孤棲。',39,'全唐诗/poet.tang.51000.json','["青山隱隱望長溪，獨墩無伴只孤棲。", "草堂不見婁羅漢，金雞不向五更啼。", "（同上卷一）。"]'),
('e2d6b716-6334-4f94-bfb6-6d04e523e0f4','掛劍處','羅隱','唐','唐诗','tang','','[]','忠貞者必信，所信交道深。',33,'全唐诗/poet.tang.51000.json','["忠貞者必信，所信交道深。", "賢哉吳季子，可稱莫逆心。", "（《梅里志》三）。"]'),
('f2de76c6-1319-4af4-b463-285c15204e08','題延和閣（《全唐詩》八七五作讖記，詩題、小序、詩多有不同，故重錄）（時高駢欲繼淮南王求仙方爲妖亂，後爲畢將軍所害。隱作《妖亂誌》以譏之，故有《題延和閣》云。）','羅隱','唐','唐诗','tang','','[]','延和高閣勢凌雲，輕語猶疑太一聞。',54,'全唐诗/poet.tang.51000.json','["延和高閣勢凌雲，輕語猶疑太一聞。", "燒盡餘香無一事，開門迎得畢將軍。", "（《詩話總龜》三五《譏誚門》引《鑑誡錄》）。"]'),
('bc9690d6-ba05-45ef-b695-e8de3e429ed9','上亭驛（在梓潼武連二縣之界。唐明皇幸蜀。聞鈴聲之地。又名琅璫驛）','羅隱','唐','唐诗','tang','','[]','山雨霏微宿上亭，雨中因想雨淋鈴。',104,'全唐诗/poet.tang.51000.json','["山雨霏微宿上亭，雨中因想雨淋鈴。", "貴爲天子猶魂斷，窮著荷衣好涕零。", "（《輿地紀勝》一八六《隆慶府》。", "《全唐詩》六六五引《天中記》只存前二句）（〖1〗《碧雞漫志》卷五收此詩全篇，爲七律，詳《全唐詩續拾》卷四五。", "）。"]'),
('eeed1ae1-7960-4307-b40e-bf2e5799f3d7','','任翻','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('2516a2d1-22a8-4aea-a2df-fa03ae26913b','賦台州早春（句）','任翻','唐','唐诗','tang','','[]','豈堪滄海畔，爲客十年來。',57,'全唐诗/poet.tang.51000.json','["豈堪滄海畔，爲客十年來。", "（《輿地紀勝》十二《台州》）（〖1〗《天台前集》存此詩全篇，詳《全唐詩續拾》卷三十五。", "）。"]'),
('77eedb79-5fc0-4971-a6bc-3adb5ad4712c','詠志（《全唐詩》七九五只存前二句）','屠環智','唐','唐诗','tang','','[]','輕身都是義，殉主始爲忠。',109,'全唐诗/poet.tang.51000.json','["輕身都是義，殉主始爲忠。", "一夜西陵路，朱旗走大風。", "（《全五代詩》七三引《槜李詩繫》）（〖1〗此說未允。", "《全唐文》卷八九八收皮光業《屠將軍墓誌銘》、《十國春秋》卷八四皆作屠瓌智。", "〖2〗見《槜李詩繫》卷一，作者作屠瓌智。", "）。"]'),
('49ac821d-d48f-4b81-aac3-b1d9b0f17c0a','題常樂菴五雲堂（常樂菴在崇德縣西八十步。梁步監二年建。俗呼西寺。後入宋改悟空院。吳越時韋謙詩云云。）','韋謙','唐','唐诗','tang','','[]','吾匠慕先哲，至理皆融通。',92,'全唐诗/poet.tang.51000.json','["吾匠慕先哲，至理皆融通。", "一法果有至，五雲疑在空。", "講香浸棐几，夜月鎖簾櫳。", "弋者何由預，冥冥出塞鴻。", "（同上）（〖1〗《至元嘉禾志》卷三二收此詩，署「節度韋謙」。", "又見《槜李詩繫》卷三七。", "）。"]'),
('58f36615-f1d9-4cf7-b26b-3c85bf245a20','下獄有作','陳長官','唐','唐诗','tang','','[]','按則增科不自由，未曾舉筆淚先流。',202,'全唐诗/poet.tang.51000.json','["按則增科不自由，未曾舉筆淚先流。", "高田沙瘦常憂旱，沿海塗鹹少有秋。", "要使繭絲殫地力，願將骨肉伴枷頭。", "一時種了黃連種，萬代令人苦不休。", "（《古今圖書集成·食貨典》一五三《賦役部》）（〖1〗《十國春秋》卷八五：「陳長官，事武肅王爲寧海縣令。", "會王命增州縣賦稅，長官上書極諫，王大怒，逮之獄。", "長官以死爭之，得免。", "寧海故稱劇縣，租稅視諸邑爲獨輕者，皆其力也，至今猶廟祀焉。", "」與其詩相合。", "原收「無世次」卷，今移入本卷。", "）。"]'),
('22e639d2-fae5-42c1-8464-e1ebb2a9123a','評僧道二門論難','牛嶠','唐','唐诗','tang','','[]','玄門清淨等空門，虔奉天尊與世尊。',78,'全唐诗/poet.tang.51000.json','["玄門清淨等空門，虔奉天尊與世尊。", "金口說經十二部，玉皇留教五千言。", "鼇頭宮殿波瀾闊，鷲嶺香花夢相存。", "莫向人間爭勝負，須知三教本同源。", "（《鑑誡錄》六《旌論衡》）。"]'),
('64b82d16-1292-44f7-90e9-030cddc25aca','刺賈島','張蠙','唐','唐诗','tang','','["\u957f\u6c5f"]','少年爲理但公清，鴻漸行中是去程。',101,'全唐诗/poet.tang.51000.json','["少年爲理但公清，鴻漸行中是去程。", "莫恨長江爲短簿，可能勝得賈先生？", "（《鑑誡錄》八《賈忤旨》）（〖1〗《鑑誡錄》云：「後有一少年除長江簿，猶豫不赴，張蠙先輩爲詩刺之。", "」此處所擬詩題不允，應作「刺少年」。", "）。"]'),
('402ba9b4-8764-45c6-8ce9-cc89b519a9bd','弔孟浩然（後二句）','盧延讓','唐','唐诗','tang','','[]','漢水醉時波尚綠，鹿門吟處草猶生。',103,'全唐诗/poet.tang.51000.json','["漢水醉時波尚綠，鹿門吟處草猶生。", "（《輿地紀勝》八二《襄陽府》）（今按：《全唐詩》七一五引《海錄碎事》，另有「高據襄陽播盛名，問人人道是詩星」二句，正可合爲一首。", "此二聯格律不粘。", "疑原詩爲七律，今僅存二聯。", "）。"]'),
('03f25790-0eb4-41e1-861e-fcf5e124ea89','懷江上（句）（盧延遜五舉方登第。〖2〗嘗作詩云。「狐衝」二句，租庸張相濬每誦之。又「餓猫」二句，成中令汭激賞之。又「栗爆」二句，王中懿建愛之。盧嘗謂人曰：「平生投謁公卿，不意得猫兒狗子之力也。」） 一','盧延讓','唐','唐诗','tang','','[]','狐衝官道過，犬刺客門開（一作「狗判店門開」）。',27,'全唐诗/poet.tang.51000.json','["狐衝官道過，犬刺客門開（一作「狗判店門開」）。", "〖3〗。"]'),
('1fe5f4d5-0d7b-41c2-a122-7fdcc3cfaabb','懷江上（句）（盧延遜五舉方登第。〖2〗嘗作詩云。「狐衝」二句，租庸張相濬每誦之。又「餓猫」二句，成中令汭激賞之。又「栗爆」二句，王中懿建愛之。盧嘗謂人曰：「平生投謁公卿，不意得猫兒狗子之力也。」） 二','盧延讓','唐','唐诗','tang','','[]','餓猫臨鼠穴，饞犬舐魚砧。',12,'全唐诗/poet.tang.51000.json','["餓猫臨鼠穴，饞犬舐魚砧。"]'),
('abf7588f-bae4-41b5-8349-4d593f4a92ae','懷江上（句）（盧延遜五舉方登第。〖2〗嘗作詩云。「狐衝」二句，租庸張相濬每誦之。又「餓猫」二句，成中令汭激賞之。又「栗爆」二句，王中懿建愛之。盧嘗謂人曰：「平生投謁公卿，不意得猫兒狗子之力也。」） 三','盧延讓','唐','唐诗','tang','','[]','栗爆燒氊破，猫跳觸鼎翻。',130,'全唐诗/poet.tang.51000.json','["栗爆燒氊破，猫跳觸鼎翻。", "（《北夢瑣言》七、《詩話總龜》三九《詼諧門》。", "參見同書八《評論門》引《談苑》）（〖1〗《懷江上》之題，僅見《談苑》引，爲「餓猫」二句之題，另二聯題未詳。", "〖2〗五舉，《北夢瑣言》作「二十五舉」。", "〖3〗「犬刺」，《北夢瑣言》作「狗觸」。", "）。"]'),
('81bf3631-41cc-4fb8-8773-4f5f5c30866c','詠白鹽山（許太尉宗憲鎮寧江日，辟劉隱辭爲節度掌書記。宗憲武人，多爲恣橫，隱辭諫不聽。遂詠《白鹽山》、《灧澦堆》詩刺之云云。宗憲聞而發怒，將殺之。已而舍之，遂遁去。）','劉隱辭','唐','唐诗','tang','','[]','占斷瞿塘一峽煙，危峯迥出衆峯前。',69,'全唐诗/poet.tang.51000.json','["占斷瞿塘一峽煙，危峯迥出衆峯前。", "都緣頑梗揎浮世，遮莫崢嶸倚半天。", "有樹只知引（一作栖）鳥雀，無雲不易駐神仙。", "假饒突兀高千丈，爭及平平數畝田。"]'),
('dd30de89-48ec-4580-b3a5-e6e33b2d58aa','詠灧澦堆','劉隱辭','唐','唐诗','tang','','[]','灧澦崔嵬百萬秋，年年出沒幾時休。',80,'全唐诗/poet.tang.51000.json','["灧澦崔嵬百萬秋，年年出沒幾時休。", "未容寸土生纖草，能向當江覆巨舟。", "無事便騰千尺浪，與人長作一堆愁。", "都緣不似蟠溪石，難使漁翁下釣鈎。", "（以上《鑑誡錄》五《因詩辱》）。"]'),
('a3c77182-2e5a-4253-b59e-e202f123702f','詠僧道二門論難','劉隱辭','唐','唐诗','tang','','[]','爲僧爲道兩悠悠，若箇能分聖主憂。',75,'全唐诗/poet.tang.51000.json','["爲僧爲道兩悠悠，若箇能分聖主憂。", "各鬬輪蹄朝紫殿，競稱卿監滿皇州。", "相嘲相詠何時了，爭利爭名早晚休。", "閑想邊庭荷戈將，功成猶自不封侯。", "（同上六《旌論衡》）。"]'),
('e0596b2c-59df-4a45-a331-076726b15dfd','題九頭鳥','楊義方','唐','唐诗','tang','','[]','三百禽中爾最靈，就中惡爾九頭名。',78,'全唐诗/poet.tang.51000.json','["三百禽中爾最靈，就中惡爾九頭名。", "數年雲外藏兇影，此夜天邊發差聲。", "好惜羽毛還鬼窟，莫留災害與蒼生。", "况當社稷延洪日，不合鳴時莫亂鳴。", "（《鑑誡錄》六《怪鳥應》）。"]'),
('935c91c1-fc5c-4528-a5c0-73b0741b87e7','生日歌（略）（太祖爲蜀王時，方搆大業，莫不賦輿〖一作「役」〗增益，轉運煩苛，百姓困窮，無敢言者。因太祖生辰，涓獨獻一歌，先紀王功，後陳生聚〖一作「衆困」〗。太祖曰：「如卿忠讜，寡人王業何憂。」遂賜黃金十斤，以旌禮諷諫，於是徭役稍減矣。議者以君臣道合，黎庶泰來，苟非明王，何以采納。《生日歌》略云：）','馮涓','唐','唐诗','tang','','[]','百姓富，軍食足，百姓足，軍民歡。',48,'全唐诗/poet.tang.51000.json','["百姓富，軍食足，百姓足，軍民歡。", "爭那生靈饑且寒，吾王有術應不難。", "但令一斗徵一斗，自然百姓富於官。"]'),
('e8824c24-1230-4620-9356-a2c13dec6b57','嶮竿歌','馮涓','唐','唐诗','tang','','[]','山嶮驚摧車，水嶮怕覆舟。',181,'全唐诗/poet.tang.51000.json','["山嶮驚摧車，水嶮怕覆舟。", "奈何平地不肯立，沿上百尺高竿頭。", "我不知爾是人耶猿耶復猱耶，教我見爾爲爾長嘆嗟。", "我聞孝子不許國，我聞忠臣不憂家。", "爾即輕命重黃金，忠孝全虧徒爾誇。", "常將嶮藝悅君目，終日貪心媚君祿。", "百尺高竿百度沿，一足參差一家哭。", "嶮竿兒，聽我語，更有嶮竿嶮於汝。", "解從上處失君恩，落向天涯海邊去。", "嶮竿兒，爾須知，嶮處欲往宜爾思。", "上得欲下下不得，我謂此輩嶮於嶮竿兒。"]'),
('a8af2e7d-618b-4d06-907a-b71dbee36706','酒令（涓與王司空鍇等小酌，巡故字令。鍇舉一字三呼，兩物相似。鍇令曰：）','馮涓','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('2861ea4e-d14d-4775-b809-96f652d6bf59','酒令（涓與王司空鍇等小酌，巡故字令。鍇舉一字三呼，兩物相似。鍇令曰：） 一','馮涓','唐','唐诗','tang','','[]','樂樂樂，冷淘似餺飥。',36,'全唐诗/poet.tang.51000.json','["樂樂樂，冷淘似餺飥。", "（涓曰云云，合座大咍，涓獨不笑，但仰視長嘯而已。", "）。"]'),
('6a8afe28-3633-4b20-b7f4-c0eb82c17898','酒令（涓與王司空鍇等小酌，巡故字令。鍇舉一字三呼，兩物相似。鍇令曰：） 二','馮涓','唐','唐诗','tang','','[]','巳巳巳，驢糞似馬屎。',26,'全唐诗/poet.tang.51000.json','["巳巳巳，驢糞似馬屎。", "（以上《鑑誡錄》四《輕薄鑑》）。"]'),
('0913e981-1006-4dda-89bd-1f1aa60037f2','嘲李珣（賓貢李珣，字德潤，本蜀中土生波斯也。少小苦心，屢稱賓貢，所吟詩句，往往動人。尹校書鶚者，錦城煙月之士，與李生常爲善友。遽因戲遇嘲之，李生文章，掃地而盡。詩曰：）','尹鶚','唐','唐诗','tang','','[]','異域從來不亂常，李波斯強學文章。',46,'全唐诗/poet.tang.51000.json','["異域從來不亂常，李波斯強學文章。", "假饒折得東堂桂，胡臭薰來也不香。", "（《鑑誡錄》四《斥亂常》）。"]'),
('18ba6404-ba90-487f-8cf4-9d880cc5ddd0','詠渾家樂（二首） 一','陳裕','唐','唐诗','tang','','[]','晨起梳頭午不休，一窠精魅鬧啾啾。',68,'全唐诗/poet.tang.51000.json','["晨起梳頭午不休，一窠精魅鬧啾啾。", "阿家解舞《清平樂》，新婦能拋白木毬。", "著綠桃牌吹觱篥，賜緋盟器和《梁州》。", "天明任你渾家樂，雨下還須滿舍愁。"]'),
('0e89beae-77ea-46b5-a913-3370c3beafaa','詠渾家樂（二首） 二','陳裕','唐','唐诗','tang','','[]','北郡南州處處過，平生家計一驢獁。',63,'全唐诗/poet.tang.51000.json','["北郡南州處處過，平生家計一驢獁。", "囊中錢物衣裝少，袋裏燕脂胡粉多。", "滿子面甜糖餅，蕭娘身瘦鬼常娥。", "怪來喚作渾家樂，骨子貓兒盡唱歌。"]'),
('31ed4761-6939-47c6-8ef5-a690e90aec15','過舊居','陳裕','唐','唐诗','tang','','[]','昔日顏回宅，今爲裹飯家。',58,'全唐诗/poet.tang.51000.json','["昔日顏回宅，今爲裹飯家。", "不聞吟秀句，只見𫗕（一作餔）油麻。", "豉汁鍋中沸，粕餻案上葩（一作爬）。", "朝朝唯早起，檐從自排衙。"]'),
('5ffa0995-729e-4758-bd66-09a6d39b8da8','有一秀才忽贖酒家青衣爲婦（一作活）因嘲之','陳裕','唐','唐诗','tang','','[]','秀才何事太怱怱，琴瑟無媒便自通。',64,'全唐诗/poet.tang.51000.json','["秀才何事太怱怱，琴瑟無媒便自通。", "新婦旋裙纔離體，外姑托布尚當胸。", "菜團箇箇皆鉗項，粳米頭頭盡翦鬃。", "一自土和逃走後，至今失却親家翁。"]'),
('d0788381-649d-4d28-814f-f448f3cfef9a','詠大慈寺齋頭鮮于闍梨','陳裕','唐','唐诗','tang','','[]','酒肉終朝沒闕時，高堂大舍養肥屍。',64,'全唐诗/poet.tang.51000.json','["酒肉終朝沒闕時，高堂大舍養肥屍。", "行婆滿院多爲婦，童子成行半是兒。", "面折掇齋窮措大，笑迎搽粉阿尼師。", "一朝若也無常至，劍樹刀山不放伊。"]'),
('84e360b6-93ac-4aef-9a8d-01444b144191','放生池（大慈寺東北有池，號曰放生池。蜀人競以三元日，多將鵝鴨放在池中。裕因謁主池僧不遇，當門書一絕句，自此放生稍息矣。）','陳裕','唐','唐诗','tang','','[]','鵝鴨同羣世所知，蜀人競送放生池。',32,'全唐诗/poet.tang.51000.json','["鵝鴨同羣世所知，蜀人競送放生池。", "比來養狗圖雞在，不那闍梨是野貍。"]'),
('5c0e6666-f0c9-4990-902e-c17f2f4219a2','詠深沙（裕後詠深沙一絕，因暴疾而終，亦由神折天年，抑又神其靈也。詩曰：）','陳裕','唐','唐诗','tang','','[]','瞋（一作「橫」）眉努目強乾嗔，便作閻浮有力神。',55,'全唐诗/poet.tang.51000.json','["瞋（一作「橫」）眉努目強乾嗔，便作閻浮有力神。", "禍福豈由泥擔漢，燒香供養弄蛇人。", "（以上《鑑誡錄》十《攻雜詠》）。"]'),
('7faa0441-f74a-466c-9fc7-2bba55d975cd','題驛門（禹卿會後主東遊，上表極諫，及後主被誅，禹卿痛哭，題詩于驛門而遁。雍守捕之，禹卿已還蜀矣。）','蒲禹卿','唐','唐诗','tang','','[]','我王銜璧遠稱臣，何事全家幷殺身。',78,'全唐诗/poet.tang.51000.json','["我王銜璧遠稱臣，何事全家幷殺身。", "漢捨子嬰名尚在，魏封劉禪事獨新。", "非干大國渾無識，都是中原未有人。", "獨向長安儘惆悵，力微何路報君親。", "（《鑑誡錄》七《陪臣諫》）。"]'),
('7dc222fb-8023-4115-8655-3364ea89cd81','寄弟詩（唐末，盧拾遺議與鄭中舍延休作贅，三年不歸陝下。其兄誥以詩讓之，詩意甚乖昆仲之禮。盧議呈其太山中舍，幷女遣之。誥寄弟詩曰：）','盧誥','唐','唐诗','tang','','[]','三年作贅在京城，著箇緋衫倚勢行。',124,'全唐诗/poet.tang.51000.json','["三年作贅在京城，著箇緋衫倚勢行。", "夜夜貪憐紅粉女，朝朝渾忘白頭兄。", "親情別後饑寒死，僕使歸來氣宇生。", "世上可能容此事，算來天道不分明。", "（《鑑誡錄》八《非告勒》）（〖1〗鄭延休官中書舍人爲咸通末年事，詳岑仲勉《翰林學士壁記注補》十二，因知盧誥即其時人。", "）。"]'),
('6f29bf8e-086f-4e06-bf26-36c43be82918','因聘女自爲內相醉酬新郎催妝之詩（詩意風豔之甚，親族聞者，莫不笑之。）','馬彥珪','唐','唐诗','tang','','[]','莫飛篇翰苦相煎，款款容人帖翠鈿。',37,'全唐诗/poet.tang.51000.json','["莫飛篇翰苦相煎，款款容人帖翠鈿。", "不是到來梳洗晚，却憂玉體未禁憐。", "（同上）。"]'),
('46574468-8b98-482a-b8ca-1371611a011d','和韋莊賀陳詠歸蜀（句）（唐前朝進士陳詠，眉州青神人，有詩名，善弈棊。昭宗劫遷，駐蹕陝郊，是歲策名歸蜀，韋書記莊以詩賀之。又有鄉人拓善者，屬和韋詩，其略云云，譏其比滌器當壚也。謬稱馮副使涓詩，以涓多諧戲故也。或云：蜀之拓善者作此詩，假馮公之名也。）','拓善','唐','唐诗','tang','','[]','讓德已聞多士伏，沽名還得世人聞。',89,'全唐诗/poet.tang.51000.json','["讓德已聞多士伏，沽名還得世人聞。", "〖2〗（《北夢瑣言》七）（〖1〗拓善，《唐詩紀事》卷七十一引作「鄉中有嫉善者」，疑「拓善」並非人名。", "〖2〗《全唐詩》卷七九六收二句於無名氏下。", "）。"]'),
('95473367-23fe-413f-b022-e2c9823a0e08','','馮銖','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('409b1373-9ea3-458d-bc68-41263efa41f4','靈巖秋月','馮銖','唐','唐诗','tang','','[]','青松崖上紫雲生，崖下仙人約舊盟。',51,'全唐诗/poet.tang.51000.json','["青松崖上紫雲生，崖下仙人約舊盟。", "駐馬看碑驚化鶴，暮雲回首萬家城。", "（《蜀中名勝記》八《成都府·資縣》）。"]'),
('66719b81-aa76-4c75-bead-1240beb26a14','簡州（句） 一','范禹偁','唐','唐诗','tang','','[]','使君橋柳凝清鏡，玉女山煙展畫屏。',16,'全唐诗/poet.tang.51000.json','["使君橋柳凝清鏡，玉女山煙展畫屏。"]'),
('44e47a48-8bc2-4157-a578-43399fda97b2','簡州（句） 二','范禹偁','唐','唐诗','tang','','[]','繞城山雪自粧點，三縣人煙共接連。',144,'全唐诗/poet.tang.51000.json','["繞城山雪自粧點，三縣人煙共接連。", "（《輿地紀勝》一四五《簡州》）（〖1〗《全唐詩》無范禹偁詩，茲據《十國春秋》卷五三補傳：范禹偁，九隴人。", "天成中登第，孟知祥以爲蒙陽令，入侍太子。", "後蜀後主孟昶嗣位後，累兼翰林學士，曾兼簡州刺史。", "蜀亡，從後主歸宋，授鴻臚卿，開寶三年尚在世。", "〖參張忱石考證〗）。"]'),
('85a1a92c-37d5-4d00-a105-4292ab24f671','夏雨登干霄亭上宋使君（二首） 一','貫休','唐','唐诗','tang','','[]','霽色澄鮮壑映紅，干霄亭上望無窮。',65,'全唐诗/poet.tang.51000.json','["霽色澄鮮壑映紅，干霄亭上望無窮。", "蟬驚殘雨疑秋蚤，雷傍嚴城報歲豐。", "歸廟片雲銜紫電，立查雙鶴唳仙風。", "自憐四郡干戈日，得在文翁教化中。", "。"]'),
('b3188200-8774-4f17-8dec-4dc6aece7055','夏雨登干霄亭上宋使君（二首） 二','貫休','唐','唐诗','tang','','[]','鄒魯封疆禾稼濃，清吟孤坐思重重。',64,'全唐诗/poet.tang.51000.json','["鄒魯封疆禾稼濃，清吟孤坐思重重。", "新詩幾獻蓬萊客，遠夢仍歸菡萏峯。", "野果一枝堪薦茗，落霞數片欲燒松。", "如何深得冥搜癖，月磬聲聲歸去慵。"]'),
('82637e97-88a3-4903-8db6-3c220a5901cc','宋使君罷新定移出東館（二首） 一','貫休','唐','唐诗','tang','','[]','無爲政化更何爲，到即生人嫗煦肥。',64,'全唐诗/poet.tang.51000.json','["無爲政化更何爲，到即生人嫗煦肥。", "必似漢高三傑去，且將劉寵一錢歸。", "玉階香惹麒麟步，銀漢風驅鸑鷟飛。", "爲報蒸民莫惆悵，陶鈞及爾更光輝。"]'),
('f38d5d25-7d40-4f73-99c6-54d768c7fe6d','宋使君罷新定移出東館（二首） 二','貫休','唐','唐诗','tang','','[]','祖筵四面煙花合，江館深冬歸思長。',64,'全唐诗/poet.tang.51000.json','["祖筵四面煙花合，江館深冬歸思長。", "火斾畫旗風燄燄，橘洲漁舍浪茫茫。", "聽歌幾入紅蘭榭，坐隱頻升白玉堂。", "今數不如沙磧雁，天邊一一得隨陽。"]'),
('45da7e45-3e26-462b-91b6-29d7fb63e12c','寄杭州宋使君（公初罷睦州）','貫休','唐','唐诗','tang','','[]','一自雙旌下釣臺，望風吟苦凍雲開。',64,'全唐诗/poet.tang.51000.json','["一自雙旌下釣臺，望風吟苦凍雲開。", "即歸紫闥天非遠，猶憶烏龍首獨回。", "高節似僧僧共坐，暮潮如雪雪中來。", "應知新定蒼生淚，灑向東風祝上台。"]'),
('b0a9afe9-807f-4a8f-bf75-5eb48fe0f446','游嚴陵釣臺','貫休','唐','唐诗','tang','','[]','雪浪皚皚萬古情，岸邊臺占子陵名。',64,'全唐诗/poet.tang.51000.json','["雪浪皚皚萬古情，岸邊臺占子陵名。", "一時大器天將與，數尺漁竿誰不擎。", "危榭高碑鐫籀字，滄洲老鶴識先生。", "游人到此慵歸去，庭樹孤猿有好聲。"]'),
('fc5fd97d-ec75-4bae-a148-4c67c2bb1770','新定江邊作','貫休','唐','唐诗','tang','','[]','江邊山頂深秋時，身閑瀟灑心無爲。',86,'全唐诗/poet.tang.51000.json','["江邊山頂深秋時，身閑瀟灑心無爲。", "石頭青草取次坐，松風竹風撩亂吹。", "數聲好鳥來依我，一點征帆去是誰。", "惆悵古賢何處在，潺潺夕照滿江湄。", "（日落山照燿，即此處也。", "以上《嚴陵集》二）。"]'),
('6ebb3829-3e84-410f-935a-c4c9a40737b7','送軒轅先生歸羅浮山（初，貫休詩名未振。時南楚才人，競以詩送軒轅先生歸羅浮山，計百餘首矣。後貫休因吟一章，羣公於是息筆。）','貫休','唐','唐诗','tang','','[]','玉房花洞接三清，謾指羅浮是去程。',78,'全唐诗/poet.tang.51000.json','["玉房花洞接三清，謾指羅浮是去程。", "龍馬便攜笻竹杖，山童常使茯苓精。", "曾教莊子拋卑吏，却喚軒皇作老兄。", "再見先生又何日，只應頻夢紫金城。", "（《鑑誡錄》五《禪月吟》）。"]'),
('d1a254dc-6b00-473d-b17c-ac3ed1d2a059','題天壇','杜光庭','唐','唐诗','tang','','[]','壁立三千仞，壇高接尾箕。',132,'全唐诗/poet.tang.51000.json','["壁立三千仞，壇高接尾箕。", "頂藏青玉髓，腰隱紫金芝。", "月掛虛皇殿，雲封太乙池。", "洞天人跡少，鶴宿萬年枝。", "（《古今圖書集成·山川典》四六《王屋山部》）（〖1〗《正統道藏》本杜光庭《天壇王屋山聖迹記》收此詩於通真道人名下。", "通真道人生平未詳。", "乾隆《濟源縣志》卷十六作姚合詩。", "）。"]'),
('12d76f03-2e09-4e29-b35c-126121d0b489','上清宮（句）','杜光庭','唐','唐诗','tang','','[]','十年重到上清宮，石磴泉梯屈曲通。',33,'全唐诗/poet.tang.51000.json','["十年重到上清宮，石磴泉梯屈曲通。", "（《輿地紀勝》一五一《永康軍》）。"]'),
('a17f94fe-fb73-44ab-b302-8e648fb86135','','光業','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('dbd6a09d-cf43-434a-a9c3-409b8e3b6760','徵李懷杲（一作果）嘲道門 一','光業','唐','唐诗','tang','','[]','雲鎖涪江水似天，又聞懷杲已升仙。',77,'全唐诗/poet.tang.51000.json','["雲鎖涪江水似天，又聞懷杲已升仙。", "強思齊見應催膽，張茂卿聞必聳肩（強與張二玄士）。", "三尺霜刀（一作鋒）充絳節，兩條朱棒替香煙。", "報伊廣德先生道，社稷威靈不偶然。"]'),
('395d53e7-dcb2-4163-82ca-609458de9ac2','徵李懷杲（一作果）嘲道門 二','光業','唐','唐诗','tang','','[]','山上擒來鎮裏收，天然模樣已成囚。',89,'全唐诗/poet.tang.51000.json','["山上擒來鎮裏收，天然模樣已成囚。", "妄占氣色爲徵兆，更引文章說御樓。", "長牓數張懸市內，短刀一隊送江頭。", "旋驅旋斬教隨水，只此名爲正道流。", "（〖1〗以上二首原作一首，從趙遂之說分爲二首。", "）。"]'),
('f807e1a4-770b-4e64-b345-468998331689','嘲道門進《武成混元圖》','光業','唐','唐诗','tang','','[]','夜深燈火滿壇舖，拔劍揮空亂叫呼。',75,'全唐诗/poet.tang.51000.json','["夜深燈火滿壇舖，拔劍揮空亂叫呼。", "黑撒半筐兵甲豆，朱書一道厭人符。", "重臣餧飼剛教活，聖主慈悲未忍誅。", "佛說毘盧三界了（一作「乃三界」），如何更有《混元圖》。"]'),
('502f98e1-70e9-43af-a8ff-9dc1681ef043','徵青州長老嘲僧門 一','楊德輝','唐','唐诗','tang','','[]','堪笑青州學坐禪，不供父母不耕田。',64,'全唐诗/poet.tang.51000.json','["堪笑青州學坐禪，不供父母不耕田。", "口中雖道無諸相，心裏元來有外緣。", "行者趁教門裏臥，尼師留在脚頭眠。", "高標不使觀音救，徒說三千與大千。"]'),
('25e900c7-8094-486a-8052-767d194a9f56','徵青州長老嘲僧門 二','楊德輝','唐','唐诗','tang','','[]','出家比要離生緣，爭是爭名更在先。',94,'全唐诗/poet.tang.51000.json','["出家比要離生緣，爭是爭名更在先。", "說法謾稱獅子吼，魅人多使野狐涎（一作禪）。", "行婆餉送新童子，居士抄條施利錢。", "蠶食萬民何所用，轉教海內有荒田。", "（〖1〗以上二首原作一首，從趙遂之說分爲二首。", "）。"]'),
('6cb49e87-3390-4723-aaba-7eb87f2ced3d','嘲僧門祝辟支佛牙','楊德輝','唐','唐诗','tang','','[]','比來降誕爲官家，堪笑羣胡讚佛牙。',80,'全唐诗/poet.tang.51000.json','["比來降誕爲官家，堪笑羣胡讚佛牙。", "手軟阿師持磬鈸，面甜童子執幡花。", "縱饒黎庶無知識，不可公王盡信邪。", "捧擁一函枯骨立，如何延得壽無涯。", "（以上《鑑誡錄》六《旌論衡》）。"]'),
('b3118f69-7930-4582-9023-1b76c8e7ce7b','落韻詩（二首） 一','李如實','唐','唐诗','tang','','[]','路傍傷羸牛，羸牛身已老。',72,'全唐诗/poet.tang.51000.json','["路傍傷羸牛，羸牛身已老。", "兩眼不能開，四蹄行欲倒。", "牛曾少壯時，歲歲耕田早。", "耕却春秋田，駕車長安道。", "今日領頭穿，無人飼水草。", "喘也不能喘，問也沒人問。"]'),
('f8d31359-45e7-4236-9011-efae45bf7b70','落韻詩（二首） 二','李如實','唐','唐诗','tang','','[]','炎蒸不可度，執（一作倏，又作賴）爾生涼風。',71,'全唐诗/poet.tang.51000.json','["炎蒸不可度，執（一作倏，又作賴）爾生涼風。", "在物誠非器，於人還有功。", "殷勤九夏內，寂寞三秋中。", "想君應有語，棄我如秋扇。", "（《鑑誡錄》三《落韻貶》）。"]'),
('e42404c6-e1f2-461a-8e5f-0b0e8a4ab4dc','','令狐嶠','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('f6ed9200-a112-409b-b269-40cdb7086143','明慶節散後贈左右兩街命服僧玄','令狐嶠','唐','唐诗','tang','','[]','卻羨僧門與道門，元年今日紫衣新。',32,'全唐诗/poet.tang.51000.json','["卻羨僧門與道門，元年今日紫衣新。", "可憐州縣祁評事，盡向荷衣老卻身。"]'),
('5cc6137d-38f3-4e24-8a47-a5a557338f6f','詠有年官健','令狐嶠','唐','唐诗','tang','','[]','六十休論少壯時，尉遲功業擬奚爲。',53,'全唐诗/poet.tang.51000.json','["六十休論少壯時，尉遲功業擬奚爲。", "高聲念佛尋街者，盡是抝（一作拘）停老健兒。", "（以上《鑑誡錄》四《蜀門諷》）。"]'),
('d8c55095-f15b-405c-9a95-5f7816f978b1','詠人祀聖君詩','鄭雲從','唐','唐诗','tang','','[]','禍福從來豈自主（一作由），俗情淫祀也堪愁。',42,'全唐诗/poet.tang.51000.json','["禍福從來豈自主（一作由），俗情淫祀也堪愁。", "拜時何用頻偷眼，未必泥人解點頭。", "（同前）。"]'),
('1e0892dd-2470-48c6-aaa9-00c3985bb4e4','乘煙觀蔣鍊師（蔣甚偉，非婦人之狀。）','向瓚','唐','唐诗','tang','','["\u5e90\u5c71"]','怪得盤跚不上昇，白雲蹋綻紫雲崩。',153,'全唐诗/poet.tang.51000.json','["怪得盤跚不上昇，白雲蹋綻紫雲崩。", "龍腰鳳背猶嫌軟，須問麻姑借大鵬。", "（同前）（〖1〗曹汛謂向瓚爲何瓚之誤。", "《全唐詩》卷七六九收何贊，亦應作何瓚。", "事迹見《新五代史》卷二八本傳。", "今按：《南唐近事》有陳沆諷廬山道士絕句，與此大同小異。", "陳詩收）（《全唐詩》卷七五七。", "《鑑誡錄》成書早於《南唐近事》，詩以向作爲近是。", "）。"]'),
('a5c58041-2ab2-4be1-916a-4841cfc28bc8','獻賀捷詩（孟知祥入梓州，舉子勾龍逢獻詩云云，孟知祥嘉納之。）','勾龍逢','唐','唐诗','tang','','[]','唇齒論交歲月長，豈其率意忽顛狂。',136,'全唐诗/poet.tang.51000.json','["唇齒論交歲月長，豈其率意忽顛狂。", "元戎統領三軍戰，巨孽奔衝一陣亡。", "莫訝潼江剛入寇，都緣錦浦合興王。", "武功蓋世光前後，堪向青編萬古揚。", "（《全五代詩》五七引《十國春秋》）（〖1〗見《鑑誡錄》卷一《知機對》、《十國春秋》卷四八《後蜀高祖本紀》。", "孟知祥入梓州，爲長興三年五月間事。", "）。"]'),
('b535d286-dd18-4446-862c-f1dcc98551c1','凌霄花','歐陽炯','唐','唐诗','tang','','[]','凌霄多半繞棕櫚，深染梔黃色不如。',50,'全唐诗/poet.tang.51000.json','["凌霄多半繞棕櫚，深染梔黃色不如。", "滿樹微風吹細葉，一條龍甲颭清虛。", "（《古今圖書集成·草木典·苕部》）。"]'),
('c2fb05e8-e996-4750-800b-e9fa31507445','至真觀（三言詩）（仁傑善導氣烹鍊之術。孟知祥鎮西川時。來蜀留詩至真觀壁間。）','杜仁傑','唐','唐诗','tang','','[]','坤所載，乾所幬，象與形，孰朕兆？',460,'全唐诗/poet.tang.51000.json','["坤所載，乾所幬，象與形，孰朕兆？", "緯五行，環二曜，流百川，何浩浩。", "四海晏，九河導，峙而山，亦多號。", "神有嶽，山有嶠，粤廟（一作「天」）壇，稽（一作「極」）道妙。", "巉孤崢（一作「撐」），未易到，日出沒，見遺照。", "偃東西，絕海徼，倐光怪，來熠耀。", "大龍燭，細螢爝，不恆出，赴感召。", "笙嘹喨，鶴窈窕，羽人路，屯其要。", "青螺堆，玉簪峭。", "左參井，右丹竈，揭清虛，不二竅。", "昔王人，往昭告，始軒轅，末徽廟。", "接柴望，咸親燎，莽刼灰，起天燒。", "摧棟宇，失朱縹。", "羣鹿逐（一作「豕」），雜蓬藋。", "予何爲，一來弔，必勝廢，乃大造。", "聖之作，賢者紹，矧玄元，語秘奧。", "探愈遠，理益耀，徵是理，萬有耗。", "文雖徑（一作「怪」），實非剽，庶今來，永爲詔。", "（《全蜀藝文志》二三、《十國春秋》五七）（〖1〗《正統道藏》本杜光庭《天壇王屋山聖迹記》末附錄此詩，署「齊人杜仁傑撰」，末署「至元二十六年五月□日」。", "至元爲元代年號。", "臺灣學者編《元人傳記資料索引》有杜仁傑小傳云：「杜仁傑，字仲梁，號止軒，原名之元，字善夫，濟南長清人。", "金末隱內鄉山中。", "至元中屢徵不起。", "」爲綜合多種資料編成。"]'),
('d36313c3-10dd-4540-b7a0-742f39920f6f','偈詩','張嶠','唐','唐诗','tang','','[]','毳流來問我家風，我道玲瓏處處通。',33,'全唐诗/poet.tang.51000.json','["毳流來問我家風，我道玲瓏處處通。", "頃刻萬邦皆徧到，途中曾未一人逢。", "。"]'),
('bf33f32e-5e4c-4a9d-bfe8-e4f115c20a52','句 一（有勾居士問：「不拘生死者，願師直指。」嶠答云：）','張嶠','唐','唐诗','tang','','[]','非干日月照，晝夜自分明。',12,'全唐诗/poet.tang.51000.json','["非干日月照，晝夜自分明。"]'),
('96a1a5e5-875b-41e7-98f0-1072a99cda19','句 二（又問：「百億往來非指的，光明終不礙山河時如何？」嶠答云：）','張嶠','唐','唐诗','tang','','[]','紅尾漫搖三尺浪，真龍透石本無踪。',28,'全唐诗/poet.tang.51000.json','["紅尾漫搖三尺浪，真龍透石本無踪。", "（以上《茅亭客話》三）。"]'),
('ff279c18-e9f5-4564-a167-2fd1529dff97','敬禮瓦屋和尚塔偈（瓦屋和尚名能光，日本國人。）','勾令玄','唐','唐诗','tang','','[]','大空無盡劫成塵，玄步孤高物外人。',105,'全唐诗/poet.tang.51000.json','["大空無盡劫成塵，玄步孤高物外人。", "日本國來尋彼岸，洞山林下過迷津。", "流流法乳誰無分，了了教知我最親。", "一百六十三歲後，方於此塔葬全身。", "（同上）（〖1〗勾令玄，原作勾令元，爲清人諱改，從穴研齋影宋本《茅亭客話》改。", "）。"]'),
('7c099011-5629-4df9-8c76-8f2a1f45ad66','','淘沙子','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('51efdb64-f013-4b25-a016-1dbe5fab2825','詩','淘沙子','唐','唐诗','tang','','[]','九重城裏人中貴，五等諸侯閫外尊。',120,'全唐诗/poet.tang.51000.json','["九重城裏人中貴，五等諸侯閫外尊。", "爭似布衣雲水客，不將名字掛乾坤。", "（同上）（〖1〗《全蜀藝文志》卷二三、《全唐詩》卷七六一收此詩爲丁元和作，《全五代詩》卷六十云丁元和號淘沙子。", "《茅亭客話》卷四載丁元和事迹較詳，與卷三所載之淘沙子似非一人。", "）。"]'),
('e857fd39-d229-4725-a685-a5008d0e1c25','遺詩','宋自然','唐','唐诗','tang','','[]','心是靈臺神是室，口爲玉池生玉液。',160,'全唐诗/poet.tang.51000.json','["心是靈臺神是室，口爲玉池生玉液。", "常將玉液溉靈臺，流利關元滋百脈。", "百脈潤，柯葉青，葉青柯潤便長生。", "世人不會長生藥，煉石燒丹勞爾形。", "（《茅亭客話》四）（〖1〗《全唐詩》無宋自然詩，茲據《茅亭客話》補其事跡：宋自然，長興中遂州貧士，常於街市中行乞。", "孟知祥攻圍遂州時，餓殍於州市。", "後有人云曾於潞州見之，又於其埋處得遺詩一紙。", "）。"]'),
('acefc38c-725f-4f7f-8201-9472d63244e2','書妙圓塔院張道者屋壁（蜀大東門外有妙圓塔院，僧名行勤，俗姓張氏，人以其精於修行，因謂之道者。）','慈覺','唐','唐诗','tang','','[]','成都有一張道者，五十年來住村野。',274,'全唐诗/poet.tang.51000.json','["成都有一張道者，五十年來住村野。", "祇將淡薄作家風，未省承迎相苟且。", "南地禪宗盡偏參，西蜀叢林遊已罷。", "深知大藏是解粘，不把三乘定真假。", "張道者，傍沙溪，居蘭若，草作衣裳茅作舍。", "活計生涯一物無，免被外人來借借。", "寅齋午睡樂咍咍，檀越供須都不謝。", "沿身不直五分銅，一句玄玄豈論價。", "張道者，貌古神清不可畫。", "鶴性雲情本自然，生死無心全不怕。", "縱逢刼火未爲災，暗裏龍蛇應歎訝。", "張道者，不說禪，不答話，蓋爲人心難誘化。", "盡奔名利謾馳驅，個個何曾有般若。", "分明與說速休心，供家卻道也爛也。", "張道者，不聚徒，甚脫灑，不結遠公白蓮社。", "心似秋潭月一輪，何用聲名播天下。", "（《茅亭客話》三）。"]'),
('9ae61afd-0ed7-4e15-b0ff-5e082eff3a57','蒸豚（王中令既平蜀，捕逐餘寇，與步隊〖隊伍〗相遠，饑甚，乃入一村寺中。主僧醉甚箕踞，公怒，欲斬之。僧應對不懾，公奇而釋之。間求蔬食，僧云：「有肉無蔬。」公益奇之。餽以蒸豚頭，食之甚美。公喜，問僧：「止能飲酒食肉耶，抑有他技耶？」僧自言能詩。公令賦蒸豚詩，援〖操〗筆立成。詩云〖見下〗。公大喜，與紫衣，賜號爲蜀中詩僧。）','村寺僧','唐','唐诗','tang','','[]','嘴長毛短淺含臕，久向山中食藥苗。',146,'全唐诗/poet.tang.51000.json','["嘴長毛短淺含臕，久向山中食藥苗。", "蒸處已將蒸葉裹，熟時兼（一作「更」）用杏漿澆。", "紅鮮雅稱食盤飣（一作貯），軟熟真堪玉筯挑。", "若把羶根來比並，羶根只合喫（一作「喚」）藤條。", "（《五代詩話》七引《百斛明珠》。", "《全五代詩》六十引《東坡志林》）（〖1〗見《仇池筆記》卷下、《苕溪漁隱叢話前集》卷五十七。", "）。"]'),
('82840466-e431-495b-9da1-58596b5bcf84','詠後主出降（《後山詩話》以爲花蕊夫人作，但前二句多異文）','王承旨','唐','唐诗','tang','','[]','蜀朝昬主出降時，銜璧牽羊倒繫旗。',73,'全唐诗/poet.tang.51000.json','["蜀朝昬主出降時，銜璧牽羊倒繫旗。", "二十萬軍齊拱手，更無一箇是男兒。", "（《鑑誡錄》五《徐后事》）（〖1〗王承旨，應即王仁裕，詳《全唐詩續拾》卷四二。", "）。"]'),
('17fa1ded-ec1b-4ce6-9c90-773e488d99be','題九仙山','詹敦仁','唐','唐诗','tang','','[]','太白歌中昔未聞，佛天高處却逢君。',16,'全唐诗/poet.tang.51000.json','["太白歌中昔未聞，佛天高處却逢君。"]'),
('6cb2d119-b3d4-475a-adc9-f586c6339ff7','題二石將軍','詹敦仁','唐','唐诗','tang','','[]','屹然相對兩將軍，化石經年久臥雲。',16,'全唐诗/poet.tang.51000.json','["屹然相對兩將軍，化石經年久臥雲。"]'),
('0af9867f-d308-44f6-bb0d-712dac09b44a','題佛耳山','詹敦仁','唐','唐诗','tang','','[]','我愛佛耳山，來偷一日閑。',50,'全唐诗/poet.tang.51000.json','["我愛佛耳山，來偷一日閑。", "不見佛耳面，愧汗不開顏。", "有時見佛耳，與山重往還。", "（以上《嘉靖安溪縣志》七）。"]'),
('f4cf1642-e923-4310-869c-6393ec43e470','介庵贈古墨梅酬以一篇','詹敦仁','唐','唐诗','tang','','[]','開屏展素看梅花，淡蕊疎枝驀驀斜。',50,'全唐诗/poet.tang.51000.json','["開屏展素看梅花，淡蕊疎枝驀驀斜。", "墨散餘香點酥萼，月留殘影照窗紗。", "（《永樂大典》二八一二「梅」字韻）。"]'),
('1a852b93-f67a-47c9-aced-f1e3cbb1ea96','清隱堂','詹敦仁','唐','唐诗','tang','','[]','一間茅屋寬容膝，半畝蔬園剩供廚。',61,'全唐诗/poet.tang.51000.json','["一間茅屋寬容膝，半畝蔬園剩供廚。", "靜把舊書重點勘，旋沽美酒養疎愚。", "（一本作「縱教窮鬼每揶揄」）。", "（同上七二三九「堂」字韻）。"]'),
('585aa2fe-e725-47c1-8fca-a81617438955','題舫齋（原作詹時澤詩，敦仁字君澤，疑即一人）','詹敦仁','唐','唐诗','tang','','[]','尖頭屋子不嫌低，上有青山下有池。',46,'全唐诗/poet.tang.51000.json','["尖頭屋子不嫌低，上有青山下有池。", "一陣東風拂松響，恰如蓬底雨來時。", "（同上二五四○「齋」字韻）。"]'),
('67ce6052-2d98-48d5-9dd5-c72cd1ebc20e','承清隱命訪劉處士已歿因弔以詩','詹琲','唐','唐诗','tang','','[]','鳳髻山前鳳閣郎，耕雲釣石久荒凉。',44,'全唐诗/poet.tang.51000.json','["鳳髻山前鳳閣郎，耕雲釣石久荒凉。", "我來弔舊多悲感，一紙哀辭酹一觴。", "（《嘉靖安溪縣志》七）。"]'),
('ad019215-54c7-47be-98d6-acf219e03581','雨後溪邊見早梅','詹琲','唐','唐诗','tang','','[]','老榦疎枝浸寒碧，淺香孤韻帶微霜。',32,'全唐诗/poet.tang.51000.json','["老榦疎枝浸寒碧，淺香孤韻帶微霜。", "迎風破萼未全折，含笑佳人對曉粧。"]'),
('03f80977-301f-4472-a13d-08f8507abe52','又一本','詹琲','唐','唐诗','tang','','[]','老榦疎枝浸寒碧，淺香孤韻湛清晨。',50,'全唐诗/poet.tang.51000.json','["老榦疎枝浸寒碧，淺香孤韻湛清晨。", "招魂不用開屏障，惟有詩情當寫真。", "（《永樂大典》二八○八「梅」字韻）。"]'),
('45a9f3de-b4ea-495f-b1e1-21b4552a1425','詔福建置惠民倉呈陳守御史','詹琲','唐','唐诗','tang','','[]','閩邦赤子近來王，聖主憂勤念遠方。',86,'全唐诗/poet.tang.51000.json','["閩邦赤子近來王，聖主憂勤念遠方。", "酌取古人救荒政，頒爲今日惠民倉。", "備先水旱民亡瘠，弊在侵移數謾張。", "我願相君謹刑政，雨暘時若自平康。", "（同上七五一八「倉」字韻引詹琲《清隱集》）。"]'),
