('858ac78a-13ef-4117-8793-7be2e4a33ffe','','慧稜','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('63213afd-3251-4227-bdf1-98d86b971b66','捲簾大悟','慧稜','唐','唐诗','tang','','[]','也大差，也不差，捲起簾來見天下。',32,'全唐诗/poet.tang.51000.json','["也大差，也不差，捲起簾來見天下。", "有人問我解何宗，拈起拂子擘觜打。"]'),
('b2059b16-3607-4931-891e-09a39da37649','又口占一頌','慧稜','唐','唐诗','tang','','[]','萬象之中獨露身，惟人自肯乃相親。',139,'全唐诗/poet.tang.51000.json','["萬象之中獨露身，惟人自肯乃相親。", "昔時謬向途中覓，今日看來火裏冰。", "（《全五代詩》八七引《槜李詩繫》）（〖1〗見《槜李詩繫》卷三十。", "二詩最早出處爲《景德傳燈錄》卷十八，又見《五燈會元》卷七。", "「擘觜」，二書作「擘口」；「相親」，二書作「方親」；「看來」，《景德傳燈錄》作「看如」。", "）。"]'),
('aa978067-bae9-40aa-b383-fdb823a3939d','過三嶺苧溪','清豁','唐','唐诗','tang','','[]','世人休說行路難，鳥道羊腸咫尺間。',216,'全唐诗/poet.tang.51000.json','["世人休說行路難，鳥道羊腸咫尺間。", "珍重苧溪溪[畔]（上）水，汝歸[滄]（蒼）海我歸山。", "（《古今圖書集成·職方典》一○五二《泉州府部》〖2〗）（〖1〗《全唐詩》卷八八八收清豁詩一首，無傳，茲據《景德傳燈錄》卷二二、《宋詩紀事》卷九一補其事跡：清豁，福州永泰人，俗姓張。", "嗣睡龍道溥禪師，住漳州保福院。", "刺史陳洪進表奏，賜號性空禪師。", "太平興國年卒。", "原收入時）（代未詳僧，今移此。", "〖2〗《景德傳燈錄》卷二二以此詩爲清豁「遺偈」，今據以校改。", "）。"]'),
('19e10956-c420-4760-af10-87bd449b6d3b','陽朔道中','石仲元','唐','唐诗','tang','','[]','平原翠削萬瓊瑰，頓轡塵沙眼暫開。',107,'全唐诗/poet.tang.51000.json','["平原翠削萬瓊瑰，頓轡塵沙眼暫開。", "文網牽人寧底急，未妨得意看山來。", "（《全五代詩》六一）（〖1〗《古今圖書集成·職方典》卷一四○六《桂林府部》收此詩，題作《壽陽山》，第二句「暫」作「漸」，第四句「得意」作「特特」。", "）。"]'),
('28b186db-bd03-4bf7-ab3b-8e317f071da8','與何致雍僧貫徽聯句（馬希振爲鼎州節度使，馬氏諸子[中]白眉也。與門下客何致雍、僧貫徽聯句。） 一','馬希振','唐','唐诗','tang','','[]','青蛇每用腰爲力。',25,'全唐诗/poet.tang.51000.json','["青蛇每用腰爲力。", "（希振）紅莧時將葉作花。", "（貫徽）。"]'),
('7bbbf8ad-f1f4-4faa-9a14-6d0e2fc16c37','與何致雍僧貫徽聯句（馬希振爲鼎州節度使，馬氏諸子[中]白眉也。與門下客何致雍、僧貫徽聯句。） 二','馬希振','唐','唐诗','tang','','[]','蟻子子啣蟲子子。',95,'全唐诗/poet.tang.51000.json','["蟻子子啣蟲子子。", "（希振）猫兒兒捉雀兒兒。", "（致雍）〖1〗（《五代詩話》六引《續歸田錄》〖2〗）（〖1〗《續歸田錄》謂此二句爲「又見蟻子緣砌」作。", "〖2〗見《增修詩話總龜》卷二引《續歸田錄》。", "）。"]'),
('31aa39bf-09fe-41de-b6a7-b59f8a808b01','潭州（諷楚王之侈）','徐仲雅','唐','唐诗','tang','','[]','千里瀟湘琴瑟流，因思舊宅在鰲頭。',66,'全唐诗/poet.tang.51000.json','["千里瀟湘琴瑟流，因思舊宅在鰲頭。", "鑿開青帝春風浦，移下嫦娥夜月樓。", "（《永樂大典》五七七○「沙」字韻）（今按：《全唐詩》只有後二句。", "）。"]'),
('b079a815-2833-44e2-99cf-4173a2744032','弔賈島（句）','王元','唐','唐诗','tang','','[]','江城賣藥常將鶴，古寺看碑不下驢。',66,'全唐诗/poet.tang.51000.json','["江城賣藥常將鶴，古寺看碑不下驢。", "（《五代詩話》引《南唐逸史》）（〖1〗見《增修詩話總龜》卷十一引《唐宋遺史》，云爲「王元贈詩」。", "）。"]'),
('5ba1b5c5-e0c7-43b6-ad17-f20e210f6186','宿玉泉寺（句）','曾弼','唐','唐诗','tang','','[]','山偷半庭月，池印一天星。',13,'全唐诗/poet.tang.51000.json','["山偷半庭月，池印一天星。", "。"]'),
('61b3f0f2-77d2-43b0-bfb0-298fb545994e','君山（句）','曾弼','唐','唐诗','tang','','[]','翠壓魚龍窟，寒堆波浪心。',96,'全唐诗/poet.tang.51000.json','["翠壓魚龍窟，寒堆波浪心。", "（以上《詩話總龜》十四引《雅言系述》）（〖1〗楊億《武夷新集》卷八《劉氏太夫人天水縣太君趙氏墓碣銘》：「一女適曾弼，舉進士，終殿中丞。", "」趙氏卒于景德二年，年八十六。", "）。"]'),
('1d650475-d164-44c9-ad5a-5fe9581d0c89','南越行（句）','翁宏','唐','唐诗','tang','','[]','因尋買珠客，悮入射猿家。',12,'全唐诗/poet.tang.51000.json','["因尋買珠客，悮入射猿家。"]'),
('0a4ca91b-4b14-4dbf-ba1f-2795aca75b4d','細雨（句）','翁宏','唐','唐诗','tang','','[]','何處殘春夜，和花落古宮。',23,'全唐诗/poet.tang.51000.json','["何處殘春夜，和花落古宮。", "（「古」一作「漢」）。"]'),
('4cdc4cfb-99a4-4ed3-8ae9-a36b31990da0','途中逢宮人（句）','翁宏','唐','唐诗','tang','','[]','孤舟半夜雨，上國十年心。',37,'全唐诗/poet.tang.51000.json','["孤舟半夜雨，上國十年心。", "（以上《詩話總龜》十一《雅什門》引《雅言系述》）。"]'),
('24e252c9-f609-4e38-9193-75ed60e274b7','塞上曲（句）','翁宏','唐','唐诗','tang','','[]','風高弓力大（一作「滿」），霜重角聲枯（一作「乾」）。',26,'全唐诗/poet.tang.51000.json','["風高弓力大（一作「滿」），霜重角聲枯（一作「乾」）。"]'),
('60becc96-dabc-4abe-84c3-07542c09355a','海中山（句）','翁宏','唐','唐诗','tang','','[]','客帆來異域，別島落蟠桃。',12,'全唐诗/poet.tang.51000.json','["客帆來異域，別島落蟠桃。"]'),
('065779d8-c07e-427a-916c-cb24a3dd8ec3','中秋月（句）','翁宏','唐','唐诗','tang','','[]','寒清萬國土，冷浸（一作鬦）四維根。',60,'全唐诗/poet.tang.51000.json','["寒清萬國土，冷浸（一作鬦）四維根。", "（以上《詩藪雜編》四）（〖1〗以上三題，均見《增修詩話總龜》卷十一引《雅言系述》。", "）。"]'),
('1ef8eef6-1b21-45ca-8493-2910319bd1b4','鸂鶒','王鼎','唐','唐诗','tang','','[]','棲息應難近小池，性靈閒雅衆禽希。',64,'全唐诗/poet.tang.51000.json','["棲息應難近小池，性靈閒雅衆禽希。", "蒲洲日暖依花立，漁浦烟深貼浪飛。", "遺羽參差沾水沫，餘蹤稠疊印苔衣。", "晚來林徑微風起，何處相呼著對歸。"]'),
('2ae3bd8c-28dd-45bb-9e60-025b4af31375','洪州西山（句）','王鼎','唐','唐诗','tang','','[]','林泉空有東西路，風月難尋十二家。',57,'全唐诗/poet.tang.51000.json','["林泉空有東西路，風月難尋十二家。", "（以上《全五代詩》六二引《詩話總龜》）（〖1〗見《詩話總龜》卷三二引《拾遺》。", "）。"]'),
('7c2d6f5d-5d71-472d-95fe-ab95170066a1','','曹菘〖1〗','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('8cb2f854-ecd7-4fa8-b4c3-e78bdafa5d09','題衡山尋仙觀（句）','曹菘〖1〗','唐','唐诗','tang','','["\u8861\u5c71"]','千年松引東陵鶴，三級芝田草木香。',16,'全唐诗/poet.tang.51000.json','["千年松引東陵鶴，三級芝田草木香。"]'),
('85515f6a-e5ed-4428-a321-833ddb4fa503','贈陳先生（句）','曹菘〖1〗','唐','唐诗','tang','','[]','讀《太玄經》秋醮罷，註《參同契》夜燈微。',20,'全唐诗/poet.tang.51000.json','["讀《太玄經》秋醮罷，註《參同契》夜燈微。"]'),
('758a61a1-d9a5-4564-a194-7ada4b7a2b8c','經羅大夫故居（句）','曹菘〖1〗','唐','唐诗','tang','','[]','鹿眠荒圃寒蕪白，鴉噪殘陽敗葉飛。',112,'全唐诗/poet.tang.51000.json','["鹿眠荒圃寒蕪白，鴉噪殘陽敗葉飛。", "〖2〗（以上《詩話總龜》十四《警句門》引《雅言系述》）（〖1〗原作「松」，據《四部叢刊》影明本《增修詩話總龜》卷十四校改。", "〖2〗《全唐詩》卷七一七據《錦繡萬花谷》誤收此詩於舒州人曹松名下。", "）。"]'),
('8ca222d7-a88f-4f58-a38f-24c727e0b5e0','題君山','任鵠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','不礙揚帆路，盤根壓洞庭。',48,'全唐诗/poet.tang.51000.json','["不礙揚帆路，盤根壓洞庭。", "波濤四面白，雲外一堆青。", "魚躍晴波動，龍歸石洞腥。", "纔期託名畫，爲我簇爲屏。"]'),
('f6049cbb-29f8-4edd-a0c6-6c176c705190','送王正己歸山','任鵠','唐','唐诗','tang','','[]','五峯青拄天，直下掛[飛]（龍）泉。',73,'全唐诗/poet.tang.51000.json','["五峯青拄天，直下掛[飛]（龍）泉。", "琴鶴同歸去，烟霞到處眠。", "鼯跳霜葉徑，虎嘯夕陽川。", "獨酌應懷我，排空樹影連。", "（以上《詩話總龜》十五引《雅言雜載》）。"]'),
('2159bf3d-7927-4992-8c07-5499c498cabb','題螺江廟','陳誼','唐','唐诗','tang','','[]','廟裏杉松蕭颯[風]（颯），廟前江水碧溶溶。',108,'全唐诗/poet.tang.51000.json','["廟裏杉松蕭颯[風]（颯），廟前江水碧溶溶。", "憑欄不見當時事，落日遠山千萬重。", "（《詩藪雜編》四引《郡閣雅談》）（〖1〗見《增修詩話總龜》卷十六引《郡閣雅談》、《吟窗雜錄》卷四九引《江表志》。", "據後書，陳誼應爲南唐時人。", "）。"]'),
('30040170-d2c8-4eca-8be2-f26ee6603fb6','旅中（句）〖2〗','蔣維東','唐','唐诗','tang','','[]','未有一夜夢，不歸千里家。',12,'全唐诗/poet.tang.51000.json','["未有一夜夢，不歸千里家。"]'),
('21a90107-6e68-41d5-9c3a-d9d0f7576390','落花（句）','蔣維東','唐','唐诗','tang','','[]','流水從將去，春風解送來。',144,'全唐诗/poet.tang.51000.json','["流水從將去，春風解送來。", "（以上《五代詩話》六引《零陵總記》〖3〗）（〖1〗宋馬永易《實賓錄》卷十一《山長》條云：「五代零陵蔣維東好學，能屬文。", "乾祐中嘗隱居衡嶽，從而受業五十餘）（人，號維東爲山長云。", "」〖2〗《詩話總龜》題作《旅中書懷》。", "〖3〗見《增修詩話總龜》卷二十一引《零陵總記》。", "）。"]'),
('5a61177e-6476-4e9f-93b7-868b5c2d29ac','句','胡擢','唐','唐诗','tang','','[]','甕中每醖逍遙藥，筆下閒偷造化功。',50,'全唐诗/poet.tang.51000.json','["甕中每醖逍遙藥，筆下閒偷造化功。", "（《五代詩話》六引《圖畫見聞志》）（〖1〗見《圖畫見聞誌》卷二。", "）。"]'),
('c226fca8-9dda-46d1-9d22-f19bc6fadb13','送成務崇（宋初奄有金陵，孟賓于先居連上，嘏興國中亦自吉水還故鄉，逾年卒。書生成務崇因遊廬山，與嘏有忘年之分。興國中見嘏，且言自連上來遊江左，時有詩送成務崇云云。務崇詢於連上知交，皆言嘏卒已十餘矣。）','孟嘏','唐','唐诗','tang','','["\u5e90\u5c71"]','同呼碧嶂前，已是十餘年。',133,'全唐诗/poet.tang.51000.json','["同呼碧嶂前，已是十餘年。", "話別非容易，相逢不偶然。", "多爲詩酒役，早免利名牽。", "幸有歸真路，何妨學上玄。", "（《全五代詩》六五引《雅言雜載》〖2〗）（〖1〗「復捷江右士頗奇之」，《詩話總龜》作「後捷名，不欲止，江左士人頗奇之」。", "〖2〗見《增修詩話總龜》卷四四引《雅言雜載》。", "）。"]'),
('6d2194fe-aa38-4650-8fd5-535f8f602950','贈史虛白（句）','孟嘏','唐','唐诗','tang','','[]','詩酒獨遊寺，琴書多寄僧。',68,'全唐诗/poet.tang.51000.json','["詩酒獨遊寺，琴書多寄僧。", "（《詩藪雜編》四引《郡閣雅談》）（〖1〗與前條同見《增修詩話總龜》引《雅言雜載》。", "《詩藪》誤作《郡閣雅談》。", "）。"]'),
('b91b6491-9c12-4997-b32f-0f53f1da82d4','題廬山瀑布','陸蟾','唐','唐诗','tang','','["\u5e90\u5c71"]','正源人莫測，千尺掛雲端。',52,'全唐诗/poet.tang.51000.json','["正源人莫測，千尺掛雲端。", "岳色染不得，神功裁亦難。", "夏噴猿鳥浴，秋射斗牛寒。", "流到滄溟日，翻濤更好看。", "〖2〗。"]'),
('025d9797-e6d5-4f46-a5b1-dc31d5fcbdeb','春暮經石頭城','陸蟾','唐','唐诗','tang','','[]','六朝多少事，搘肘思悠悠。',207,'全唐诗/poet.tang.51000.json','["六朝多少事，搘肘思悠悠。", "落日空江上，子規啼渡頭。", "蒹葭侵[壞]（廢）壘，烟霧接滄洲。", "今古分明在，那堪向九秋？", "（以上《詩話總龜》十五引《雅言雜載》）（〖1〗北宋釋契嵩《鐔津文集》卷十三有《陸蟾傳》，云蟾爲藤州鐔津人，有王霸大略，以能詩名於楚越間，後客死於攸縣司空山。", "又引高閬語稱爲國初人。", "〖2〗《陸蟾傳》所引，題作《瀑布詠》，「正源」作「靈源」，「浴」作「凝」，「射」作）（「濺」，「流」作「待」，「翻」作「爲」。", "）。"]'),
('96305df7-2115-41c6-832e-76d999dba34b','司空山聞子規','陸蟾','唐','唐诗','tang','','[]','後夜入清明，遊人何處聽？',66,'全唐诗/poet.tang.51000.json','["後夜入清明，遊人何處聽？", "花殘斑竹廟，雨歇峴山亭。", "樹罅月欲落，窗間酒正醒。", "衆鳥方在夢，誰念爾勞形？", "（《詩話總龜》十一引《雅言系述》）。"]'),
('341a0ea7-66b6-4828-bcd9-83605af64ff2','題祝融峯（句）','栖巖','唐','唐诗','tang','','["\u8861\u5c71"]','開雲四邊盡，浮世一齊低。',72,'全唐诗/poet.tang.51000.json','["開雲四邊盡，浮世一齊低。", "（《五代詩話》七引《青瑣集》）（〖1〗見《青瑣高議前集》卷九。", "栖巖，疑爲棲蟾之誤。", "《全唐詩》卷八四八收其南嶽詩多首。", "）。"]'),
('b2aed8e8-1665-49bd-8c94-79323e44907f','無事歌（長沙獄椽任福祖，[擁]〖推〗騶吏出行。有賣藥道人行吟云動。福祖審思，豈非異人，急遣訪求，已出城矣。）','賣藥道人','唐','唐诗','tang','','[]','無事歌，呵呵亦呵呵，哀哀亦呵呵。',78,'全唐诗/poet.tang.51000.json','["無事歌，呵呵亦呵呵，哀哀亦呵呵。", "不似荷葉參軍子，人人與箇拜[頃]木，大作廳上假閻羅。", "（《清異錄》三）（〖1〗據商務排印本《說郛》卷六一引《清異錄》校補。", "）。"]'),
('ca2b7f1a-89b5-4ef5-bdec-69b26b2ab364','上成汭（句）（《全唐詩》七一九誤作路德延）（荆南舊有五花館，待賓之上地也。故蔣肱上成汭詩云：）','蔣肱','唐','唐诗','tang','','[]','不是上台名姓字，五花賓館敢（一作「收」）從容。',33,'全唐诗/poet.tang.51000.json','["不是上台名姓字，五花賓館敢（一作「收」）從容。", "（《南部新書》癸）。"]'),
('c67e5849-f466-48d6-bdcd-13f7c4532bed','爐火詩','趙節','唐','唐诗','tang','','[]','近冬附火爲泰火，透春擁爐成否爐。',41,'全唐诗/poet.tang.51000.json','["近冬附火爲泰火，透春擁爐成否爐。", "用否隨時有輕重，進身君子合知無。", "（《清異錄》一）。"]'),
('b4086b1d-c6e5-4270-b814-0d5e8050530d','漳州','史維翰','唐','唐诗','tang','','[]','漳溪郡有佳山水，遷客因之作勝遊。',48,'全唐诗/poet.tang.51000.json','["漳溪郡有佳山水，遷客因之作勝遊。", "怪石千峯聳晴巘，枯槎百尺擁寒流。", "（《輿地紀勝》一三一《漳州》）。"]'),
('6e4f33ed-414e-41ba-85b0-f33b489aa093','八公山（嘉慶志按《江南通志》引《綱目集覽》云：「山在壽春者，淮南王與八公憇處；在巢縣者，王遇八公處。」《方輿勝覽》以爲晉敗苻堅處，非是。）','吳資','唐','唐诗','tang','','[]','幼度提晉師，胡卒驚鶴唳。',56,'全唐诗/poet.tang.51000.json','["幼度提晉師，胡卒驚鶴唳。", "城外軍屯壘，可數不可計。", "至今風雨夜，鬼哭雜異類。", "（《光緒續修廬州府志》六《山川志》上）。"]'),
('d30cc4f6-8810-416e-a7d2-bc248fd724b0','教弩臺（《方輿勝覽》：教弩臺在懷德坊明教寺。舊經云：昔魏武帝築臺，教強弩五百人，以禦孫權櫂船。唐大曆間因得鐵佛高一丈八尺，刺史裴絹奏請爲寺。）','吳資','唐','唐诗','tang','','[]','曹公教弩臺，今爲比丘寺。',93,'全唐诗/poet.tang.51000.json','["曹公教弩臺，今爲比丘寺。", "東門小河橋，曾飛吳主騎。", "（同上十一《古蹟志》）（〖1〗裴絹，疑應作裴諝，詳《唐刺史考》卷一二九。", "〖2〗《輿地紀勝》卷四五《廬州》收以上二詩，題作《合肥懷古》。", "）。"]'),
('9b1a89b0-b6cb-4235-85c9-e0bb6659931f','遊北巖（句）','李渭','唐','唐诗','tang','','[]','淮陽清淨理，永嘉山水心。',217,'全唐诗/poet.tang.51000.json','["淮陽清淨理，永嘉山水心。", "（《蜀中名勝記》八《成都府·資縣》）（〖1〗《新唐書·宰相世系表》趙郡李氏東祖房有李渭，爲長洲主簿李暄之子。", "《蜀中名勝記》卷八引《蜀志補遺》云：「唐李渭爲刺史，有游山詩云〖詩略〗。", "刻於等慈寺壁。", "」另參後文。", "〖2〗《輿地紀勝》卷一五七云：「李渭爲本州刺史，有詩刻留等慈寺。", "時與前進士崔公輔同遊，崔有詩略曰：淮陽清靜理，永嘉山水心。", "」二句詩頌揚刺史善政多才，以崔作爲近是。", "崔公輔爲杜甫同時人，詳《全唐詩續拾》。", "）。"]'),
('6b3ccff0-0113-43f9-837d-9abac7e0621e','漢武帝祈仙臺（《三秦記》：「坊州橋山有漢武帝祈仙臺，高百尺。」李欽止題詩云：）','李欽止','唐','唐诗','tang','','[]','四方禍結與兵連，海內空虛在末年。',80,'全唐诗/poet.tang.51000.json','["四方禍結與兵連，海內空虛在末年。", "謾築此臺高百尺，不知何處有神仙。", "（《永樂大典》二六○四「臺」字韻）（〖1〗李欽止，疑非唐人。", "《大典》殆據《類編長安志》卷三。", "）。"]'),
('f526e6a7-07f4-413c-9972-ccde3ee16696','丫頭山','施逵','唐','唐诗','tang','','[]','何不梳粧嫁去休，常教人喚作丫頭。',76,'全唐诗/poet.tang.51000.json','["何不梳粧嫁去休，常教人喚作丫頭。", "只因不信良媒說，躭閣千秋與萬秋。", "（《古今圖書集成·職方典》二八四《黃州府志》）（〖1〗弘治《黃州府志》卷七作蘇軾詩。", "）。"]'),
('66ee4f3b-9f89-4274-b09e-624edb32d19e','金華山','袁吉','唐','唐诗','tang','','[]','金華山色與天齊，一徑盤紆盡石梯。',113,'全唐诗/poet.tang.51000.json','["金華山色與天齊，一徑盤紆盡石梯。", "步步前登清漢近，時時回首白雲低。", "風偷藥氣名何限，水泛花光路即迷。", "洞口數聲仙犬吠，始知羽客此真棲。", "（《古今圖書集成·山川典》一二七《金華山部》）（〖1〗光緒《金華縣志》卷二稱袁吉爲「唐刺史」。", "）。"]'),
('05c6de80-194e-4b49-ba02-7906a662d2a0','早春送郎官出宰（〖1〗《全唐詩》七八一作袁求賢詩○《文苑英華》一八九《省試》。）','張隨','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('ce27afc0-578e-4a4e-b012-cd127ea2ae7f','題透明巖安祿山題記後（透明巖，亦名棲真巖，在大蓬山。巖西曰禪窟，巖壁上有安祿山題記云：「大唐先天二年，歲在辛丑，七月朔，安祿山敬造彌勒佛一龕。」有清遠居士題其後云云。王象之按：「先天二年即開元元年，是時祿山尚未顯，以相傳之久，兼恐別有姓名偶同，姑兩存之。」）','清遠居士','唐','唐诗','tang','','[]','妖胡作逆罪滔天，翠輦倉皇幸蜀川。',109,'全唐诗/poet.tang.51000.json','["妖胡作逆罪滔天，翠輦倉皇幸蜀川。", "千載業緣磨不盡，卻來邀福向金仙。", "（《輿地紀勝》一八八《蓬州·景物》及《碑記》）（〖1〗葉奕苞《金石錄補》卷十二云：「居士不知何許人。", "顏魯公于虎邱題詠，同游者亦曰清遠，未知即其人否。", "」）。"]'),
('b562768d-0124-4ef3-80ac-5db572989510','子規（〖1〗《全唐詩》二六七作顧況詩○《文苑英華》三二九《禽獸》。）','楊逵','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('016b1a8f-609d-4a68-a726-15ec4d499880','題孟巖（句）','楊禹珪','唐','唐诗','tang','','[]','郡雖饒勝境，偏愛此巖幽。',28,'全唐诗/poet.tang.51000.json','["郡雖饒勝境，偏愛此巖幽。", "（《輿地紀勝》一五七《資州》）。"]'),
('852f32f1-7ba3-4042-a277-e445d2871c0f','和杜甫（句）','楊興義','唐','唐诗','tang','','[]','莫嫌袍紫歸家阻，且慶豐年雅俗安。',16,'全唐诗/poet.tang.51000.json','["莫嫌袍紫歸家阻，且慶豐年雅俗安。"]'),
('5a4f98d0-c5c0-4b82-9d7b-e60d3cb2bf7e','題秋風（句）','楊興義','唐','唐诗','tang','','[]','霜風一夜將紅葉，換盡江頭萬木青。',58,'全唐诗/poet.tang.51000.json','["霜風一夜將紅葉，換盡江頭萬木青。", "（《蜀中名勝記》二五《保寧府·巴州》）（〖1〗《蜀中名勝記》稱「唐進士楊興義」。", "）。"]'),
('83343b7b-71b9-4825-925e-4646a99af3af','送尹蔓回睦州','厲翼','唐','唐诗','tang','','[]','憐君授衣月，遠作泛舟行。',57,'全唐诗/poet.tang.51000.json','["憐君授衣月，遠作泛舟行。", "江闊桐廬岸，山深建德城。", "千尋喬木影，七里暮灘聲。", "興盡當停櫂，臨流更濯纓。", "（《嚴陵集》二）。"]'),
('1c2c1acb-09ef-4022-8203-731e6e2135b7','贈妓（詳縱情詩酒，至廬江謁郡守，留連吟醉，因贈妓曰：）','鄭詳','唐','唐诗','tang','','[]','臺盤闊狹纔三尺，似隔中當有阻艱。',92,'全唐诗/poet.tang.51000.json','["臺盤闊狹纔三尺，似隔中當有阻艱。", "若不騎龍與騎鳳，樂營門是望夫山。", "（《詩話總龜》二三《寓情門》引《南部新書》）（〖1〗《登科記考》卷二二載會昌四年登進士第者有鄭祥，漢南人，疑即此人。", "）。"]'),
('a6a1ef10-7277-4de7-ae22-89f4e1b22e9a','題蓮花洞','獨孤均','唐','唐诗','tang','','[]','路迴千曲繞芝田，羽客相擕訪謫仙。',64,'全唐诗/poet.tang.51000.json','["路迴千曲繞芝田，羽客相擕訪謫仙。", "石竇嵌空惟有跡，靈龕隱軫莫知年。", "來居洞裏長無死，不出人間自有天。", "更欲不眠吟至曉，恐驚龍動起愁烟。"]'),
('b2023a6c-5b68-4685-b357-59d03019f4da','題含虛洞二首 一','獨孤均','唐','唐诗','tang','','[]','高樹猿啼亂水聲，尋幽不覺洞中行。',64,'全唐诗/poet.tang.51000.json','["高樹猿啼亂水聲，尋幽不覺洞中行。", "驪龍宿處雲常暗，羽客歸時路自明。", "別後已迷舟竈火，迴來猶認玉童名。", "從今已去朝金闕，便隔人間五百生。"]'),
('d8f43d1a-6964-4d74-9795-87de6eb9fa56','題含虛洞二首 二','獨孤均','唐','唐诗','tang','','[]','捫蘿攀蹬步欹危，歷覽幽巖駭怪奇。',107,'全唐诗/poet.tang.51000.json','["捫蘿攀蹬步欹危，歷覽幽巖駭怪奇。", "泉石膏肓傳亦久，神仙窟宅到何遲。", "真人鹿引非無路，洞府龍升自有時。", "但覺塵緣挹絕景，躊躇落筆媿題詩。", "（以上《康熙徽州府志》二《婺源·山川》）（〖1〗光緒《婺源縣志》卷六十二作獨孤筠。", "）。"]'),
('bb74feb5-8e64-418f-95f9-820a964fe84e','經故宮女墳有感（二首） 一','聶通志','唐','唐诗','tang','','[]','家國久隨狂虜沒，春蕪又向冢頭青。',32,'全唐诗/poet.tang.51000.json','["家國久隨狂虜沒，春蕪又向冢頭青。", "如今憶得當時事，爲爾傷心一涕零。"]'),
('1e1645e4-33f0-4d9e-95a1-2c9c6a38e8a8','經故宮女墳有感（二首） 二','聶通志','唐','唐诗','tang','','[]','長郊煙淡月華清，因醉荒墳半夜醒。',77,'全唐诗/poet.tang.51000.json','["長郊煙淡月華清，因醉荒墳半夜醒。", "失路孤吟不勝苦，暗中應有鬼神聽。", "（《萬首唐人絕句》三五〖1〗）（〖1〗此指明趙宧光、黃習遠重訂本。", "又見《才鬼記》卷七。", "）。"]'),
('5318a98d-cde1-4889-a433-1dd4c4112d63','沃洲山','魏證','唐','唐诗','tang','','[]','一聲清磬海邊月，十里香風澗底松。',119,'全唐诗/poet.tang.51000.json','["一聲清磬海邊月，十里香風澗底松。", "何代沃洲今夜興，倚欄干聽赤城鐘。", "（《輿地紀勝》四《紹興府》）（〖1〗《會稽掇英總集》卷四作魏徵詩，爲七律，此爲後四句。", "然魏徵平生未及東南，詩律成熟，亦非初唐所宜有。", "或另其魏證其人。", "參《全唐詩續拾》卷一。", "）。"]'),
('be10538c-7b07-49f0-8066-49c2149cbd27','送芝上人遊羅浮（二首） 一','清範','唐','唐诗','tang','','[]','一瓶一錫十方遊，揮塵湘南夜語投。',32,'全唐诗/poet.tang.51000.json','["一瓶一錫十方遊，揮塵湘南夜語投。", "四百好峯在何許？寄師雙眼看羅浮。"]'),
('a1c9d741-0425-43a6-bdd4-33aa18ea6476','送芝上人遊羅浮（二首） 二','清範','唐','唐诗','tang','','[]','此身政坐愛名山，投老求閒可得閒。',44,'全唐诗/poet.tang.51000.json','["此身政坐愛名山，投老求閒可得閒。", "遙夜相思千里月，想應騎虎度松關。", "（《羅浮志》十《詩》）。"]'),
('001f83f2-243d-4c76-b569-10b83321ce4c','雲門寺','德圓','唐','唐诗','tang','','[]','若耶溪邊寺，幽勝絕塵囂。',72,'全唐诗/poet.tang.51000.json','["若耶溪邊寺，幽勝絕塵囂。", "一洞花將發，千巖雪未消。", "依陰生徑竹，野色映溪橋。", "漸賞登高處，鐘聲應寂寥。", "（《古今圖書集成·山川典》一一四《雲門山部》）。"]'),
('a7da7e2d-a225-448e-9b54-261ffb1fa8db','望樊川','澹交','唐','唐诗','tang','','[]','萬樹葉初紅，人家樹色中。',72,'全唐诗/poet.tang.51000.json','["萬樹葉初紅，人家樹色中。", "疎鐘搖雨足，積水浸雲容。", "雪磧回寒雁，村燈促夜舂。", "舊山歸未得，生計欲何從？", "（《古今圖書集成·職方典》五二○《西安府部》）。"]'),
('86693ac7-1c93-4ce3-9b7e-2d4a99b81fb6','江亭晚眺','覺隱','唐','唐诗','tang','','[]','獨隱清江秋思長，晚潮初上水亭凉。',56,'全唐诗/poet.tang.51000.json','["獨隱清江秋思長，晚潮初上水亭凉。", "海門雲起雙巒暝，一抹銀花影夕陽。", "（《古今圖書集成·職方典》七八五《安慶府部》）。"]'),
('3efae1f8-4f02-4d6a-a6ca-b12e52c17d30','戰城南','無名氏','唐','唐诗','tang','','[]','戰地何昏昏，戰士如羣蟻。',88,'全唐诗/poet.tang.51000.json','["戰地何昏昏，戰士如羣蟻。", "氣重日輪紅，血染蓬蒿紫。", "烏鳥銜人肉，食悶飛不起。", "昨日城上人，今日城下鬼。", "旗色如羅星，鼙聲殊未已。", "妾家夫與兒，俱在鼙聲裏。", "（《文苑英華》一九六《樂府》）。"]'),
('9cb33277-9207-40bc-9931-3df35a1ba329','昭君怨','無名氏','唐','唐诗','tang','','[]','銜悲出漢關，落淚灑胡鞍。',60,'全唐诗/poet.tang.51000.json','["銜悲出漢關，落淚灑胡鞍。", "關榆三夏凍，塞柳九春寒。", "眉任愁中結，腰隨帶裏寬。", "別曲易悽斷，哀絃不忍彈。", "（同上二○四《樂府》）。"]'),
('2e41acb8-237e-44a7-b1b6-4bb29c91721e','採菱女','無名氏','唐','唐诗','tang','','[]','白日期何去？青春只自矜。',89,'全唐诗/poet.tang.51000.json','["白日期何去？青春只自矜。", "艷歌呈幾曲，江畔采新菱，望浦思同濟，輕舟喜共乘。", "翠（一作葉）將眉比色，聲與調相應。", "蕩漾微波散，清泠遠水澄。", "更看池際影，若對玉壺冰。", "（同上二○八《樂府》）。"]'),
('836a6f2a-6961-4c01-b1ec-10fc4cf535b7','分柑子歌示諸小','無名氏','唐','唐诗','tang','','[]','癡男騃女愁殺人，偏呼小者大者嗔。',103,'全唐诗/poet.tang.51000.json','["癡男騃女愁殺人，偏呼小者大者嗔。", "粗衣糲食盡須一，何況異味兼時新。", "今朝樓下[柑]（甘）初熟，摘得一筐分不足。", "兒童豈待父母施，自各捻來（一作「各自捻將」）獻兄叔。", "就中小女有所翳，（下缺）（同上三三七《歌行》）。"]'),
('e2cac32e-a99f-494f-b723-a3883968022e','哭從伯祭酒','無名氏','唐','唐诗','tang','','[]','剖符馮翊次，以疾拜司成。',190,'全唐诗/poet.tang.51000.json','["剖符馮翊次，以疾拜司成。", "義重疎皆友，仁深怨不生。", "昔居南比省，長話水雲情。", "吟諷資高興，絲綸發重名。", "經秋漳浦臥，一旦逝川聲。", "自古誰迴得，重泉獨往程。", "明靈辭魏闕，冬日冷秦宮。", "〖1〗孝子號天護，銘旌引柩行。", "門闌容足跡，章句許才清。", "劣薄無因報，恩知豈謂輕？", "捫膺詞莫吐，奠酒淚先傾。", "從此階前石，何人肯念貞？", "（愚魯獻孤石蒙賞孤峭。", "同上三○四《悲悼》）（〖1〗「宮」字不韻，趙遂之校作「庭」。", "）。"]'),
('94c317a4-b873-4a4c-899d-34ea248ab177','雜詩','無名氏','唐','唐诗','tang','','[]','舊山雖在不關身，且向長安過暮春。',45,'全唐诗/poet.tang.51000.json','["舊山雖在不關身，且向長安過暮春。", "一樹梨花一溪月，不知今夜屬何人？", "（《萬首唐人絕句》三八）。"]'),
('a3a33868-18a0-4b37-af7f-111993425d24','碧玉潭（潭在武康西一十里響應山之下，唐人有詩刻於岩上云：）','無名氏','唐','唐诗','tang','','[]','水面平鋪映碧空，夜深明月照龍宮。',50,'全唐诗/poet.tang.51000.json','["水面平鋪映碧空，夜深明月照龍宮。", "猿啼未響潭先響，一樹花開兩樹紅。", "（《輿地紀勝》四《安吉州·景物》）。"]'),
('8348381e-a0a5-430e-8924-86d6d98a0510','子陵山洞（在京山縣南六十里，即嚴子陵隱所也。傍有石室名帝星井，寺曰淨安，嘗有一星，光芒見井中。昔人賦詩云：）','無名氏','唐','唐诗','tang','','[]','翩翩釣臺翁，弊屣棄利祿。',72,'全唐诗/poet.tang.51000.json','["翩翩釣臺翁，弊屣棄利祿。", "煙溪七里瀨，風月一竿竹。", "平生知己誰？故人劉文叔。", "三聘乃肯來，公卿指爲辱。", "高風輕萬乘，敢以足加腹。", "居然動天象，下應太史卜。"]'),
('5fbe1f71-08eb-463b-9ad3-4158f76d1857','帝星井','無名氏','唐','唐诗','tang','','[]','帝星胡爲落此間？豈非此有子陵山。',112,'全唐诗/poet.tang.51000.json','["帝星胡爲落此間？豈非此有子陵山。", "蒼蒼珉井一百丈，至今深夜光芒寒。", "野老相傳是陳迹，斷碑摸索苔蘚斑。", "往事恍惚不可問，青山綠水空潺潺。", "（以上《輿地紀勝》八四《郢州·古跡》。", "後一首又見《古文圖書集成·職方典》一一四七《安陸府部》）。"]'),
('963854b4-72b8-4f29-b5ba-a732baaf3c08','小桃源（曩有耕于小桃源得一銅牌，牌上有詩一絕云：）','無名氏','唐','唐诗','tang','','[]','綽約去朝真，仙源萬木春。',46,'全唐诗/poet.tang.51000.json','["綽約去朝真，仙源萬木春。", "要知竊桃客，定是會（一作滑）稽人。", "（《輿地紀勝》一六六《長寧軍》）。"]'),
('80e51954-4f59-4be2-96c0-ef037035a741','題靈鷲','無名氏','唐','唐诗','tang','','[]','靈鷲名山萬古名，幾回無事繞廊行。',80,'全唐诗/poet.tang.51000.json','["靈鷲名山萬古名，幾回無事繞廊行。", "殿前流水晴尤急，塔上春雲晚自生。", "鶴傍經牀聽梵語，鳥窺齋鉢候鐘聲。", "我來借得蒲團坐，歸去閒眠夢亦清。", "（《咸淳臨安志》八○《寺觀》）。"]'),
('48f73717-bbe4-4463-9bdb-4652505e9a78','平蓋山','無名氏','唐','唐诗','tang','','[]','平蓋山高古木疎，昔人曾此築仙居。',83,'全唐诗/poet.tang.51000.json','["平蓋山高古木疎，昔人曾此築仙居。", "井通八角寒泉湧，觀燬三清劫火餘。", "洗墨池邊丹竈冷，繫龍巖畔石潭虛。", "吟成獨坐荒苔上，閑看蝸牛學篆書。", "（《蜀中名勝記》十二《眉州彭山縣》）。"]'),
('fd72b7ee-16c7-40f1-8c4a-3bc9996df510','洞真觀（在酃縣北）','無名氏','唐','唐诗','tang','','[]','玉洞瑤壇長冷落，真虛崖竇色常新。',54,'全唐诗/poet.tang.51000.json','["玉洞瑤壇長冷落，真虛崖竇色常新。", "可憐城裏悠悠者，不識瀟湘四季春。", "（同治《湖南通志》二三九《方外志·寺觀》）。"]'),
('64cdf8a1-da94-46c6-b028-cd1d5bf8f410','滄浪寺（在沅江縣南三十里）','無名氏','唐','唐诗','tang','','[]','閒步滄浪野，棲禪竹作扉。',32,'全唐诗/poet.tang.51000.json','["閒步滄浪野，棲禪竹作扉。", "浮生自有樂，塵慮總皆非。", "（同上二四○）。"]'),
('b0673865-dc44-4c08-b8bc-c570d541a1e5','玉乳泉壁間詩','無名氏','唐','唐诗','tang','','[]','騎馬出門三月暮，楊花無奈雪漫天。',49,'全唐诗/poet.tang.51000.json','["騎馬出門三月暮，楊花無奈雪漫天。", "客情最苦夜難度，宿處先尋無杜鵑。", "（《重修丹陽縣志》三四《藝文》）。"]'),
('aea6bf55-bb1f-4e34-a8b5-c155b00e29eb','楚泊亭（二首） 一','無名氏','唐','唐诗','tang','','[]','天垂六幕水浮空，霽月光風上下同。',32,'全唐诗/poet.tang.51000.json','["天垂六幕水浮空，霽月光風上下同。", "我向山頭一舒笑，楚人還望白雲中。"]'),
('fcfa5f70-2303-4859-9233-affe09c218a1','楚泊亭（二首） 二','無名氏','唐','唐诗','tang','','[]','卷逃屈放兩俱空，山止波流萬古同。',49,'全唐诗/poet.tang.51000.json','["卷逃屈放兩俱空，山止波流萬古同。", "美惡不隨天地老，斷魂啼鳥一聲中。", "（《嘉靖常德府志》十九《賦詠》）。"]'),
('d23c33fa-50bb-4649-8c81-dd0249304c42','黃金臺','無名氏','唐','唐诗','tang','','[]','燕昭北築黃金臺，四方豪傑乘風來。',125,'全唐诗/poet.tang.51000.json','["燕昭北築黃金臺，四方豪傑乘風來。", "秦家燒書殺儒客，肘腋之間千里隔。", "去年八月幽州道，昭君墓前哭秋草。", "今年五月咸陽關，秦家城外悲河山。", "河上關頭車馬路，殘日青烟五陵樹。", "（見元人王惲《秋澗集》。", "《古今圖書集成·職方典》二九《順天府部》亦載此詩，題作《燕臺》）。"]'),
('ff03a664-b0f6-4892-a765-75001fe9db07','題仙人洞石鐘','無名氏','唐','唐诗','tang','','[]','我欲扣石鐘，驚起洞中人。',72,'全唐诗/poet.tang.51000.json','["我欲扣石鐘，驚起洞中人。", "烟蘿杳無際，空鎖石門春。", "石洞何窈窕，云是仙人庭。", "仙人渺何許？瑤草空自青。", "石洞窅且深，花落無人掃。", "仙翁去不還，何處尋瑤草。"]'),
('f10378f5-4993-4a7b-a40b-a6b3e1f1ffc0','盤山','無名氏','唐','唐诗','tang','','[]','盤山高巍峩，半入青雲裏。',36,'全唐诗/poet.tang.51000.json','["盤山高巍峩，半入青雲裏。", "中間最上峯，更向天邊起。", "行行白石崖，六月不知暑。"]'),
('717341b6-340c-45a7-9c59-d1dfdde91f69','題薊州桃李寺','無名氏','唐','唐诗','tang','','[]','舊有桃花樹，人呼寺故云。',76,'全唐诗/poet.tang.51000.json','["舊有桃花樹，人呼寺故云。", "石危秋鷺上，灘遠夜僧聞。", "汲井連黃葉，登臺散白雲。", "燒丹勾漏合，無處不逢君。", "（以上孫承澤《天府廣記》四二《失名唐人詩》，見石刻。", "）。"]'),
('cce10a39-231e-4556-a718-776d7710cdcf','魯陽城','無名氏','唐','唐诗','tang','','[]','豢術緣何竟醢龍，因遷僻壤隔雲封。',64,'全唐诗/poet.tang.51000.json','["豢術緣何竟醢龍，因遷僻壤隔雲封。", "山迷故國芙蓉秀，水瀉沙河玳瑁封。", "離黍何須發浩歎，荒城久矣屬空墉。", "獨憐遼鶴歸何處，漫向深芊聽曉鐘。"]'),
('02aee58e-fa25-4aad-895a-07fee6a020c8','思父臺','無名氏','唐','唐诗','tang','','[]','駐馬空山親舍迷，不堪回首白雲低。',57,'全唐诗/poet.tang.51000.json','["駐馬空山親舍迷，不堪回首白雲低。", "王師爲國驅鋒鏑，爭向兒家杖履追。", "（以上《古今圖書集成·職方典》四八八《汝州部》）。"]'),
('43bb96b2-44c4-4cf1-85f4-26b517ccc4ab','桃川宮（方士，失名）','無名氏','唐','唐诗','tang','','[]','流水迴環日夕澄，烟蘿石壁四時新。',104,'全唐诗/poet.tang.51000.json','["流水迴環日夕澄，烟蘿石壁四時新。", "清風臺上生瑤草，夜雨松根老茯苓。", "九轉丹砂龍虎伏，千年劍氣鬼神驚。", "道人今向蓬萊去，白鶴歸來月滿庭。", "（同上一二六二《常德府部》。", "又同治《湖南通志》二四○《方外志·寺觀·桃源縣》）。"]'),
('0cd62b47-71db-42e8-a718-d7118fcaefad','聖壽寺（三首） 一','無名氏','唐','唐诗','tang','','[]','石罅題詩紀別年，風煙南北各凄然。',33,'全唐诗/poet.tang.51000.json','["石罅題詩紀別年，風煙南北各凄然。", "薝蒲坐我靈山下，猶借高人半日緣。", "。"]'),
('e30b2637-afab-4eef-a082-13e0a4925325','聖壽寺（三首） 二','無名氏','唐','唐诗','tang','','[]','夕籟鳴寒雨，晴峯出翠屏。',24,'全唐诗/poet.tang.51000.json','["夕籟鳴寒雨，晴峯出翠屏。", "風塵吾獨愧，鴻鵠下蒼冥。"]'),
('cc8e41ab-2104-4a67-bf1d-d54d7911ce13','聖壽寺（三首） 三','無名氏','唐','唐诗','tang','','[]','趺坐叢林下，朗吟白石巔。',49,'全唐诗/poet.tang.51000.json','["趺坐叢林下，朗吟白石巔。", "一丘盤曲處，中有老龍眠。", "（《古今圖書集成·職方典》一○八五《興化府部》）。"]'),
('9d89dd51-024f-42ae-b982-582607d1afc0','寒亭','無名氏','唐','唐诗','tang','','[]','朔風凜凜雪漫漫，未是寒亭分外寒。',47,'全唐诗/poet.tang.51000.json','["朔風凜凜雪漫漫，未是寒亭分外寒。", "六月火雲天不雨，請君來此凭欄杆。", "（同上一一四七《安陸府部》）。"]'),
('24fcc6fa-3893-47bd-9886-031f8d945bf2','緱山廟','無名氏','唐','唐诗','tang','','[]','獨挹榴花夜向闌，詩情高寄碧雲間。',49,'全唐诗/poet.tang.51000.json','["獨挹榴花夜向闌，詩情高寄碧雲間。", "不知鶴駕人何在，笙月亭亭滿故山。", "（同上《山川典》六三《緱山部》）。"]'),
('e6b443a3-f922-47bf-9dd1-b192f57b2c92','牡丹','無名氏','唐','唐诗','tang','','[]','傾國姿容別，多開富貴家。',42,'全唐诗/poet.tang.51000.json','["傾國姿容別，多開富貴家。", "臨軒一賞後，輕薄萬千花。", "（同上《草木典》二八九《牡丹部》）。"]'),
('3346ed12-7292-4b23-b424-43c55d317230','紀信墓','無名氏','唐','唐诗','tang','','[]','紀信生降爲沛公，草荒古塚臥秋風。',53,'全唐诗/poet.tang.51000.json','["紀信生降爲沛公，草荒古塚臥秋風。", "不知青史緣何事，却道蕭何第一功。", "（乾隆《直隸秦州新志》十一《藝文·詩》）。"]'),
('7f073e5e-3332-43ba-84e5-d58a84d6469c','卻鬼丸','無名氏','唐','唐诗','tang','','[]','走鹿枯風吼夜闌，頌花還喜向椒盤。',83,'全唐诗/poet.tang.51000.json','["走鹿枯風吼夜闌，頌花還喜向椒盤。", "人情此日非前日，歲事新官對舊官。", "竹[葉]（裏）莫辭終日醉，梅花已拚隔年看。", "書生但恐寒爲祟，不用朱泥卻鬼丹。", "（《歲時廣記》五《元旦》）。"]'),
